const X={id:"celebrity-study",title:"A study of western celebrity",content:"In our celebrity-obsessed culture...",paragraphs:[{label:"A",content:"It seems that our current society cannot get enough information about the daily lives of celebrities. But how did celebrities become so much an important force in our culture? While people have always had shared a certain obsession for the fantastic and the famous, the notion of celebrity, as well as the types of people termed 'celebrities', has evolved greatly throughout the ages. The word 'celebrity' has its roots in the language of the ancient Roman civilization. The word we now know to mean 'a condition of being famous' or 'a famous person' is derived from the Latin word 'celeber', meaning 'frequented or populous'."},{label:"B",content:"The celebrities of the ancient world were the powerful and awesome deities of Greece and Rome, and the citizens of these civilizations believed in a vast number of immortals who had a direct impact on their lives. It was, therefore, important to know about these figures' personal lives. This need to know led to the creation of myths, which personalized the gods and involved them in ancient celebrity scandals that thrilled and excited the common people."},{label:"C",content:"During ancient times, amateur and professional athletes also began to make an impact on the celebrity culture. Victors in the ancient Olympic Games were treated as heroes and were often elevated to god-like status. In the ancient Roman civilization, gladiators вЂ” the equivalent of today's professional athletes вЂ” were also revered by the common people for their heroics and seemingly superhuman strength."},{label:"D",content:"As Europe moved into the Dark Ages..."}],questions:[{id:"q14",number:14,text:"Paragraph A",type:"matching-headings",options:["i Why it is necessary to explain the meaning of the word celebrity","ii The influence of non-human celebrities on societies","iii The impact of broadcasting on concepts of celebrity","iv Creativity having greater value","v Admiration for physical achievement","vi The advantages of celebrity status in the ancient world","vii A result of hardship","viii Literacy and widespread celebrity","ix Attitudes of celebrities towards the media","x The original definition of celebrity"],correctAnswer:"10",explanation:"Paragraph A discusses the origins...",location:"Paragraph A"},{id:"q15",number:15,text:"Paragraph B",type:"matching-headings",options:["i Why it is necessary to explain the meaning of the word celebrity","ii The influence of non-human celebrities on societies","iii The impact of broadcasting on concepts of celebrity"],correctAnswer:"2",explanation:"Paragraph B describes how deities...",location:"Paragraph B"},{id:"q16",number:16,text:"Paragraph C",type:"matching-headings",options:["v Admiration for physical achievement"],correctAnswer:"5",explanation:"Paragraph C focuses on athletes...",location:"Paragraph C"}]},ee={id:"ideal-homes",title:"Ideal Homes",paragraphs:[{label:"A",content:"The concept of an ideal home has evolved significantly..."}],questions:[]},te={id:"third-passage",title:"Third Passage",paragraphs:[{label:"A",content:"Content for third passage..."}],questions:[]},na=Array.from({length:5},(e,t)=>({id:`reading-test-${t+1}`,title:`IELTS Academic Reading Test ${t+1}`,type:"Academic",module:"Reading",duration:60,sections:[X,ee,te],totalQuestions:40})),ia=()=>({id:`reading-test-${Date.now()}`,title:"Random IELTS Academic Reading Test",type:"Academic",module:"Reading",duration:60,sections:[X,ee,te],totalQuestions:40}),j="/audio/ielts-listening",L="/images/ielts-listening";function a(e,t,o,i,n,Q){return{id:e,number:t,text:o,type:i,options:Q,correctAnswer:n}}const ie={id:"ielts-listening-test1-part1",title:"Part 1: Cycling Holiday in Austria",audioUrl:`${j}/test1-part1.mp3`,visualAidUrl:`${L}/test1-part1.png`,duration:380,content:"Questions 1-10. Complete the notes below. Write NO MORE THAN TWO WORDS AND/OR A NUMBER for each answer.",questions:[a("ls1-q1",1,"Holiday begins on","note-completion","Saturday"),a("ls1-q2",2,"No more than ____ people in cycling group","note-completion","12"),a("ls1-q3",3,"Each day, group cycles ____ on average","note-completion","35 km"),a("ls1-q4",4,"Some of the hotels have a","note-completion","swimming pool"),a("ls1-q5",5,"Holiday costs GBP ____ per person without flights","note-completion","760"),a("ls1-q6",6,"All food included except","note-completion","lunch"),a("ls1-q7",7,"Essential to bring a","note-completion","waterproof jacket"),a("ls1-q8",8,"Discount possible on equipment at www.____.com","note-completion","bikeplus"),a("ls1-q9",9,"Possible that the ____ may change","note-completion","route"),a("ls1-q10",10,"Guided tour of a ____ is arranged","note-completion","castle")]},re={id:"ielts-listening-test1-part2",title:"Part 2: Harbour Area and Restaurants",audioUrl:`${j}/test1-part2.mp3`,visualAidUrl:`${L}/test1-part2.png`,duration:420,content:"Questions 11-14: choose the correct letter A, B or C. Questions 15-20: choose SIX answers from the box and write the correct letter A-H.",questions:[a("ls1-q11",11,"The market is now situated","multiple-choice","2",["A. under a car park.","B. beside the cathedral.","C. near the river."]),a("ls1-q12",12,"On only one day a week the market sells","multiple-choice","2",["A. antique furniture.","B. local produce.","C. hand-made items."]),a("ls1-q13",13,"The area is well known for","multiple-choice","1",["A. ice cream.","B. a cake.","C. a fish dish."]),a("ls1-q14",14,"What change has taken place in the harbour area?","multiple-choice","1",["A. Fish can now be bought from the fishermen.","B. The restaurants have moved to a different part.","C. There are fewer restaurants than there used to be."]),a("ls1-q15",15,"Merrivales - advantage letter (A-H)","short-answer","2"),a("ls1-q16",16,"The Lobster Pot - advantage letter (A-H)","short-answer","5"),a("ls1-q17",17,"Elliots - advantage letter (A-H)","short-answer","1"),a("ls1-q18",18,"The Cabin - advantage letter (A-H)","short-answer","6"),a("ls1-q19",19,"The Olive Tree - advantage letter (A-H)","short-answer","7"),a("ls1-q20",20,"The Old School Restaurant - advantage letter (A-H)","short-answer","0")]},se={id:"ielts-listening-test1-part3",title:"Part 3: Film Project and Old Water-mill Map",audioUrl:`${j}/test1-part3.mp3`,visualAidUrl:`${L}/test1-part3.png`,duration:470,content:"Questions 21-26: choose SIX answers from the box A-I. Questions 27-30: choose four answers from the box A-G for the map.",questions:[a("ls1-q21",21,"Visit locations and discuss","short-answer","4"),a("ls1-q22",22,"Contact the ____ about roadworks","short-answer","5"),a("ls1-q23",23,"Plan the","short-answer","7"),a("ls1-q24",24,"Hold auditions and recheck availability of the","short-answer","1"),a("ls1-q25",25,"Choose the ____ from the volunteers","short-answer","8"),a("ls1-q26",26,"Collect ____ and organise food and transport","short-answer","9"),a("ls1-q27",27,"Map label 27 (A-G)","short-answer","1"),a("ls1-q28",28,"Map label 28 (A-G)","short-answer","5"),a("ls1-q29",29,"Map label 29 (A-G)","short-answer","4"),a("ls1-q30",30,"Map label 30 (A-G)","short-answer","7")]},he={id:"ielts-listening-test1-part4",title:"Part 4: Exotic Pests Table Completion",audioUrl:`${j}/test1-part4.mp3`,visualAidUrl:`${L}/test1-part4.png`,duration:520,content:"Questions 31-40. Complete the table below. Write NO MORE THAN TWO WORDS for each answer.",questions:[a("ls1-q31",31,"Even on island in middle of","note-completion","Pacific"),a("ls1-q32",32,"Imported into England to be used for","note-completion","food"),a("ls1-q33",33,"New habitat: ____ in Brisbane","note-completion","parks"),a("ls1-q34",34,"Origin: Australia. Name:","note-completion","cane toad"),a("ls1-q35",35,"Introduced to improve","note-completion","sugar cane"),a("ls1-q36",36,"New habitat: ____ Europe","note-completion","north-west"),a("ls1-q37",37,"Accidental introduction inside imported","note-completion","plants"),a("ls1-q38",38,"Origin: Japan. Name:","note-completion","starfish"),a("ls1-q39",39,"Budgerigar new habitat: urban areas of south-east","note-completion","England"),a("ls1-q40",40,"Smaller flocks because of arrival of","note-completion","cats")]},ae=[ie,re,se,he];function le(e,t){return{...e,id:`${e.id}-${t}`,questions:e.questions.map(o=>({...o,id:`${o.id}-${t}`,correctAnswer:Array.isArray(o.correctAnswer)?[...o.correctAnswer]:o.correctAnswer,options:o.options?[...o.options]:void 0}))}}const ce=ae.map(e=>le(e,"t2")),H=[{id:"ielts-listening-1",title:"IELTS Listening Full Test 1",type:"Academic",module:"Listening",duration:30,totalQuestions:40,sections:ae},{id:"ielts-listening-2",title:"IELTS Listening Full Test 2",type:"General Training",module:"Listening",duration:30,totalQuestions:40,sections:ce}],E=["A","B","C","D","E","F"],de=["Susanna Tol","Greg Spotts","Yanira Pineda","Elizabeth English","Raisa Chowdhury"],ue={id:"georgia-okeeffe-p1",title:"Reading Passage 1: Georgia O'Keeffe",paragraphs:[{label:"A",content:"For seven decades, Georgia O'Keeffe (1887-1986) was a major figure in American art. Remarkably, she remained independent from shifting art trends and her work stayed true to her own vision, which was based on finding the essential, abstract forms in nature. With exceptionally keen powers of observation and great finesse with a paintbrush, she recorded subtle nuances of colour, shape, and light that enlivened her paintings and attracted a wide audience."},{label:"B",content:"Born in 1887 near Sun Prairie, Wisconsin to cattle breeders Francis and Ida O'Keeffe, Georgia was raised on their farm along with her six siblings. By the time she graduated from high school in 1905, she had determined to make her way as an artist. She studied the techniques of traditional painting at the Art Institute of Chicago school (1905) and the Art Students League of New York (1907-8). After attending university and then training college, she became an art teacher and taught in elementary schools, high schools, and colleges in Virginia, Texas, and South Carolina from 1911 to 1918."},{label:"C",content:"During this period, O'Keeffe began to experiment with creating abstract compositions in charcoal, and produced a series of innovative drawings that led her art in a new direction. She sent some of these drawings to a friend in New York, who showed them to art collector and photographer Alfred Stieglitz in January 1916. Stieglitz was impressed, and exhibited the drawings later that year at his gallery on Fifth Avenue, New York City, where the works of many avant-garde artists and photographers were introduced to the American public."},{label:"D",content:"With Stieglitz's encouragement and promise of financial support, O'Keeffe arrived in New York in June 1918 to begin a career as an artist. For the next three decades, Stieglitz vigorously promoted her work in twenty-two solo exhibitions and numerous group installations. The two were married in 1924. The ups and downs of their personal and professional relationship were recorded in Stieglitz's celebrated black-and-white portraits of O'Keeffe, taken over the course of twenty years (1917-37)."},{label:"E",content:"By the mid-1920s, O'Keeffe was recognized as one of America's most important and successful artists, widely known for the architectural pictures that dramatically depict the soaring skyscrapers of New York. But most often, she painted botanical subjects, inspired by annual trips to the Stieglitz family summer home. In her magnified images depicting flowers, begun in 1924, O'Keeffe brings the viewer right into the picture."},{label:"F",content:"Enlarging the tiniest details to fill an entire metre-wide canvas emphasized their shapes and lines and made them appear abstract. Such daring compositions helped establish O'Keeffe's reputation as an innovative modernist."},{label:"G",content:"In 1929, O'Keeffe made her first extended trip to the state of New Mexico. It was a visit that had a lasting impact on her life, and an immediate effect on her work. Over the next two decades she made almost annual trips to New Mexico, staying up to six months there, painting in relative solitude, then returning to New York each winter to exhibit the new work at Stieglitz's gallery. This pattern continued until she moved permanently to New Mexico in 1949."},{label:"H",content:"There, O'Keeffe found new inspiration: at first, it was the numerous sun-bleached bones she came across in the state's rugged terrain that sparked her imagination. Two of her earliest and most celebrated Southwestern paintings exquisitely reproduce a cow skull's weathered surfaces, jagged edges, and irregular openings. Later, she also explored another variation on this theme in her large series of Pelvis pictures, which focused on the contrasts between convex and concave surfaces, and solid and open spaces. However, it was the region's spectacular landscape, with its unusual geological formations, vivid colours, clarity of light, and exotic vegetation, that held the artist's imagination for more than four decades. Often, she painted the rocks, cliffs, and mountains in striking close-up, just as she had done with her botanical subjects."},{label:"I",content:"O'Keeffe eventually owned two homes in New Mexico - the first, her summer retreat at Ghost Ranch, was nestled beneath 200-metre cliffs, while the second, used as her winter residence, was in the small town of Abiquiu. While both locales provided a wealth of imagery for her paintings, one feature of the Abiquiu house - the large walled patio with its black door - was particularly inspirational. In more than thirty pictures between 1946 and 1960, she reinvented the patio into an abstract arrangement of geometric shapes."},{label:"J",content:"From the 1950s into the 1970s, O'Keeffe travelled widely, making trips to Asia, the Middle East, and Europe. Flying in planes inspired her last two major series - aerial views of rivers and expansive paintings of the sky viewed from just above clouds. In both series, O'Keeffe increased the size of her canvases, sometimes to mural proportions, reflecting perhaps her newly expanded view of the world. When in 1965 she successfully translated one of her cloud motifs to a monumental canvas measuring 6 metres in length (with the help of assistants), it was an enormous challenge and a special feat for an artist nearing eighty years of age."},{label:"K",content:"The last two decades of the artist's life were relatively unproductive as ill health and blindness hindered her ability to work. O'Keeffe died in 1986 at the age of ninety-eight, but her rich legacy of some 900 paintings has continued to attract subsequent generations of artists and art lovers who derive inspiration from these very American images."}],questions:[{id:"gok-q1",number:1,type:"summary-completion",groupTitle:"Questions 1-7",instruction:"Complete the notes. Write ONE WORD ONLY from the text for each answer.",text:"The life and work of Georgia O'Keeffe: studied art, then worked as a ______ in various places in the USA.",correctAnswer:"teacher",location:"Paragraph B"},{id:"gok-q2",number:2,type:"summary-completion",text:"created drawings using ______ which were exhibited in New York City.",correctAnswer:"charcoal",location:"Paragraph C"},{id:"gok-q3",number:3,type:"summary-completion",text:"moved to New York and became famous for her paintings of the city's ______.",correctAnswer:"skyscrapers",location:"Paragraph E"},{id:"gok-q4",number:4,type:"summary-completion",text:"produced a series of innovative close-up paintings of ______.",correctAnswer:"flowers",location:"Paragraph E"},{id:"gok-q5",number:5,type:"summary-completion",text:"went to New Mexico and was initially inspired to paint the many ______ that could be found there.",correctAnswer:"bones",location:"Paragraph H"},{id:"gok-q6",number:6,type:"summary-completion",text:"continued to paint various features that together formed the dramatic ______ of New Mexico for over forty years.",correctAnswer:"landscape",location:"Paragraph H"},{id:"gok-q7",number:7,type:"summary-completion",text:"travelled widely by plane in later years, and painted pictures of clouds and ______ seen from above.",correctAnswer:"rivers",location:"Paragraph J"},{id:"gok-q8",number:8,type:"true-false-not-given",groupTitle:"Questions 8-13",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Georgia O'Keeffe's style was greatly influenced by the changing fashions in art over the seven decades of her career.",correctAnswer:"FALSE",location:"Paragraph A"},{id:"gok-q9",number:9,type:"true-false-not-given",text:"When O'Keeffe finished high school, she had already made her mind up about the career that she wanted.",correctAnswer:"TRUE",location:"Paragraph B"},{id:"gok-q10",number:10,type:"true-false-not-given",text:"Alfred Stieglitz first discovered O'Keeffe's work when she sent some abstract drawings to his gallery in New York City.",correctAnswer:"FALSE",location:"Paragraph C"},{id:"gok-q11",number:11,type:"true-false-not-given",text:"O'Keeffe was the subject of Stieglitz's photographic work for many years.",correctAnswer:"TRUE",location:"Paragraph D"},{id:"gok-q12",number:12,type:"true-false-not-given",text:"O'Keeffe's paintings of the patio of her house in Abiquiu were among the artist's favourite works.",correctAnswer:"NOT GIVEN",location:"Paragraph I"},{id:"gok-q13",number:13,type:"true-false-not-given",text:"O'Keeffe produced a greater quantity of work during the 1950s to 1970s than at any other time in her life.",correctAnswer:"NOT GIVEN",location:"Paragraphs J-K"}]},pe={id:"climate-adaptation-p2",title:"Reading Passage 2: Adapting to the effects of climate change",paragraphs:[{label:"A",content:"All around the world, nations are already preparing for, and adapting to, climate change and its impacts. Even if we stopped all CO2 emissions tomorrow, we would continue to see the impact of the CO2 already released since industrial times, with scientists forecasting that global warming would continue for around 40 years. In the meantime, ice caps would continue to melt and sea levels rise. Some countries and regions will suffer more extreme impacts from these changes than others. It's in these places that innovation is thriving."},{label:"B",content:"In Miami Beach, Florida, USA, seawater isn't just breaching the island city's walls, it's seeping up through the ground, so the only way to save the city is to lift it up above sea level. Starting in the lowest and most vulnerable neighbourhoods, roads have been raised by as much as 61 centimetres. The elevation work was carried out as part of Miami Beach's ambitious but much-needed stormwater-management programme. In addition to the road adaptations, the city has set up new pumps that can remove up to 75,000 litres of water per minute. In the face of floods, climate-mitigation strategies have often been overlooked, says Yanira Pineda, a senior sustainability coordinator. She knows that they're essential and that the job is far from over. 'We know that in 20, 30, 40 years, we'll need to go back in there and adjust to the changing environment,' she says."},{label:"C",content:"Seawalls are a staple strategy for many coastal communities, but on the soft, muddy northern shores of Java, Indonesia, they frequently collapse, further exacerbating coastal erosion. There have been many attempts to restore the island's coastal mangroves: ecosystems of trees and shrubs that help defend coastal areas by trapping sediment in their net-like root systems, elevating the sea bed and dampening the energy of waves and tidal currents. But Susanna Tol of the not-for-profit organisation Wetlands International says that, while hugely popular, the majority of mangrove-planting projects fail. So, Wetlands International started out with a different approach, building semi-permeable dams, made from bamboo poles and brushwood, to mimic the role of mangrove roots and create favourable conditions for mangroves to grow back naturally. The programme has seen moderate success, mainly in areas with less subsidence. 'Unfortunately, traditional infrastructure is often single-solution focused,' says Tol. 'For long-term success, it's critical that we transition towards multifunctional approaches that embed natural processes and that engage and benefit communities and local decision-makers.'"},{label:"D",content:"As the floodwaters rose in the rice fields of the Mekong Delta in September 2018, four small houses rose with them. Homes in this part of Vietnam are traditionally built on stilts but these ones had been built to float. The modifications were made by the Buoyant Foundation Project, a not-for-profit organisation that has been researching and retrofitting amphibious houses since 2006. 'When I started this,' explains founder Elizabeth English, 'climate change was not on the tip of everybody's tongue, but this technology is becoming necessary in places that didn't previously need it.' It's much cheaper than permanently elevating houses, English explains - about a third of what it would cost to completely replace a building's foundations. It also avoids the problem of taller houses being at greater risk from wind damage. Another plus comes from the fact that amphibious structures can be sensitively adapted to meet cultural needs and match the kind of houses that are already common in a community."},{label:"E",content:"Bangladesh is especially vulnerable to climate change. Most of the country is less than a metre above sea level and 80 per cent of its land lies on floodplains. 'Almost 35 million people living on the coastal belt of Bangladesh are currently affected by soil and water salinity,' says Raisa Chowdhury of the international development organisation ICCO Cooperation. Rather than fighting against it, one project is helping communities adapt to salt-affected soils. ICCO Cooperation has been working with 10,000 farmers in Bangladesh to start cultivating naturally salt-tolerant crops in the region. Certain varieties of carrot, potato, kohlrabi, cabbage and beetroot have been found to be better suited to salty soil than the rice and wheat that is typically grown there. Chowdhury says that the results are very visible, comparing a barren plot of land to the 'beautiful, lush green vegetable garden' sitting beside it, in which he and his team have been working with the farmers. Since the project began, farmers trained in saline agriculture have reported increases of two to three more harvests per year."},{label:"F",content:"Greg Spotts from Los Angeles (LA) in the USA is chief sustainability officer of the city's street services department. He leads the Cool Streets LA programme, a series of pilot projects, which include the planting of trees and the installation of a 'cool pavement' system, designed to help reach the city's goal of bringing down its average temperature by 1.5C. 'Urban cooling is literally a matter of life and death for our future in LA,' says Spotts. Using a Geographic Information System data mapping tool, the programme identified streets with low tree canopy cover in three of the city's neighbourhoods and covered them with a light-grey, light-reflecting coating, which had already been shown to lower road surface temperature in Los Angeles by 6C. Spotts says one of these streets, in the Winnetka neighbourhood of San Fernando Valley, can now be seen as a pale crescent, the only cool spot on an otherwise red thermal image, from the International Space Station."}],questions:[{id:"cca-q14",number:14,type:"matching-information",groupTitle:"Questions 14-17",instruction:"The text has six sections A-F. Which section contains the following information? Choose the correct paragraph A-F.",text:"how a type of plant functions as a natural protection for coastlines",options:E,correctAnswer:"C",location:"Paragraph C"},{id:"cca-q15",number:15,type:"matching-information",text:"a prediction about how long it could take to stop noticing the effects of climate change",options:E,correctAnswer:"A",location:"Paragraph A"},{id:"cca-q16",number:16,type:"matching-information",text:"a reference to the fact that a solution is particularly cost-effective",options:E,correctAnswer:"D",location:"Paragraph D"},{id:"cca-q17",number:17,type:"matching-information",text:"a mention of a technology used to locate areas most in need of intervention",options:E,correctAnswer:"F",location:"Paragraph F"},{id:"cca-q18",number:18,type:"summary-completion",groupTitle:"Questions 18-22",instruction:"Complete the sentences. Write ONE WORD ONLY from the text for each answer.",text:"The stormwater-management programme in Miami Beach has involved the installation of efficient ______.",correctAnswer:"pumps",location:"Paragraph B"},{id:"cca-q19",number:19,type:"summary-completion",text:"The construction of ______ was the first stage of a project to ensure the success of mangroves in Indonesia.",correctAnswer:"dams",location:"Paragraph C"},{id:"cca-q20",number:20,type:"summary-completion",text:"As a response to rising floodwaters in the Mekong Delta, a not-for-profit organisation has been building houses that can ______.",correctAnswer:"float",location:"Paragraph D"},{id:"cca-q21",number:21,type:"summary-completion",text:"Rising sea levels in Bangladesh have made it necessary to introduce various ______ that are suitable for areas of high salt content.",correctAnswer:"crops",location:"Paragraph E"},{id:"cca-q22",number:22,type:"summary-completion",text:"A project in LA has increased the number of ______ on the city's streets.",correctAnswer:"trees",location:"Paragraph F"},{id:"cca-q23",number:23,type:"drag-drop-summary",groupTitle:"Questions 23-26",instruction:"Complete the summary by dragging the correct words into the gaps.",text:`It is essential to adopt strategies which involve and help residents of the region.
Interventions which reduce heat are absolutely vital for our survival in this location.
More work will need to be done in future decades to deal with the impact of rising water levels.
The number of locations requiring action to adapt to flooding has grown in recent years.`,options:de,correctAnswer:["Susanna Tol","Greg Spotts","Yanira Pineda","Elizabeth English"],location:"Paragraphs B, C, D, F"}]},me={id:"metropolis-p3",title:"Reading Passage 3: Movie of Metropolis",paragraphs:[{label:"A",content:"When German director Fritz Lang visited the United States in 1924, his first glimpse of the country was a night-time view of the New York skyline from the deck of an ocean liner. This, he later recalled, was the direct inspiration for what is still probably the most innovative and influential science-fiction film ever made - Metropolis."},{label:"B",content:"Metropolis is a bleak vision of the early twenty-first century that is at once both chilling and exhilarating. This spectacular city of the future is a technological marvel of high-rise buildings connected by elevated railways and airships. It's also a world of extreme inequality and social division. The workers live below ground and exist as machines working in an endless routine of mind-numbing 10-hour shifts while the city's elite lead lives of luxury high above. Presiding over them all is the Master of Metropolis, John Fredersen, whose sole satisfaction seems to lie in the exercise of power."},{label:"C",content:"Lang's graphic depiction of the future is conceived in almost totally abstract terms. The function of the individual machines is never defined. Instead, this mass of dials, levers and gauges symbolically stands for all machines and all industry, with the workers as slave-like extensions of the equipment they have to operate. Lang emphasizes this idea in the famous shift-change sequence at the start of the movie when the workers walk in zombie-like geometric ranks, all dressed in the same dark overalls and all exhibiting the same bowed head and dead-eyed stare. An extraordinary fantasy sequence sees one machine transformed into a huge open-jawed statue which then literally swallows them up."},{label:"D",content:"On one level the machines and the exploited workers simply provide the wealth and services which allow the elite to live their lives of leisure, but on a more profound level, the purpose of all this demented industry is to serve itself. Power, control and the continuance of the system from one 10-hour shift to the next is all that counts. The city consumes people and their labour and in the process becomes a perverse parody of a living being."},{label:"E",content:"It is enlightening, I think, to relate the film to the modern global economy in which multinational corporations now routinely close their factories in one continent so that they can take advantage of cheap labour in another. Like the industry in Metropolis, these corporations' goals of increased efficiency and profits have little to do with the welfare of the majority of their employees or that of the population at large. Instead, their aims are to sustain the momentum of their own growth and to increase the monetary rewards to a tiny elite - their executives and shareholders. Fredersen himself is the essence of the big company boss: Rupert Murdoch would probably feel perfectly at home in his huge skyscraper office with its panoramic view of the city below. And it is important that there is never any mention of government in Metropolis - the whole concept is by implication obsolete. The only people who have power are the supreme industrialist, Fredersen, and his magician/scientist cohort Rotwang."},{label:"F",content:"So far so good: when the images are allowed to speak for themselves the film is impeccable both in its symbolism and in its cynicism. The problem with Metropolis is its sentimental story-line, which sees Freder, Fredersen's son, instantly falling in love with the visionary Maria. Maria leads an underground pseudo-religious movement and preaches that the workers should not rebel but should await the arrival of a 'Mediator' between the 'Head' (capital) and the 'Hands' (labour). That mediator is the 'Heart' - love, as embodied, finally, by Freder's love of Maria and his father's love of him."},{label:"G",content:"Lang wrote the screenplay in collaboration with his then-wife Thea von Harbou. In 1933 he fled from the Nazis (and continued a very successful career in Hollywood). She stayed in Germany and continued to make films under the Hitler regime. There is a constant tension within the film between the too-tidy platitudes of von Harbou's script and the uncompromisingly caustic vigour of Lang's imagery."},{label:"H",content:"To my mind, both in Metropolis and in the real world, it's not so much that the 'Head' and 'Hands' require a 'Heart' to mediate between them but that the 'Hands' need to develop their own 'Head', their own political consciousness, and act accordingly - through the ballot box, through buying power and through a sceptical resistance to the materialistic fantasies of the Fredersens."},{label:"I",content:"All the same, Metropolis is probably more accurate now as a representation of industrial and social relations than it has been at any time since its original release. And Fredersen is certainly still the most potent movie symbol of the handful of elusive corporate figureheads who increasingly treat the world as a Metropolis-like global village."}],questions:[{id:"met-q27",number:27,type:"yes-no-not-given",groupTitle:"Questions 27-30",instruction:"Choose YES if the statement agrees with the information in the text, choose NO if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"The inspiration of the movie - Metropolis - comes from the director's visit in the USA in 1924.",correctAnswer:"YES",location:"Paragraph A"},{id:"met-q28",number:28,type:"yes-no-not-given",text:"The Master of Metropolis, John Fredersen, is portrayed from an industrialist that the director met in the US.",correctAnswer:"NOT GIVEN",location:"Paragraphs A-B"},{id:"met-q29",number:29,type:"yes-no-not-given",text:"The start of the movie exhibits the workers working in full energy.",correctAnswer:"NO",location:"Paragraph C"},{id:"met-q30",number:30,type:"yes-no-not-given",text:"The director and his wife got divorced because his wife decided to stay in Germany.",correctAnswer:"NOT GIVEN",location:"Paragraph G"},{id:"met-q31",number:31,type:"summary-completion",groupTitle:"Questions 31-36",instruction:"Complete the summary. Write NO MORE THAN TWO WORDS from the text for each answer.",text:"The director depicts a world of inequality and ______.",correctAnswer:"social division",location:"Paragraph B"},{id:"met-q32",number:32,type:"summary-completion",text:"In the future, the mindless masses of workers living underground are treated as ______.",correctAnswer:"machines",location:"Paragraph B"},{id:"met-q33",number:33,type:"summary-completion",text:"And the master of them is ______, who is in charge of the whole city.",correctAnswer:"John Fredersen",location:"Paragraph B"},{id:"met-q34",number:34,type:"summary-completion",text:"The writer claims that the director, Fritz Lang, presents the movie in almost totally ______ terms.",correctAnswer:"abstract",location:"Paragraph C"},{id:"met-q35",number:35,type:"summary-completion",text:"In this presentation, the ______ of the individual machines is not defined.",correctAnswer:"function",location:"Paragraph C"},{id:"met-q36",number:36,type:"summary-completion",text:"Besides, the writer compares the film to the modern global economy in which multinational corporations care more about growing ______ and money.",correctAnswer:"profits",location:"Paragraph E"},{id:"met-q37",number:37,type:"multiple-choice",groupTitle:"Question 37",instruction:"Choose the correct answer.",text:"The first sentence in paragraph B indicates",options:["the author's fear about technology","the inspiration of the director","the contradictory feelings towards future","the city elite's well management of the workers"],correctAnswer:"C",location:"Paragraph B"},{id:"met-q38",number:38,type:"multiple-choice",groupTitle:"Question 38",instruction:"Choose the correct letter, A, B, C, or D.",text:"Why the function of the individual machines is not defined?",options:["Because Lang sticks to the theme in a symbolic way.","Because workers are more important to exploit.","Because the fantasy sequence is difficult to take.","Because the focus of the movie is not about machines."],correctAnswer:"A",location:"Paragraph C"},{id:"met-q39",number:39,type:"multiple-choice",groupTitle:"Question 39",instruction:"Choose the correct letter, A, B, C, or D.",text:"The writer's purpose in paragraph five is to",options:["emphasize the multinational corporations' profit-oriented goal","compare the movie with the reality in the modern global economy","exploit the difference between fantasy and reality","enlighten the undeveloped industry"],correctAnswer:"B",location:"Paragraph E"},{id:"met-q40",number:40,type:"multiple-choice",groupTitle:"Question 40",instruction:"Choose the correct letter, A, B, C, or D.",text:"What is the writer's opinion about the movie?",options:["The movie's story-line is excellent.","The movie has a poor implication in symbolism.","The movie is perfect in all aspects.","The movie is good but could be better."],correctAnswer:"D",location:"Paragraph F"}]},w={id:"ielts-reading-full-vol1",title:"IELTS Reading Full Test 1 - Georgia O'Keeffe, Climate Change, Metropolis",type:"Academic",module:"Reading",duration:60,totalQuestions:40,sections:[ue,pe,me]},b=["A","B","C","D","E","F","G"],v=["A. Matt Elliot","B. Karen Russell","C. Peter Bourne"],A=["A. made them feel optimistic.","B. took relatively little notice of bad news.","C. responded to negative and positive information in the same way.","D. were feeling under stress.","E. put them in a stressful situation.","F. behaved in a similar manner, regardless of the circumstances.","G. thought it more likely that they would experience something bad."],ge={id:"kakapo-p1",title:"Reading Passage 1: The kākāpō",paragraphs:[{label:"A",content:"The kākāpō. The kākāpō is a nocturnal, flightless parrot that is critically endangered and one of New Zealand's unique treasures. The kākāpō, also known as the owl parrot, is a large, forest-dwelling bird, with a pale owl-like face. Up to 64 cm in length, it has predominantly yellow-green feathers, forward-facing eyes, a large grey beak, large blue feet, and relatively short wings and tail. It is the world's only flightless parrot, and is also possibly one of the world's longest-living birds, with a reported lifespan of up to 100 years."},{label:"B",content:"Kākāpō are solitary birds and tend to occupy the same home range for many years. They forage on the ground and climb high into trees. They often leap from trees and flap their wings, but at best manage a controlled descent to the ground. They are entirely vegetarian, with their diet including the leaves, roots and bark of trees as well as bulbs, and fern fronds."},{label:"C",content:"Kākāpō breed in summer and autumn, but only in years when food is plentiful. Males play no part in incubation or chick-rearing - females alone incubate eggs and feed the chicks. The 1-4 eggs are laid in soil, which is repeatedly turned over before and during incubation. The female kākāpō has to spend long periods away from the nest searching for food, which leaves the unattended eggs and chicks particularly vulnerable to predators."},{label:"D",content:"Before humans arrived, kākāpō were common throughout New Zealand's forests. However, this all changed with the arrival of the first Polynesian settlers about 700 years ago. For the early settlers, the flightless kākāpō was easy prey. They ate its meat and used its feathers to make soft cloaks. With them came the Polynesian dog and rat, which also preyed on kākāpō. By the time European colonisers arrived in the early 1800s, kākāpō had become confined to the central North Island and forested parts of the South Island. The fall in kākāpō numbers was accelerated by European colonisation. A great deal of habitat was lost through forest clearance, and introduced species such as deer depleted the remaining forests of food. Other predators such as cats, stoats and two more species of rat were also introduced. The kākāpō were in serious trouble."},{label:"E",content:"In 1894, the New Zealand government launched its first attempt to save the kākāpō. Conservationist Richard Henry led an effort to relocate several hundred of the birds to predator-free Resolution Island in Fiordland. Unfortunately, the island didn't remain predator free - stoats arrived within six years, eventually destroying the kākāpō population. By the mid-1900s, the kākāpō was practically a lost species. Only a few clung to life in the most isolated parts of New Zealand."},{label:"F",content:"From 1949 to 1973, the newly formed New Zealand Wildlife Service made over 60 expeditions to find kākāpō, focusing mainly on Fiordland. Six were caught, but there were no females amongst them and all but one died within a few months of captivity. In 1974, a new initiative was launched, and by 1977, 18 more kākāpō were found in Fiordland. However, there were still no females. In 1977, a large population of males was spotted in Rakiura - a large island free from stoats, ferrets and weasels. There were about 200 individuals, and in 1980 it was confirmed females were also present. These birds have been the foundation of all subsequent work in managing the species."},{label:"G",content:"Unfortunately, predation by feral cats on Rakiura Island led to a rapid decline in kākāpō numbers. As a result, during 1980-97, the surviving population was evacuated to three island sanctuaries: Codfish Island, Maud Island and Little Barrier Island. However, breeding success was hard to achieve. Rats were found to be a major predator of kākāpō chicks and an insufficient number of chicks survived to offset adult mortality. By 1995, although at least 12 chicks had been produced on the islands, only three had survived. The kākāpō population had dropped to 51 birds. The critical situation prompted an urgent review of kākāpō management in New Zealand."},{label:"H",content:"In 1996, a new Recovery Plan was launched, together with a specialist advisory group called the Kākāpō Scientific and Technical Advisory Committee and a higher amount of funding. Renewed steps were taken to control predators on the three islands. Cats were eradicated from Little Barrier Island in 1980, and possums were eradicated from Codfish Island by 1986. However, the population did not start to increase until rats were removed from all three islands, and the birds were more intensively managed. This involved moving the birds between islands, supplementary feeding of adults and rescuing and hand-raising any failing chicks."},{label:"I",content:"After the first five years of the Recovery Plan, the population was on target. By 2000, five new females had been produced, and the total population had grown to 62 birds. For the first time, there was cautious optimism for the future of kākāpō and by June 2020, a total of 210 birds was recorded."},{label:"J",content:"Today, kākāpō management continues to be guided by the kākāpō Recovery Plan. Its key goals are: minimise the loss of genetic diversity in the kākāpō population, restore or maintain sufficient habitat to accommodate the expected increase in the kākāpō population, and ensure stakeholders continue to be fully engaged in the preservation of the species."}],questions:[{id:"kakapo-q1",number:1,type:"true-false-not-given",groupTitle:"Questions 1-6",instruction:"Choose TRUE if the statement agrees with the information given in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"There are other parrots that share the kakapo's inability to fly.",correctAnswer:"FALSE",location:"Paragraph A"},{id:"kakapo-q2",number:2,type:"true-false-not-given",text:"Adult kakapo produce chicks every year.",correctAnswer:"FALSE",location:"Paragraph C"},{id:"kakapo-q3",number:3,type:"true-false-not-given",text:"Adult male kakapo bring food back to nesting females.",correctAnswer:"FALSE",location:"Paragraph C"},{id:"kakapo-q4",number:4,type:"true-false-not-given",text:"The Polynesian rat was a greater threat to the kakapo than Polynesian settlers.",correctAnswer:"NOT GIVEN",location:"Paragraph D"},{id:"kakapo-q5",number:5,type:"true-false-not-given",text:"Kakapo were transferred from Rakiura Island to other locations because they were at risk from feral cats.",correctAnswer:"TRUE",location:"Paragraph H"},{id:"kakapo-q6",number:6,type:"true-false-not-given",text:"One Recovery Plan initiative that helped increase the kakapo population size was caring for struggling young birds.",correctAnswer:"TRUE",location:"Paragraph H"},{id:"kakapo-q7",number:7,type:"summary-completion",groupTitle:"Questions 7-13",instruction:"Complete the notes below. Choose ONE WORD AND/OR A NUMBER from the passage for each answer.",text:"diet consists of fern fronds, various parts of a tree and ______.",correctAnswer:"bulbs",location:"Paragraph B"},{id:"kakapo-q8",number:8,type:"summary-completion",text:"nests are created in ______ where eggs are laid",correctAnswer:"soil",location:"Paragraph C"},{id:"kakapo-q9",number:9,type:"summary-completion",text:"the ______ of the kakapo were used to make clothes",correctAnswer:"feathers",location:"Paragraph D"},{id:"kakapo-q10",number:10,type:"summary-completion",text:"______ were an animal which they introduced that ate the kakapo food sources",correctAnswer:"deer",location:"Paragraph D"},{id:"kakapo-q11",number:11,type:"summary-completion",text:"a definite sighting of female kakapo on Rakiura Island was reported in the year ______",correctAnswer:"1980",location:"Paragraph F"},{id:"kakapo-q12",number:12,type:"summary-completion",text:"the Recovery Plan included an increase in ______",correctAnswer:"funding",location:"Paragraph H"},{id:"kakapo-q13",number:13,type:"summary-completion",text:"a current goal of the Recovery Plan is to maintain the involvement of ______ in kakapo protection",correctAnswer:"stakeholders",location:"Paragraph J"}]},fe={id:"elm-return-p2",title:"Reading Passage 2: Return of the elm",paragraphs:[{label:"A",content:`Return of the elm: reintroducing the beloved tree to Britain. Mark Rowe investigates attempts to reintroduce elms to Britain. Around 25 million elms, accounting for 90% of all elm trees in the UK, died during the 1960s and '70s of Dutch elm disease. In the aftermath, the elm, once so dominant in the British landscape, was largely forgotten. However, there's now hope the elm may be reintroduced to the countryside of central and southern England. Any reintroduction will start from a very low base. "The impact of the disease is difficult to picture if you hadn't seen what was there before," says Matt Elliot of the Woodland Trust. "You look at old photographs from the 1960s and it's only then that you realise the impact [elms had]...They were significant, large trees...then they were gone."`},{label:"B",content:"The disease is caused by a fungus that blocks the elms' vascular (water, nutrient and food transport) system, causing branches to wilt and die. A first epidemic, which occurred in the 1920s, gradually died down, but in the '70s a second epidemic was triggered by shipments of elm from Canada. The wood came in the form of logs destined for boat building and its intact bark was perfect for the elm bark beetles that spread the deadly fungus. This time, the beetles carried a much more virulent strain that destroyed the vast majority of British elms."},{label:"C",content:`Today, elms still exist in the southern English countryside but mostly only in low hedgerows between fields. "We have millions of small elms in hedgerows but they get targeted by the beetle as soon as they reach a certain size," says Karen Russell, co-author of the report 'Where we are with elm'. Once the trunk of the elm reaches 10-15 centimetres or so in diameter, it becomes a perfect size for beetles to lay eggs and for the fungus to take hold. Yet mature specimens have been identified, in counties such as Cambridgeshire, that are hundreds of years old, and have mysteriously escaped the epidemic. The key, Russell says, is to identify and study those trees that have survived and work out why they stood tall when millions of others succumbed. Nevertheless, opportunities are limited as the number of these mature survivors is relatively small. "What are the reasons for their survival?" asks Russell. "Avoidance, tolerance, resistance? We don't know where the balance lies between the three. I don't see how it can be entirely down to luck."`},{label:"D",content:"For centuries, elm ran a close second to oak as the hardwood tree of choice in Britain and was in many instances the most prominent tree in the landscape. Not only was elm common in European forests, it became a key component of birch, ash and hazel woodlands. The use of elm is thought to go back to the Bronze Age, when it was widely used for tools. Elm was also the preferred material for shields and early swords. In the 18th century, it was planted more widely and its wood was used for items such as storage crates and flooring. It was also suitable for items that experienced high levels of impact and was used to build the keel of the 19th-century sailing ship Cutty Sark as well as mining equipment."},{label:"E",content:`Given how ingrained elm is in British culture, it's unsurprising the tree has many advocates. Amongst them is Peter Bourne of the National Elm Collection in Brighton. "I saw Dutch elm disease unfold as a small boy," he says. "The elm seemed to be part of rural England, but I remember watching trees just lose their leaves and that really stayed with me." Today, the city of Brighton's elms total about 17,000. Local factors appear to have contributed to their survival. Strong winds from the sea make it difficult for the determined elm bark beetle to attack this coastal city's elm population. However, the situation is precarious. "The beetles can just march in if we're not careful, as the threat is right on our doorstep," says Bourne.`},{label:"F",content:'Any prospect of the elm returning relies heavily on trees being either resistant to, or tolerant of, the disease. This means a widespread reintroduction would involve existing or new hybrid strains derived from resistant, generally non-native elm species. A new generation of seedlings have been bred and tested to see if they can withstand the fungus by cutting a small slit on the bark and injecting a tiny amount of the pathogen. "The effects are very quick," says Russell. "You return in four to six weeks and trees that are resistant show no symptoms, whereas those that are susceptible show leaf loss and may even have died completely."'},{label:"G",content:`All of this raises questions of social acceptance, acknowledges Russell. "If we're putting elm back into the landscape, a small element of it is not native - are we bothered about that?" For her, the environmental case for reintroducing elm is strong. "They will host wildlife, which is a good thing." Others are more wary. "On the face of it, it seems like a good idea," says Elliot. The problem, he suggests, is that, "You're replacing a native species with a horticultural analogue*. You're effectively cloning." There's also the risk of introducing new diseases. Rather than plant new elms, the Woodland Trust emphasises providing space to those elms that have survived independently. "Sometimes the best thing you can do is just give nature time to recover... over time, you might get resistance," says Elliot.`},{label:"H",content:"Glossary: * horticultural analogue: a cultivated plant species that is genetically similar to an existing species."}],questions:[{id:"elm-q14",number:14,type:"matching-information",groupTitle:"Questions 14-18",instruction:"Reading Passage 2 has seven sections. Which section contains the following information? You may use any letter more than once.",text:"reference to the research problems that arise from there being only a few surviving large elms",options:b,correctAnswer:"C",location:"Paragraph C"},{id:"elm-q15",number:15,type:"matching-information",text:"details of a difference of opinion about the value of reintroducing elms to Britain",options:b,correctAnswer:"G",location:"Paragraph G"},{id:"elm-q16",number:16,type:"matching-information",text:"reference to how Dutch elm disease was brought into Britain",options:b,correctAnswer:"B",location:"Paragraph B"},{id:"elm-q17",number:17,type:"matching-information",text:"a description of the conditions that have enabled a location in Britain to escape Dutch elm disease",options:b,correctAnswer:"E",location:"Paragraph E"},{id:"elm-q18",number:18,type:"matching-information",text:"reference to the stage at which young elms become vulnerable to Dutch elm disease",options:b,correctAnswer:"C",location:"Paragraph C"},{id:"elm-q19",number:19,type:"matching-headings",groupTitle:"Questions 19-23",instruction:"Look at the following statements and the list of people below. Match each statement with the correct person.",text:"If a tree gets infected with Dutch elm disease, the damage rapidly becomes visible.",options:v,correctAnswer:"B",location:"Paragraph F"},{id:"elm-q20",number:20,type:"matching-headings",text:"It may be better to wait and see if the mature elms that have survived continue to flourish.",options:v,correctAnswer:"A",location:"Paragraph G"},{id:"elm-q21",number:21,type:"matching-headings",text:"There must be an explanation for the survival of some mature elms.",options:v,correctAnswer:"B",location:"Paragraph C"},{id:"elm-q22",number:22,type:"matching-headings",text:"We need to be aware that insects carrying Dutch elm disease are not very far away.",options:v,correctAnswer:"C",location:"Paragraph E"},{id:"elm-q23",number:23,type:"matching-headings",text:"You understand the effect Dutch elm disease has had when you see evidence of how prominent the tree once was.",options:v,correctAnswer:"A",location:"Paragraph A"},{id:"elm-q24",number:24,type:"summary-completion",groupTitle:"Questions 24-26",instruction:"Complete the summary below. Choose ONE WORD ONLY from the passage for each answer.",text:"For hundreds of years, the only tree that was more popular in Britain than elm was ______.",correctAnswer:"oak",location:"Paragraph D"},{id:"elm-q25",number:25,type:"summary-completion",text:"In the 18th century, it was grown to provide wood for boxes and ______.",correctAnswer:"flooring",location:"Paragraph D"},{id:"elm-q26",number:26,type:"summary-completion",text:"Due to its strength, elm was often used for mining equipment and the Cutty Sark's ______ was also constructed from elm.",correctAnswer:"keel",location:"Paragraph D"}]},ye={id:"stress-judgement-p3",title:"Reading Passage 3: How stress affects our judgement",paragraphs:[{label:"A",content:"Some of the most important decisions of our lives occur while we're feeling stressed and anxious. From medical decisions to financial and professional ones, we are all sometimes required to weigh up information under stressful conditions. But do we become better or worse at processing and using information under such circumstances?"},{label:"B",content:"My colleague and I, both neuroscientists, wanted to investigate how the mind operates under stress, so we visited some local fire stations. Firefighters' workdays vary quite a bit. Some are pretty relaxed; they'll spend their time washing the truck, cleaning equipment, cooking meals and reading. Other days can be hectic, with numerous life-threatening incidents to attend to; they'll enter burning homes to rescue trapped residents, and assist with medical emergencies. These ups and downs presented the perfect setting for an experiment on how people's ability to use information changes when they feel under pressure."},{label:"C",content:"We found that perceived threat acted as a trigger for a stress reaction that made the task of processing information easier for the firefighters - but only as long as it conveyed bad news."},{label:"D",content:"This is how we arrived at these results. We asked the firefighters to estimate their likelihood of experiencing 40 different adverse events in their life, such as being involved in an accident or becoming a victim of card fraud. We then gave them either good news (that their likelihood of experiencing these events was lower than they'd thought) or bad news (that it was higher) and asked them to provide new estimates."},{label:"E",content:"People are normally quite optimistic - they will ignore bad news and embrace the good. This is what happened when the firefighters were relaxed; but when they were under stress, a different pattern emerged. Under these conditions, they became hyper-vigilant to bad news, even when it had nothing to do with their job, and altered their beliefs in response. In contrast, stress didn't change how they responded to good news."},{label:"F",content:"Back in our lab, we observed the same pattern in students who were told they had to give a surprise public speech, which would be judged by a panel, recorded and posted online. Sure enough, their cortisol levels spiked, their heart rates went up and they suddenly became better at processing unrelated, yet alarming, information about rates of disease and violence."},{label:"G",content:"When we experience stressful events, a physiological change is triggered that causes us to take in warnings and focus on what might go wrong. Brain imaging reveals that this 'switch' is related to a sudden boost in a neural signal important for learning, specifically in response to unexpected warning signs, such as faces expressing fear."},{label:"H",content:"Such neural engineering could have helped prehistoric humans to survive. When our ancestors found themselves surrounded by hungry animals, they would have benefited from an increased ability to learn about hazards. In a safe environment, however, it would have been wasteful to be on high alert constantly. So, a neural switch that automatically increases or decreases our ability to process warnings in response to changes in our environment could have been useful. In fact, people with clinical depression and anxiety seem unable to switch away from a state in which they absorb all the negative messages around them."},{label:"I",content:"It is also important to realise that stress travels rapidly from one person to the next. If a co-worker is stressed, we are more likely to tense up and feel stressed ourselves. We don't even need to be in the same room with someone for their emotions to influence our behaviour. Studies show that if we observe positive feeds on social media, such as images of a pink sunset, we are more likely to post uplifting messages ourselves. If we observe negative posts, such as complaints about a long queue at the coffee shop, we will in turn create more negative posts."},{label:"J",content:"In some ways, many of us now live as if we are in danger, constantly ready to tackle demanding emails and text messages, and respond to news alerts and comments on social media. Repeatedly checking your phone, according to a survey conducted by the American Psychological Association, is related to stress. In other words, a pre-programmed physiological reaction, which evolution has equipped us with to help us avoid famished predators, is now being triggered by an online post. Social media posting, according to one study, raises your pulse, makes you sweat, and enlarges your pupils more than most daily activities."},{label:"K",content:"The fact that stress increases the likelihood that we will focus more on alarming messages, together with the fact that it spreads extremely rapidly, can create collective fear that is not always justified. After a stressful public event, such as a natural disaster or major financial crash, there is often a wave of alarming information in traditional and social media, which individuals become very aware of. But that has the effect of exaggerating existing danger. And so, a reliable pattern emerges - stress is triggered, spreading from one person to the next, which temporarily enhances the likelihood that people will take in negative reports, which increases stress further. As a result, trips are cancelled, even if the disaster took place across the globe; stocks are sold, even when holding on is the best thing to do."},{label:"L",content:"The good news, however, is that positive emotions, such as hope, are contagious too, and are powerful in inducing people to act to find solutions. Being aware of the close relationship between people's emotional state and how they process information can help us frame our messages more effectively and become conscientious agents of change."}],questions:[{id:"stress-q27",number:27,type:"multiple-choice",groupTitle:"Question 27",instruction:"Choose the correct answer.",text:"In the first paragraph, the writer introduces the topic of the text by",options:["defining some commonly used terms.","questioning a widely held assumption.","mentioning a challenge faced by everyone.","specifying a situation which makes us most anxious."],correctAnswer:"C",location:"Paragraph A"},{id:"stress-q28",number:28,type:"multiple-choice",groupTitle:"Question 28",instruction:"Choose the correct answer.",text:"What point does the writer make about firefighters in the second paragraph?",options:["The regular changes of stress levels in their working lives make them ideal study subjects.","The strategies they use to handle stress are of particular interest to researchers.","The stressful nature of their job is typical of many public service professions.","Their personalities make them especially well-suited to working under stress."],correctAnswer:"A",location:"Paragraph B"},{id:"stress-q29",number:29,type:"multiple-choice",groupTitle:"Question 29",instruction:"Choose the correct answer.",text:"What is the writer doing in the fourth paragraph?",options:["explaining their findings","justifying their approach","setting out their objectives","describing their methodology"],correctAnswer:"D",location:"Paragraph D"},{id:"stress-q30",number:30,type:"multiple-choice",groupTitle:"Question 30",instruction:"Choose the correct answer.",text:"In the seventh paragraph, the writer describes a mechanism in the brain which",options:["enables people to respond more quickly to stressful situations.","results in increased ability to control our levels of anxiety.","produces heightened sensitivity to indications of external threats.","is activated when there is a need to communicate a sense of danger."],correctAnswer:"C",location:"Paragraph G"},{id:"stress-q31",number:31,type:"matching-headings",groupTitle:"Questions 31-35",instruction:"Complete each sentence with the correct ending.",text:"At times when they were relaxed, the firefighters usually",options:A,correctAnswer:"B",location:"Paragraph E"},{id:"stress-q32",number:32,type:"matching-headings",text:"The researchers noted that when the firefighters were stressed, they",options:A,correctAnswer:"G",location:"Paragraph E"},{id:"stress-q33",number:33,type:"matching-headings",text:"When the firefighters were told good news, they always",options:A,correctAnswer:"F",location:"Paragraph E"},{id:"stress-q34",number:34,type:"matching-headings",text:"The students' cortisol levels and heart rates were affected when the researchers",options:A,correctAnswer:"E",location:"Paragraph F"},{id:"stress-q35",number:35,type:"matching-headings",text:"In both experiments, negative information was processed better when the subjects",options:A,correctAnswer:"D",location:"Paragraphs E-F"},{id:"stress-q36",number:36,type:"yes-no-not-given",groupTitle:"Questions 36-40",instruction:"Choose YES if the statement agrees with the information in the text, choose NO if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"The tone of the content we post on social media tends to reflect the nature of the posts in our feeds.",correctAnswer:"YES",location:"Paragraph I"},{id:"stress-q37",number:37,type:"yes-no-not-given",text:"Phones have a greater impact on our stress levels than other electronic media devices.",correctAnswer:"NOT GIVEN",location:"Paragraph J"},{id:"stress-q38",number:38,type:"yes-no-not-given",text:"The more we read about a stressful public event on social media, the less able we are to take the information in.",correctAnswer:"NO",location:"Paragraph K"},{id:"stress-q39",number:39,type:"yes-no-not-given",text:"Stress created by social media posts can lead us to take unnecessary precautions.",correctAnswer:"YES",location:"Paragraph K"},{id:"stress-q40",number:40,type:"yes-no-not-given",text:"Our tendency to be affected by other people's moods can be used in a positive way.",correctAnswer:"YES",location:"Paragraph L"}]},we={id:"ielts-reading-full-vol2",title:"IELTS Reading Full Test 2 - Kakapo, Return of the Elm, Stress and Judgement",type:"Academic",module:"Reading",duration:60,totalQuestions:40,sections:[ge,fe,ye]},z=["A","B","C","D","E","F"],be={id:"manatees-p1",title:"Reading Passage 1: Manatees",paragraphs:[{label:"A",content:"Manatees, also known as sea cows, are aquatic mammals that belong to a group of animals called Sirenia. This group also contains dugongs. Dugongs and manatees look quite alike - they are similar in size, colour and shape, and both have flexible flippers for forelimbs. However, the manatee has a broad, rounded tail, whereas the dugong's is fluked, like that of a whale. There are three species of manatees: the West Indian manatee (Trichechus manatus), the African manatee (Trichechus senegalensis) and the Amazonian manatee (Trichechus inunguis)."},{label:"B",content:"Unlike most mammals, manatees have only six bones in their neck - most others, including humans and giraffes, have seven. This short neck allows a manatee to move its head up and down, but not side to side. To see something on its left or its right, a manatee must turn its entire body, steering with its flippers. Manatees have pectoral flippers but no back limbs, only a tail for propulsion. They do have pelvic bones, however - a leftover from their evolution from a four-legged to a fully aquatic animal. Manatees share some visual similarities to elephants. Like elephants, manatees have thick, wrinkled skin. They also have some hairs covering their bodies which help them sense vibrations in the water around them."},{label:"C",content:"Seagrasses and other marine plants make up most of a manatee's diet. Manatees spend about eight hours each day grazing and uprooting plants. They eat up to 15% of their weight in food each day. African manatees are omnivorous - studies have shown that molluscs and fish make up a small part of their diets. West Indian and Amazonian manatees are both herbivores."},{label:"D",content:"Manatees' teeth are all molars - flat, rounded teeth for grinding food. Due to manatees' abrasive aquatic plant diet, these teeth get worn down and they eventually fall out, so they continually grow new teeth that get pushed forward to replace the ones they lose. Instead of having incisors to grasp their food, manatees have lips which function like a pair of hands to help tear food away from the seafloor."},{label:"E",content:"Manatees are fully aquatic, but as mammals, they need to come up to the surface to breathe. When awake, they typically surface every two to four minutes, but they can hold their breath for much longer. Adult manatees sleep underwater for 10-12 hours a day, but they come up for air every 15-20 minutes. Active manatees need to breathe more frequently. It's thought that manatees use their muscular diaphragm and breathing to adjust their buoyancy. They may use diaphragm contractions to compress and store gas in folds in their large intestine to help them float."},{label:"F",content:"The West Indian manatee reaches about 3.5 metres long and weighs on average around 500 kilogrammes. It moves between fresh water and salt water, taking advantage of coastal mangroves and coral reefs, rivers, lakes and inland lagoons. There are two subspecies of West Indian manatee: the Antillean manatee is found in waters from the Bahamas to Brazil, whereas the Florida manatee is found in US waters, although some individuals have been recorded in the Bahamas. In winter, the Florida manatee is typically restricted to Florida. When the ambient water temperature drops below 20 degrees C, it takes refuge in naturally and artificially warmed water, such as at the warm-water outfalls from powerplants."},{label:"G",content:"The African manatee is also about 3.5 metres long and found in the sea along the west coast of Africa, from Mauritania down to Angola. The species also makes use of rivers, with the mammals seen in landlocked countries such as Mali and Niger."},{label:"H",content:"The Amazonian manatee is the smallest species, though it is still a big animal. It grows to about 2.5 metres long and 350 kilogrammes. Amazonian manatees favour calm, shallow waters that are above 23 degrees C. This species is found in fresh water in the Amazon Basin in Brazil, as well as in Colombia, Ecuador and Peru."},{label:"I",content:"All three manatee species are endangered or at a heightened risk of extinction. The African manatee and Amazonian manatee are both listed as Vulnerable by the International Union for Conservation of Nature (IUCN). It is estimated that 140,000 Amazonian manatees were killed between 1935 and 1954 for their meat, fat and skin, with the latter used to make leather. In more recent years, African manatee decline has been tied to incidental capture in fishing nets and hunting. Manatee hunting is now illegal in every country the African species is found in."},{label:"J",content:"The two subspecies of West Indian manatee are listed as Endangered by the IUCN. Both are also expected to undergo a decline of 20% over the next 40 years. A review of almost 1,800 cases of entanglement in fishing nets and of plastic consumption among marine mammals in US waters from 2009 to 2020 found that at least 700 cases involved manatees. The chief cause of death in Florida manatees is boat strikes. However, laws in certain parts of Florida now limit boat speeds during winter, allowing slow-moving manatees more time to respond."}],questions:[{id:"manatees-q1",number:1,type:"note-completion",groupTitle:"Questions 1-6",instruction:"Complete the notes below. Choose ONE WORD AND/OR A NUMBER from the passage for each answer.",text:"look similar to dugongs, but with a differently shaped ______",correctAnswer:"tail",location:"Paragraph A"},{id:"manatees-q2",number:2,type:"note-completion",text:"need to use their ______ to help turn their bodies around in order to look sideways",correctAnswer:"flippers",location:"Paragraph B"},{id:"manatees-q3",number:3,type:"note-completion",text:"sense vibrations in the water by means of ______ on their skin",correctAnswer:"hairs",location:"Paragraph B"},{id:"manatees-q4",number:4,type:"note-completion",text:"eat mainly aquatic vegetation, such as ______",correctAnswer:"seagrasses",location:"Paragraph C"},{id:"manatees-q5",number:5,type:"note-completion",text:"grasp and pull up plants with their ______",correctAnswer:"lips",location:"Paragraph D"},{id:"manatees-q6",number:6,type:"note-completion",text:"may regulate the ______ of their bodies by using muscles of diaphragm to store air internally",correctAnswer:"buoyancy",location:"Paragraph E"},{id:"manatees-q7",number:7,type:"true-false-not-given",groupTitle:"Questions 7-13",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"West Indian manatees can be found in a variety of different aquatic habitats.",correctAnswer:"TRUE",location:"Paragraph F"},{id:"manatees-q8",number:8,type:"true-false-not-given",text:"The Florida manatee lives in warmer waters than the Antillean manatee.",correctAnswer:"NOT GIVEN",location:"Paragraph F"},{id:"manatees-q9",number:9,type:"true-false-not-given",text:"The African manatee's range is limited to coastal waters between the West African countries of Mauritania and Angola.",correctAnswer:"FALSE",location:"Paragraph G"},{id:"manatees-q10",number:10,type:"true-false-not-given",text:"The extent of the loss of Amazonian manatees in the mid-twentieth century was only revealed many years later.",correctAnswer:"NOT GIVEN",location:"Paragraph I"},{id:"manatees-q11",number:11,type:"true-false-not-given",text:"It is predicted that West Indian manatee populations will fall in the coming decades.",correctAnswer:"TRUE",location:"Paragraph J"},{id:"manatees-q12",number:12,type:"true-false-not-given",text:"The risk to manatees from entanglement and plastic consumption increased significantly in the period 2009-2020.",correctAnswer:"NOT GIVEN",location:"Paragraph J"},{id:"manatees-q13",number:13,type:"true-false-not-given",text:"There is some legislation in place which aims to reduce the likelihood of boat strikes on manatees in Florida.",correctAnswer:"TRUE",location:"Paragraph J"}]},ve={id:"procrastination-p2",title:"Reading Passage 2: Procrastination",paragraphs:[{label:"A",content:"Procrastination is the habit of delaying a necessary task, usually by focusing on less urgent, more enjoyable, and easier activities instead. We all do it from time to time. We might be composing a message to a friend who we have to let down, or putting together an important report for college or work; we're doing our best to avoid doing the job at hand, but deep down we know that we should just be getting on with it. Unfortunately, berating ourselves won't stop us procrastinating again. In fact, it's one of the worst things we can do. This matters because, as my research shows, procrastination doesn't just waste time, but is actually linked to other problems, too."},{label:"B",content:"Contrary to popular belief, procrastination is not due to laziness or poor time management. Scientific studies suggest procrastination is, in fact, caused by poor mood management. This makes sense if we consider that people are more likely to put off starting or completing tasks that they are really not keen to do. If just thinking about the task threatens our sense of self-worth or makes us anxious, we will be more likely to put it off. Research involving brain imaging has found that areas of the brain linked to detection of threats and emotion regulation are actually different in people who chronically procrastinate compared to those who don't procrastinate frequently."},{label:"C",content:"Tasks that are emotionally loaded or difficult, such as preparing for exams, are prime candidates for procrastination. People with low self-esteem are more likely to procrastinate. Another group of people who tend to procrastinate are perfectionists, who worry their work will be judged harshly by others. We know that if we don't finish that report or complete those home repairs, then what we did can't be evaluated. When we avoid such tasks, we also avoid the negative emotions associated with them. This is rewarding, and it conditions us to use procrastination to repair our mood. If we engage in more enjoyable tasks instead, we get another mood boost. In the long run, however, procrastination isn't an effective way of managing emotions. The mood repair we experience is temporary. Afterwards, people tend to be left with a sense of guilt that not only increases their negative mood, but also reinforces their tendency to procrastinate."},{label:"D",content:"So why is this such a problem? When most people think of the costs of procrastination, they think of the toll on productivity. For example, studies have shown that procrastination negatively impacts on student performance. But putting off reading textbooks and writing essays may affect other areas of students' lives. In one study of over 3,000 German students over a six-month period, those who reported procrastinating over their university work were also more likely to engage in study-related misconduct, such as cheating and plagiarism. But the behaviour that procrastination was most closely linked with was using fraudulent excuses to get deadline extensions. Other research shows that employees on average spend almost a quarter of their workday procrastinating, and again this is linked with negative outcomes. In fact, in one US survey of over 22,000 employees, participants who said they regularly procrastinated had less annual income and less employment stability. For every one-point increase on a measure of chronic procrastination, annual income decreased by US$15,000."},{label:"E",content:"Procrastination also correlates with serious health and well-being problems. A tendency to procrastinate is linked to poor mental health, including higher levels of depression and anxiety. Across numerous studies, I've found people who regularly procrastinate report a greater number of health issues, such as headaches, flu and colds, and digestive issues. They also experience higher levels of stress and poor sleep quality. They are less likely to practise healthy behaviours, such as eating a healthy diet and regularly exercising, and use destructive coping strategies to manage their stress. In one study of over 700 people, I found people prone to procrastination had a 63% greater risk of poor heart health after accounting for other personality traits and demographics."},{label:"F",content:"Finding better ways of managing our emotions is one route out of the vicious cycle of procrastination. An important first step is to manage our environment and how we view the task. There are a number of evidence-based strategies that can help us fend off distractions that can occupy our minds when we should be focusing on the thing we should be getting on with. For example, reminding ourselves about why the task is important and valuable can increase positive feelings towards it. Forgiving ourselves and feeling compassion when we procrastinate can help break the procrastination cycle. We should admit that we feel bad, but not be overly critical of ourselves. We should remind ourselves that we're not the first person to procrastinate, nor the last. Doing this can take the edge off the negative feelings we have about ourselves when we procrastinate. This can all make it easier to get back on track."}],questions:[{id:"procrastination-q14",number:14,type:"matching-information",groupTitle:"Questions 14-16",instruction:"Reading Passage 2 has six paragraphs. Which paragraph contains the following information?",text:"mention of false assumptions about why people procrastinate",options:z,correctAnswer:"B",location:"Paragraph B"},{id:"procrastination-q15",number:15,type:"matching-information",text:"reference to the realisation that others also procrastinate",options:z,correctAnswer:"F",location:"Paragraph F"},{id:"procrastination-q16",number:16,type:"matching-information",text:"neurological evidence of a link between procrastination and emotion",options:z,correctAnswer:"B",location:"Paragraph B"},{id:"procrastination-q17",number:17,type:"summary-completion",groupTitle:"Questions 17-22",instruction:"Complete the summary below. Choose ONE WORD ONLY from the passage for each answer.",text:"Many people think that procrastination is the result of ______.",correctAnswer:"laziness",location:"Paragraph B"},{id:"procrastination-q18",number:18,type:"summary-completion",text:"The tasks we are most likely to put off are those that could damage our self-esteem or cause us to feel ______ when we think about them.",correctAnswer:"anxious",location:"Paragraph B"},{id:"procrastination-q19",number:19,type:"summary-completion",text:"Research comparing chronic procrastinators with other people even found differences in the brain regions associated with regulating emotions and identifying ______.",correctAnswer:"threats",location:"Paragraph B"},{id:"procrastination-q20",number:20,type:"summary-completion",text:"Getting ready to take ______ might be a typical example of one such task.",correctAnswer:"exams",location:"Paragraph C"},{id:"procrastination-q21",number:21,type:"summary-completion",text:"People who are likely to procrastinate tend to be either ______ or those with low self-esteem.",correctAnswer:"perfectionists",location:"Paragraph C"},{id:"procrastination-q22",number:22,type:"summary-completion",text:"Procrastination is only a short-term measure for managing emotions. It's often followed by a feeling of ______, which worsens our mood and leads to more procrastination.",correctAnswer:"guilt",location:"Paragraph C"},{id:"procrastination-q23",number:23,type:"five-true-statements",groupTitle:"Questions 23-24",instruction:"Choose TWO correct answers. Which TWO comparisons between employees who often procrastinate and those who do not are mentioned in the text?",text:"Select TWO options.",options:["A. Their salaries are lower.","B. The quality of their work is inferior.","C. They don't keep their jobs for as long.","D. They don't enjoy their working lives as much.","E. They have poorer relationships with colleagues."],correctAnswer:["A","C"],location:"Paragraph D"},{id:"procrastination-q25",number:25,type:"five-true-statements",groupTitle:"Questions 25-26",instruction:"Choose TWO correct answers. Which TWO recommendations for getting out of a cycle of procrastination does the writer give?",text:"Select TWO options.",options:["A. not judging ourselves harshly","B. setting ourselves manageable aims","C. rewarding ourselves for tasks achieved","D. prioritising tasks according to their importance","E. avoiding things that stop us concentrating on our tasks"],correctAnswer:["A","E"],location:"Paragraph F"}]},Ae={id:"robot-umpires-p3",title:"Reading Passage 3: Invasion of the Robot Umpires",paragraphs:[{label:"A",content:"A few years ago, Fred DeJesus from Brooklyn, New York became the first umpire in a minor league baseball game to use something called the Automated Ball-Strike System (ABS), often referred to as the robo-umpire. Instead of making any judgments himself about a strike, DeJesus had decisions fed to him through an earpiece, connected to a modified missile-tracking system. The contraption looked like a large black pizza box with one glowing green eye; it was mounted above the press stand."},{label:"B",content:"Major League Baseball (MLB), who had commissioned the system, wanted human umpires to announce the calls, just as they would have done in the past. When the first pitch came in, a recorded voice told DeJesus it was a strike. Previously, calling a strike was a judgment call on the part of the umpire. Even if the batter does not hit the ball, a pitch that passes through the strike zone (an imaginary zone about seventeen inches wide, stretching from the batter's knees to the middle of his chest) is considered a strike. During that first game, when DeJesus announced calls, there was no heckling and no shouted disagreement. Nobody said a word."},{label:"C",content:"For a hundred and fifty years or so, the strike zone has been the game's animating force - countless arguments between a team's manager and the umpire have taken place over its boundaries and whether a ball had crossed through it. The rules of play have evolved in various stages. Today, everyone knows that you may scream your disagreement in an umpire's face, but you must never shout personal abuse at them or touch them. That's a no-no. When the robo-umpires came, however, the arguments stopped."},{label:"D",content:`During the first robo-umpire season, players complained about some strange calls. In response, MLB decided to tweak the dimensions of the zone, and the following year the consensus was that ABS is profoundly consistent. MLB says the device is near-perfect, precise to within fractions of an inch. "It'll reduce controversy in the game, and be good for the game," says Rob Manfred, who is Commissioner for MLB. But the question is whether controversy is worth reducing, or whether it is the sign of a human hand.`},{label:"E",content:`A human, at least, yells back. When I spoke with Frank Viola, a coach for a North Carolina team, he said that ABS works as designed, but that it was also unforgiving and pedantic, almost legalistic. "Manfred is a lawyer," Viola noted. Some pitchers have complained that, compared with a human's, the robot's strike zone seems too precise. Viola was once a major-league player himself. When he was pitching, he explained, umpires rewarded skill. "Throw it where you aimed, and it would be a strike, even if it was an inch or two outside. There was a dialogue between pitcher and umpire."`},{label:"F",content:"The executive tasked with running the experiment for MLB is Morgan Sword, who's in charge of baseball operations. According to Sword, ABS was part of a larger project to make baseball more exciting since executives are terrified of losing younger fans, as has been the case with horse racing and boxing. He explains how they began the process by asking fans what version of baseball they found most exciting. The results showed that everyone wanted more action: more hits, more defense, more baserunning. This type of baseball essentially hasn't existed since the 1960s, when the hundred-mile-an-hour fastball, which is difficult to hit and control, entered the game. It flattened the game into strikeouts, walks, and home runs - a type of play lacking much action."},{label:"G",content:`Sword's team brainstormed potential fixes. Any rule that existed, they talked about changing - from changing the bats to changing the geometry of the field. But while all of these were ruled out as potential fixes, ABS was seen as a perfect vehicle for change. According to Sword, once you get the technology right, you can load any strike zone you want into the system. "It might be a triangle, or a blob, or something shaped like Texas. Over time, as baseball evolves, ABS can allow the zone to change with it."`},{label:"H",content:"In the past twenty years, sports have moved away from judgment calls. Soccer has Video Assistant Referees (for offside decisions, for example). Tennis has Hawk-Eye (for line calls, for example). For almost a decade, baseball has used instant replay on the base paths. This is widely liked, even if the precision can sometimes cause problems. But these applications deal with something physical: bases, lines, goals. The boundaries of action are precise, delineated like the keys of a piano. This is not the case with ABS and the strike zone. Historically, a certain discretion has been appreciated."},{label:"I",content:`I decided to email Alva Noe, a professor at Berkeley University and a baseball fan, for his opinion. "Hardly a day goes by that I don't wake up and run through the reasons that this [robo-umpires] is such a terrible idea," he replied. He later told me, "This is part of a movement to use algorithms to take the hard choices of living out of life." Perhaps he's right. We watch baseball to kill time, not to maximize it.`},{label:"J",content:`Some players I have met take a dissenting stance toward the robots too, believing that accuracy is not the answer. According to Joe Russo, who plays for a New Jersey team, "With technology, people just want everything to be perfect. That's not reality. I think perfect would be weird. Your teams are always winning, work is always just great, there's always money in your pocket, your car never breaks down. What is there to talk about?"`}],questions:[{id:"robot-q27",number:27,type:"yes-no-not-given",groupTitle:"Questions 27-32",instruction:"Choose YES if the statement agrees with the information given in the text, choose NO if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"When DeJesus first used ABS, he shared decision-making about strikes with it.",correctAnswer:"NO",location:"Paragraph A"},{id:"robot-q28",number:28,type:"yes-no-not-given",text:"MLB considered it necessary to amend the size of the strike zone when criticisms were received from players.",correctAnswer:"YES",location:"Paragraph D"},{id:"robot-q29",number:29,type:"yes-no-not-given",text:"MLB is keen to justify the money spent on improving the accuracy of ABS's calculations.",correctAnswer:"NOT GIVEN",location:"Paragraphs D-F"},{id:"robot-q30",number:30,type:"yes-no-not-given",text:"The hundred-mile-an-hour fastball led to a more exciting style of play.",correctAnswer:"NO",location:"Paragraph F"},{id:"robot-q31",number:31,type:"yes-no-not-given",text:"The differing proposals for alterations to the baseball bat led to fierce debate on Sword's team.",correctAnswer:"NOT GIVEN",location:"Paragraph G"},{id:"robot-q32",number:32,type:"yes-no-not-given",text:"ABS makes changes to the shape of the strike zone feasible.",correctAnswer:"YES",location:"Paragraph G"},{id:"robot-q33",number:33,type:"drag-drop-summary",groupTitle:"Questions 33-37",instruction:"Complete the summary by dragging the correct words into the gaps.",text:`Even after ABS was developed, MLB still wanted human umpires to shout out decisions as they had in their previous model.
The umpire's job had, at one time, required a personal decision about whether a ball was a strike.
A ball is considered a strike when the batter does not hit it and it crosses through a zone extending approximately from the batter's knee to his chest.
In the past, arguments over strike calls were not uncommon, but today everyone accepts the complete ban on pushing or shoving the umpire.
One difference, however, is that during the first game DeJesus used ABS, strike calls were met with no reaction.`,options:["pitch boundary","numerous disputes","team tactics","subjective assessment","widespread approval","former roles","total silence","perceived area"],correctAnswer:["former roles","subjective assessment","perceived area","numerous disputes","total silence"],location:"Paragraphs B-C"},{id:"robot-q38",number:38,type:"multiple-choice",groupTitle:"Question 38",instruction:"Choose the correct answer. What does the writer suggest about ABS in the fifth paragraph?",text:"Select one option.",options:["It is bound to make key decisions that are wrong.","It may reduce some of the appeal of the game.","It will lead to the disappearance of human umpires.","It may increase calls for the rules of baseball to be changed."],correctAnswer:"B",location:"Paragraph E"},{id:"robot-q39",number:39,type:"multiple-choice",groupTitle:"Question 39",instruction:"Choose the correct answer. Morgan Sword says that the introduction of ABS",text:"Select one option.",options:["was regarded as an experiment without a guaranteed outcome.","was intended to keep up with developments in other sports.","was a response to changing attitudes about the role of sport.","was an attempt to ensure baseball retained a young audience."],correctAnswer:"D",location:"Paragraph F"},{id:"robot-q40",number:40,type:"multiple-choice",groupTitle:"Question 40",instruction:"Choose the correct answer. Why does the writer include the views of Noe and Russo?",text:"Select one option.",options:["to show that attitudes to technology vary widely","to argue that people have unrealistic expectations of sport","to indicate that accuracy is not the same thing as enjoyment","to suggest that the number of baseball fans needs to increase"],correctAnswer:"C",location:"Paragraphs I-J"}]},ke={id:"ielts-reading-full-vol3",title:"IELTS Reading Full Test 3 - Manatees, Procrastination, Invasion of the Robot Umpires",type:"Academic",module:"Reading",duration:60,sections:[be,ve,Ae],totalQuestions:40},k=["A","B","C","D","E","F","G"],S=["A. Yanira Pineda","B. Susanna Tol","C. Elizabeth English","D. Raisa Chowdhury","E. Greg Spotts"],_=["A. Dan Macon","B. Silvia Ribeiro","C. Linda van Bommel","D. Julie Young","E. Bethany Smith"];function K(e){return{...e,options:e.options?[...e.options]:void 0,correctAnswer:Array.isArray(e.correctAnswer)?[...e.correctAnswer]:e.correctAnswer}}function oe(e){return{...e,paragraphs:e.paragraphs?e.paragraphs.map(t=>({...t})):void 0,questions:e.questions.map(K)}}const $=oe(w.sections[0]),_e={...$,id:"georgia-okeeffe-p1-v6",title:"Reading Passage 1: Georgia O'Keeffe",questions:$.questions.map(e=>({...K(e),id:`gok-v6-q${e.number}`}))},ne=oe(w.sections[1]),xe=ne.questions.filter(e=>e.number<=22).map(e=>({...K(e),id:`cca-v6-q${e.number}`})),Te=[{id:"cca-v6-q23",number:23,type:"matching-information",groupTitle:"Questions 23-26",instruction:"Look at the following statements and the list of people below. Match each statement with the correct person.",text:"It is essential to adopt strategies which involve and help residents of the region.",options:S,correctAnswer:"B",location:"Paragraph C"},{id:"cca-v6-q24",number:24,type:"matching-information",text:"Interventions which reduce heat are absolutely vital for our survival in this location.",options:S,correctAnswer:"E",location:"Paragraph F"},{id:"cca-v6-q25",number:25,type:"matching-information",text:"More work will need to be done in future decades to deal with the impact of rising water levels.",options:S,correctAnswer:"A",location:"Paragraph B"},{id:"cca-v6-q26",number:26,type:"matching-information",text:"The number of locations requiring action to adapt to flooding has grown in recent years.",options:S,correctAnswer:"C",location:"Paragraph D"}],Pe={...ne,id:"climate-adaptation-p2-v6",title:"Reading Passage 2: Adapting to the effects of climate change",questions:[...xe,...Te]},qe={id:"guard-dogs-p3-v6",title:"Reading Passage 3: A new role for livestock guard dogs",paragraphs:[{label:"A",content:"For thousands of years, livestock guard dogs worked alongside shepherds to protect their sheep, goats and cattle from predators such as wolves and bears. But in the 19th and 20th centuries, when such predators were largely exterminated, most guard dogs lost their jobs. In recent years, however, as increased efforts have been made to protect wild animals, predators have become more widespread again. As a result, farmers once more need to protect their livestock, and guard dogs are enjoying an unexpected revival."},{label:"B",content:"Today there are around 50 breeds of guard dogs on duty in various parts of the world. These dogs are raised from an early age with the animals they will be watching and eventually these animals become the dog's family. The dogs will place themselves between the livestock and any threat, barking loudly. If necessary, they will chase away predators, but often their mere presence is sufficient. 'Their initial training is to make them understand that livestock is going to be their life,' says Dan Macon, a shepherd with three guard dogs. 'A fluffy white puppy is fun to be around, but too much human affection makes it a great dog for guarding the front porch, rather than a great livestock guard dog.'"},{label:"C",content:"The evidence indicates that guard dogs are highly effective. For example, in Portugal, biologist Silvia Ribeiro has found that more than 90 per cent of the farmers participating in a programme to train and use guard dogs to protect their herds against attack from wolves rate the performance of the dogs as very good or excellent. In a study carried out in Australia by Linda van Bommel and Chris Johnson at the University of Tasmania, more than 65 per cent of herders reported that predation stopped completely after they got the dogs, and almost all the rest saw a decrease in attacks. 'If they are managed and used properly, livestock guard dogs are the most efficient control method that we have in terms of the amount of livestock that they save from predation,' says van Bommel."},{label:"D",content:"But today's guard dogs also have a new role - to help preserve the predators. It is hoped that reductions in livestock losses can make farmers more tolerant of predators and less likely to kill them. In Namibia, more than 90 per cent of cheetahs live outside protected areas, close to humans raising livestock. As a result, the cheetahs are often held responsible for animal losses, and large numbers have been killed by farmers. When guard dogs were introduced, more than 90 per cent of farmers reported a dramatic reduction in livestock losses, and said that as a result they were less likely to kill predators. Julie Young, at Utah State University in the US, believes this result applies widely. 'There is common ground from the livestock perspective and from the conservation perspective,' she says. 'If ranchers don't have a dead cow, they will not make a call to apply for a permit to kill a wolf.'"},{label:"E",content:"Looking at all the published evidence, Bethany Smith at Nottingham Trent University in the UK found that up to 88 per cent of farmers said they no longer killed predators after using dogs - but warned that such self-reported results must be taken with a pinch of salt. What's more, it is possible that livestock guard dogs merely displace predators to unprotected neighbouring properties, where their fate isn't recorded. 'In some regions, we work with almost every farmer, but in others only one or two have dogs,' says Ribeiro. 'If we are not working with everybody, we are transferring the wolf pressure to the neighbour's herd and he can use poison and kill an entire pack of wolves.'"},{label:"F",content:"Another concern is whether there may be unintended ecological effects of using guard dogs. Studies suggest that reducing deaths of one type of predator may have a negative impact on other species. The extent of this problem isn't known, but the consequences are clear in Namibia. Cheetahs aren't the only species that cause sheep and goat losses there: other predators also attack livestock. In 2015, researchers reported that in spite of the impact farmers obtaining guard dogs had on cheetahs, the number of jackals killed by dogs and people actually increased. Guard dogs have other ecological impacts too. They have been found to spread diseases to wild animals, including endangered Ethiopian wolves. They may also compete with other carnivores for food. And by creating a 'landscape of fear', their mere presence can influence the behaviour of prey animals."},{label:"G",content:"The evidence so far, however, indicates that these consequences aren't always negative. Guard dogs can deliver unexpected benefits by protecting vulnerable wildlife from predators. For example, their presence has been found to protect birds which build their nests on the ground in fields, where foxes would normally raid them. Indeed, Australian researchers are now using dogs to enhance biodiversity and create refuges for species threatened by predation. So if we can get this right, there may be a bright future for guard dogs in promoting harmonious coexistence between humans and wildlife."}],questions:[{id:"guard-v6-q27",number:27,type:"matching-information",groupTitle:"Questions 27-31",instruction:"Reading Passage 3 has seven paragraphs. Which paragraph contains the following information?",text:"an example of how one predator has been protected by the introduction of livestock guard dogs",options:k,correctAnswer:"D",location:"Paragraph D"},{id:"guard-v6-q28",number:28,type:"matching-information",text:"an optimistic suggestion about the possible positive developments in the use of livestock guard dogs",options:k,correctAnswer:"G",location:"Paragraph G"},{id:"guard-v6-q29",number:29,type:"matching-information",text:"a description of how the methods used by livestock guard dogs help to keep predators away",options:k,correctAnswer:"B",location:"Paragraph B"},{id:"guard-v6-q30",number:30,type:"matching-information",text:"claims by different academics that the use of livestock guard dogs is a successful way of protecting farmers' herds",options:k,correctAnswer:"C",location:"Paragraph C"},{id:"guard-v6-q31",number:31,type:"matching-information",text:"a reference to how livestock guard dogs gain their skills",options:k,correctAnswer:"B",location:"Paragraph B"},{id:"guard-v6-q32",number:32,type:"matching-information",groupTitle:"Questions 32-36",instruction:"Look at the following statements and the list of people below. Match each statement with the correct person.",text:"The use of guard dogs may save the lives of both livestock and wild animals.",options:_,correctAnswer:"D",location:"Paragraph D"},{id:"guard-v6-q33",number:33,type:"matching-information",text:"Claims of a change in behaviour from those using livestock guard dogs may not be totally accurate.",options:_,correctAnswer:"E",location:"Paragraph E"},{id:"guard-v6-q34",number:34,type:"matching-information",text:"There may be negative results if the use of livestock guard dogs is not sufficiently widespread.",options:_,correctAnswer:"B",location:"Paragraph E"},{id:"guard-v6-q35",number:35,type:"matching-information",text:"Livestock guard dogs are the best way of protecting farm animals, as long as the dogs are appropriately handled.",options:_,correctAnswer:"C",location:"Paragraph C"},{id:"guard-v6-q36",number:36,type:"matching-information",text:"Teaching a livestock guard dog how to do its work needs a different focus from teaching a house guard dog.",options:_,correctAnswer:"A",location:"Paragraph B"},{id:"guard-v6-q37",number:37,type:"summary-completion",groupTitle:"Questions 37-40",instruction:"Complete the summary below. Choose ONE WORD ONLY from the passage for each answer.",text:"In Namibia, livestock guard dogs have been used to protect domestic animals from attacks by cheetahs. This has led to a rise in the deaths of other predators, particularly ______.",correctAnswer:"jackals",location:"Paragraph F"},{id:"guard-v6-q38",number:38,type:"summary-completion",text:"In addition, it has been suggested that dogs could spread ______ which may affect other species.",correctAnswer:"diseases",location:"Paragraph F"},{id:"guard-v6-q39",number:39,type:"summary-completion",text:"Guard dogs may also reduce the amount of ______ available to certain wild animals.",correctAnswer:"food",location:"Paragraph F"},{id:"guard-v6-q40",number:40,type:"summary-completion",text:"Ground-nesting birds might otherwise be threatened by predators such as ______.",correctAnswer:"foxes",location:"Paragraph G"}]},Y={id:"ielts-reading-full-vol6",title:"IELTS Reading Full Test 6 - Georgia O'Keeffe, Climate Change Adaptation, Guard Dogs",type:"Academic",module:"Reading",duration:60,totalQuestions:40,sections:[_e,Pe,qe]};function Ce(e){return{...e,options:e.options?[...e.options]:void 0,correctAnswer:Array.isArray(e.correctAnswer)?[...e.correctAnswer]:e.correctAnswer}}function Ie(e){return{...e,paragraphs:e.paragraphs?e.paragraphs.map(t=>({...t})):void 0,questions:e.questions.map(Ce)}}function Ee(e){return e.endsWith("-v6")?e.replace("-v6","-v4"):`${e}-v4`}function Se(e){return e.includes("-v6-")?e.replace("-v6-","-v4-"):e.endsWith("-v6")?e.replace("-v6","-v4"):`${e}-v4`}const Be={...Y,id:"ielts-reading-full-vol4",title:"IELTS Reading Full Test 4 - Georgia O'Keeffe, Climate Change Adaptation, Guard Dogs",sections:Y.sections.map(e=>{const t=Ie(e);return{...t,id:Ee(t.id),questions:t.questions.map(o=>({...o,id:Se(o.id)}))}})},d=["A. Tried and tested solutions","B. Cooperation beneath the waves","C. Working to lessen the problems","D. Disagreement about the accuracy of a certain phrase","E. Two clear educational goals","F. Promoting hope","G. A warning of further trouble ahead"],s=["A. Martin Rees","B. Daniel Wolpert","C. Kathleen Richardson"],U=["A. robots to explore outer space.","B. advances made in machine intelligence so far.","C. changes made to other planets for our own benefit.","D. the harm already done by artificial intelligence."],De={id:"frozen-food-p1-v5",title:"Reading Passage 1: Frozen Food",paragraphs:[{label:"A",content:"At some point in history, humans discovered that ice preserved food. There is evidence that winter ice was stored to preserve food in the summer as far back as 10,000 years ago. Two thousand years ago, the inhabitants of South America's Andean mountains had a unique means of conserving potatoes for later consumption. They froze them overnight, then trampled them to squeeze out the moisture, then dried them in the sun. This preserved their nutritional value - if not their aesthetic appeal."},{label:"B",content:"Natural ice remained the main form of refrigeration until late in the 19th century. In the early 1800s, ship owners from Boston, USA, had enormous blocks of Arctic ice towed all over the Atlantic for the purpose of food preservation. In 1851, railroads first began putting blocks of ice in insulated rail cars to send butter from Ogdensburg, New York, to Boston."},{label:"C",content:'Finally, in 1870, Australian inventors found a way to make "mechanical ice". They used a compressor to force a gas - ammonia at first and later Freon - through a condenser. The compressed gas gave up some of its heat as it moved through the condenser. Then the gas was released quickly into a low-pressure evaporator coil where it became liquid and cold. Air was blown over the evaporator coil and then this cooled air passed into an insulated compartment, lowering its temperature to freezing point.'},{label:"D",content:"Initially, this process was invented to keep Australian beer cool even in hot weather. But Australian cattlemen were quick to realize that, if they could put this new invention on a ship, they could export meat across the oceans. In 1880, a shipment of Australian beef and mutton was sent, frozen, to England. While the food frozen this way was still palatable, there was some deterioration. During the freezing process, crystals formed within the cells of the food, and when the ice expanded and the cells burst, this spoilt the flavor and texture of the food."},{label:"E",content:"The modern frozen food industry began with the indigenous Inuit people of Canada. In 1912, a biology student in Massachusetts, USA, named Clarence Birdseye, ran out of money and went to Labrador in Canada to trap and trade furs. While he was there, he became fascinated with how the Inuit would quickly freeze fish in the Arctic air. The fish looked and tasted fresh even months later."},{label:"F",content:"Birdseye returned to the USA in 1917 and began developing mechanical freezers capable of quick-freezing food. Birdseye methodically kept inventing better freezers and gradually built a business selling frozen fish from Gloucester, Massachusetts. In 1929, his business was sold and became General Foods, but he stayed with the company as director of research, and his division continued to innovate."},{label:"G",content:"Birdseye was responsible for several key innovations that made the frozen food industry possible. He developed quick-freezing techniques that reduced the damage that crystals caused, as well as the technique of freezing the product in the package it was to be sold in. He also introduced the use of cellophane, the first transparent material for food packaging, which allowed consumers to see the quality of the product. Birdseye products also came in convenient size packages that could be prepared with a minimum of effort."},{label:"H",content:"But there were still obstacles. In the 1930s, few grocery stores could afford to buy freezers for a market that wasn't established yet. So, Birdseye leased inexpensive freezer cases to them. He also leased insulated railroad cars so that he could ship his products nationwide. However, few consumers had freezers large enough or efficient enough to take advantage of the products."},{label:"I",content:"Sales increased in the early 1940s, when World War II gave a boost to the frozen food industry because tin was being used for munitions. Canned foods were rationed to save tin for the war effort, while frozen foods were abundant and cheap. Finally, by the 1950s, refrigerator technology had developed far enough to make these appliances affordable for the average family. By 1953, 33 million US families owned a refrigerator, and manufacturers were gradually increasing the size of the freezer compartments in them."},{label:"J",content:`1950s families were also looking for convenience at mealtimes, so the moment was right for the arrival of the "TV Dinner". Swanson Foods was a large, nationally recognized producer of canned and frozen poultry. In 1954, the company adapted some of Birdseye's freezing techniques, and with the help of a clever name and a huge advertising budget, it launched the first "TV Dinner". This consisted of frozen turkey, potatoes and vegetables served in the same segmented aluminum tray that was used by airlines. The product was an instant success. Within a year, Swanson had sold 13 million TV dinners. American consumers couldn't resist the combination of a trusted brand name, a single-serving package and the convenience of a meal that could be ready after only 25 minutes in a hot oven. By 1959, Americans were spending $2.7 billion annually on frozen foods, and half a billion of that was spent on ready-prepared meals such as the TV Dinner.`},{label:"K",content:"Today, the US frozen food industry has a turnover of over $67 billion annually, with $26.6 billion of that sold to consumers for home consumption. The remaining $40 billion in frozen food sales come through restaurants, cafeterias, hospitals and schools, and that represents a third of the total food service sales."}],questions:[{id:"frozen-q1",number:1,type:"note-completion",groupTitle:"Questions 1-7",instruction:"Complete the notes below. Choose ONE WORD ONLY from the passage for each answer.",text:"People conserved the nutritional value of ______, using a method of freezing then drying.",correctAnswer:"potatoes",location:"Paragraph A"},{id:"frozen-q2",number:2,type:"note-completion",text:"______ was kept cool by ice during transportation in specially adapted trains.",correctAnswer:"butter",location:"Paragraph B"},{id:"frozen-q3",number:3,type:"note-completion",text:"Two kinds of ______ were the first frozen foods shipped to England.",correctAnswer:"meat",location:"Paragraph D"},{id:"frozen-q4",number:4,type:"note-completion",text:"Quick-freezing methods, so that ______ did not spoil the food.",correctAnswer:"crystals",location:"Paragraph G"},{id:"frozen-q5",number:5,type:"note-completion",text:"Packaging products with ______, so the product was visible.",correctAnswer:"cellophane",location:"Paragraph G"},{id:"frozen-q6",number:6,type:"note-completion",text:"Frozen food became popular because of a shortage of ______.",correctAnswer:"tin",location:"Paragraph I"},{id:"frozen-q7",number:7,type:"note-completion",text:"A large number of homes now had a ______.",correctAnswer:"refrigerator",location:"Paragraph I"},{id:"frozen-q8",number:8,type:"true-false-not-given",groupTitle:"Questions 8-13",instruction:"Choose TRUE if the statement agrees with the information given in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"The ice transportation business made some Boston ship owners very wealthy in the early 1800s.",correctAnswer:"NOT GIVEN",location:"Paragraph B"},{id:"frozen-q9",number:9,type:"true-false-not-given",text:"A disadvantage of the freezing process invented in Australia was that it affected the taste of food.",correctAnswer:"TRUE",location:"Paragraph D"},{id:"frozen-q10",number:10,type:"true-false-not-given",text:"Clarence Birdseye travelled to Labrador in order to learn how the Inuit people froze fish.",correctAnswer:"FALSE",location:"Paragraph E"},{id:"frozen-q11",number:11,type:"true-false-not-given",text:"Swanson Foods invested a great deal of money in the promotion of the TV Dinner.",correctAnswer:"TRUE",location:"Paragraph J"},{id:"frozen-q12",number:12,type:"true-false-not-given",text:"Swanson Foods developed a new style of container for the launch of the TV Dinner.",correctAnswer:"FALSE",location:"Paragraph J"},{id:"frozen-q13",number:13,type:"true-false-not-given",text:"The US frozen food industry is currently the largest in the world.",correctAnswer:"NOT GIVEN",location:"Paragraph K"}]},Oe={id:"coral-reefs-p2-v5",title:"Reading Passage 2: Can the planet's coral reefs be saved?",paragraphs:[{label:"A",content:`Conservationists have put the final touches to a giant artificial reef they have been assembling at the world-renowned Zoological Society of London (London Zoo). Samples of the planet's most spectacular corals - vivid green branching coral, yellow scroll, blue ridge and many more species - have been added to the giant tank along with fish that thrive in their presence: blue tang, clownfish and many others. The reef is in the zoo's new gallery, Tiny Giants, which is dedicated to the minuscule invertebrate creatures that sustain life across the planet. The coral reef tank and its seven-metre-wide window form the core of the exhibition.

"Coral reefs are the most diverse ecosystems on Earth and we want to show people how wonderful they are," said Paul Pearce-Kelly, senior curator of invertebrates and fish at the Zoological Society of London. "However, we also want to highlight the research and conservation efforts that are now being carried out to try to save them from the threat of global warming." They want people to see what is being done to try to save these wonders.`},{label:"B",content:"Corals are composed of tiny animals, known as polyps, with tentacles for capturing small marine creatures in the sea water. These polyps are transparent but get their brilliant tones of pink, orange, blue, green, etc. from algae that live within them, which in turn get protection, while their photosynthesising of the sun's rays provides nutrients for the polyps. This comfortable symbiotic relationship has led to the growth of coral reefs that cover 0.1% of the planet's ocean bed while providing homes for more than 25% of marine species, including fish, molluscs, sponges and shellfish."},{label:"C",content:'As a result, coral reefs are often described as the "rainforests of the sea", though the comparison is dismissed by some naturalists, including David Attenborough. "People say you cannot beat the rainforest," Attenborough has stated. "But that is simply not true. You go there and the first thing you think is: where are the birds? Where are the animals? They are hiding in the trees, of course. No, if you want beauty and wildlife, you want a coral reef. Put on a mask and stick your head under the water. The sight is mind-blowing."'},{label:"D",content:`Unfortunately, these majestic sights are now under very serious threat, with the most immediate problem coming in the form of thermal stress. Rising ocean temperatures are triggering bleaching events that strip reefs of their colour and eventually kill them. And that is just the start. Other menaces include ocean acidification, sea level increase, pollution by humans, deoxygenation and ocean current changes, while the climate crisis is also increasing habitat destruction. As a result, vast areas - including massive chunks of Australia's Great Barrier Reef - have already been destroyed, and scientists advise that more than 90% of reefs could be lost by 2050 unless urgent action is taken to tackle global heating and greenhouse gas emissions.

Pearce-Kelly says that coral reefs have to survive really harsh conditions - wave erosion and other factors. And "when things start to go wrong in the oceans, then corals will be the first to react. And that is exactly what we are seeing now. Coral reefs are dying and they are telling us that all is not well with our planet."`},{label:"E",content:'However, scientists are trying to pinpoint hardy types of coral that could survive our overheated oceans, and some of this research will be carried out at London Zoo. "Behind our coral reef tank we have built laboratories where scientists will be studying coral species," said Pearce-Kelly. "One aim will be to carry out research on species to find those that can survive best in warm, acidic waters. Another will be to try to increase coral breeding rates. "Coral spawn just once a year," he added. "However, aquarium-based research has enabled some corals to spawn artificially, which can assist coral reef restoration efforts. And if this can be extended for all species, we could consider the launching of coral-spawning programmes several times a year. That would be a big help in restoring blighted reefs."'},{label:"F",content:`Research in these fields is being conducted in laboratories around the world, with the London Zoo centre linked to this global network. Studies carried out in one centre can then be tested in others. The resulting young coral can then be displayed in the tank in Tiny Giants. "The crucial point is that the progress we make in making coral better able to survive in a warming world can be shown to the public and encourage them to believe that we can do something to save the planet's reefs," said Pearce-Kelly. "Saving our coral reefs is now a critically important ecological goal."`}],questions:[{id:"coral-q14",number:14,type:"matching-headings",groupTitle:"Questions 14-19",instruction:"Reading Passage 2 has six sections. Choose the correct heading for each section from the list of headings below.",text:"Section 14",options:d,correctAnswer:"E",location:"Section 14"},{id:"coral-q15",number:15,type:"matching-headings",text:"Section 15",options:d,correctAnswer:"B",location:"Section 15"},{id:"coral-q16",number:16,type:"matching-headings",text:"Section 16",options:d,correctAnswer:"D",location:"Section 16"},{id:"coral-q17",number:17,type:"matching-headings",text:"Section 17",options:d,correctAnswer:"G",location:"Section 17"},{id:"coral-q18",number:18,type:"matching-headings",text:"Section 18",options:d,correctAnswer:"C",location:"Section 18"},{id:"coral-q19",number:19,type:"matching-headings",text:"Section 19",options:d,correctAnswer:"F",location:"Section 19"},{id:"coral-q20",number:20,type:"five-true-statements",groupTitle:"Questions 20-21",instruction:"Choose TWO correct answers.",text:"Which TWO of these causes of damage to coral reefs are mentioned by the writer of the text?",options:["A. a rising number of extreme storms","B. the removal of too many fish from the sea","C. the contamination of the sea from waste","D. increased disease among marine species","E. alterations in the usual flow of water in the seas"],correctAnswer:["C","E"],location:"Section 17"},{id:"coral-q22",number:22,type:"five-true-statements",groupTitle:"Questions 22-23",instruction:"Choose TWO correct answers.",text:"Which TWO of the following statements are true of the researchers at London Zoo?",options:["A. They are hoping to expand the numbers of different corals being bred in laboratories.","B. They want to identify corals that can cope well with the changed sea conditions.","C. They are looking at ways of creating artificial reefs that corals could grow on.","D. They are trying out methods that would speed up reproduction in some corals.","E. They are investigating materials that might protect reefs from higher temperatures."],correctAnswer:["B","D"],location:"Section 18"},{id:"coral-q24",number:24,type:"note-completion",groupTitle:"Questions 24-26",instruction:"Complete the sentences below. Choose ONE WORD ONLY from the passage for each answer.",text:"Corals have a number of ______ which they use to collect their food.",correctAnswer:"tentacles",location:"Section 15"},{id:"coral-q25",number:25,type:"note-completion",text:"Algae gain ______ from being inside the coral.",correctAnswer:"protection",location:"Section 15"},{id:"coral-q26",number:26,type:"note-completion",text:"Increases in the warmth of the sea water can remove the ______ from coral.",correctAnswer:"colour",location:"Section 17"}]},Ne={id:"robots-and-us-p3-v5",title:"Reading Passage 3: Robots and us",paragraphs:[{label:"A",content:'When asked "Should robots be used to colonise other planets?", cosmology and astrophysics Professor Martin Rees said he believed the solar system would be mapped by robotic craft by the end of the century. "The next step would be mining of asteroids, enabling fabrication of large structures in space without having to bring all the raw materials from Earth... I think this is more realistic and benign than the... "terraforming" of planets." He maintains that colonised planets "should be preserved with a status that is analogous to Antarctica here on Earth."'},{label:"B",content:`On the question of using robots to colonise other planets and exploit mineral resources, engineering Professor Daniel Wolpert replied, "I don't see a pressing need to colonise other planets unless we can bring [these] resources back to Earth. The vast majority of Earth is currently inaccessible to us. Using robots to gather resources nearer to home would seem to be a better use of our robotic tools."`},{label:"C",content:`Meanwhile, for anthropology Professor Kathleen Richardson, the idea of 'colonisation' of other planets seemed morally dubious: "I think whether we do something on Earth or on Mars we should always do it in the spirit of a genuine interest in "the Other", not to impose a particular model, but to meet 'the Other'."`},{label:"D",content:`In response to the second question, 'How soon will machine intelligence outstrip human intelligence?', Rees mentions robots that are advanced enough to beat humans at chess, but then goes on to say, "Robots are still limited in their ability to sense their environment: they can't yet recognise and move the pieces on a real chessboard as cleverly as a child can. Later this century, however, their more advanced successors may relate to their surroundings, and to people, as adeptly as we do. Moral questions then arise.... Should we feel guilty about exploiting [sophisticated robots]? Should we fret if they are underemployed, frustrated, or bored?" Wolpert's response to the question about machine intelligence outstripping human intelligence was this: "In a limited sense it already has. Machines can already navigate, remember and search for items with an ability that far outstrips humans. However, there is no machine that can identify visual objects or speech with the reliability and flexibility of humans.... Expecting a machine close to the creative intelligence of a human within the next 50 years would be highly ambitious."`},{label:"E",content:`Richardson believes that our fear of machines becoming too advanced has more to do with human nature than anything intrinsic to the machines themselves. In her view, it stems from humans' tendency to personify inanimate objects: we create machines based on representations of ourselves, imagine that machines think and behave as we do, and therefore see them as an autonomous threat. "One of the consequences of thinking that the problem lies with machines is that... we tend to imagine they are greater and more powerful than they really are and subsequently they become so."`},{label:"F",content:`This led on to the third question, 'Should we be scared by advances in artificial intelligence?' To this question, Rees replied, "Those who should be worried are the futurologists who believe in the so-called 'singularity'*... And another worry is that we are increasingly dependent on computer networks, and that these could behave like a single 'brain' with a mind of its own, and with goals that may be contrary to human welfare. I think we should ensure that robots remain as no more than 'idiot savants' lacking the capacity to outwit us, even though they may greatly surpass us in the ability to calculate and process information."

Wolpert's response was to say that we have already seen the damaging effects of artificial intelligence in the form of computer viruses. "But in this case," he says, "the real intelligence is the malicious designer. Critically, the benefits of computers outweigh the damage that computer viruses cause. Similarly, while there may be misuses of robotics in the near future, the benefits that they will bring are likely to outweigh these negative aspects."

Richardson's response to this question was this: "We need to ask why fears of artificial intelligence and robots persist; none have in fact risen up and challenged human supremacy." She believes that as robots have never shown themselves to be a threat to humans, it seems unlikely that they ever will. In fact, she went on, "Not all fear [robots]; many people welcome machine intelligence."`},{label:"G",content:`In answer to the fourth question, 'What can science fiction tell us about robotics?', Rees replied, "I sometimes advise students that it's better to read first-rate science fiction than second-rate science - more stimulating, and perhaps no more likely to be wrong."

As his response, Wolpert commented, "Science fiction has often been remarkable at predicting the future.... Science fiction has painted a vivid spectrum of possible futures, from cute and helpful robots to dystopian robotic societies. Interestingly, almost no science fiction envisages a future without robots."

Finally, on the question of science fiction, Richardson pointed out that in modern society, people tend to think there is reality on the one hand, and fiction and fantasy on the other. She then explained that the division did not always exist, and that scientists and technologists made this separation because they wanted to carve out the sphere of their work. "But the divide is not so clear cut, and that is why the worlds seem to collide at times," she said. "In some cases, we need to bring these different understandings together to get a whole perspective. Perhaps then, we won't be so frightened that something we create as a copy of ourselves will be a [threat] to us."`}],questions:[{id:"robots-q27",number:27,type:"matching-information",groupTitle:"Questions 27-33",instruction:"Look at the following statements and the list of experts below. Match each statement with the correct expert.",text:"For our own safety, humans will need to restrict the abilities of robots.",options:s,correctAnswer:"A",location:"Paragraph F"},{id:"robots-q28",number:28,type:"matching-information",text:"The risk of robots harming us is less serious than humans believe it to be.",options:s,correctAnswer:"C",location:"Paragraphs E-F"},{id:"robots-q29",number:29,type:"matching-information",text:"It will take many decades for robot intelligence to be as imaginative as human intelligence.",options:s,correctAnswer:"B",location:"Paragraph D"},{id:"robots-q30",number:30,type:"matching-information",text:"We may have to start considering whether we are treating robots fairly.",options:s,correctAnswer:"A",location:"Paragraph D"},{id:"robots-q31",number:31,type:"matching-information",text:"Robots are probably of more help to us on Earth than in space.",options:s,correctAnswer:"B",location:"Paragraph B"},{id:"robots-q32",number:32,type:"matching-information",text:"The ideas in high-quality science fiction may prove to be just as accurate as those found in the work of mediocre scientists.",options:s,correctAnswer:"A",location:"Paragraph G"},{id:"robots-q33",number:33,type:"matching-information",text:"There are those who look forward to robots developing greater intelligence.",options:s,correctAnswer:"C",location:"Paragraph F"},{id:"robots-q34",number:34,type:"matching-headings",groupTitle:"Questions 34-36",instruction:"Complete each sentence with the correct ending.",text:"Richardson and Rees express similar views regarding the ethical aspect of ______",options:U,correctAnswer:"C",location:"Paragraphs A and C"},{id:"robots-q35",number:35,type:"matching-headings",text:"Rees and Wolpert express similar views regarding ______",options:U,correctAnswer:"B",location:"Paragraph D"},{id:"robots-q36",number:36,type:"matching-headings",text:"Wolpert disagrees with Richardson on the question of ______",options:U,correctAnswer:"D",location:"Paragraph F"},{id:"robots-q37",number:37,type:"multiple-choice",groupTitle:"Question 37",instruction:"Choose the correct answer.",text:"What point does Richardson make about fear of machines?",options:["It has grown alongside the development of ever more advanced robots.","It is the result of our inclination to attribute human characteristics to non-human entities.","It has its origins in basic misunderstandings about how inanimate objects function.","It demonstrates a key difference between human intelligence and machine intelligence."],correctAnswer:"B",location:"Paragraph E"},{id:"robots-q38",number:38,type:"multiple-choice",groupTitle:"Questions 38-40",instruction:"Choose the correct letter, A, B, C, or D.",text:'According to Rees, who should be most worried about the idea of the "singularity"?',options:["People who are underemployed and bored.","Engineers building space robots.","Futurologists who believe in it.","All users of digital networks."],correctAnswer:"C",location:"Paragraph F"},{id:"robots-q39",number:39,type:"multiple-choice",text:"What does Wolpert say about AI misuse in the near future?",options:["It will certainly cause more harm than good.","Its benefits are likely to outweigh its negative aspects.","It can only be prevented by stricter laws.","It proves robots are becoming autonomous threats."],correctAnswer:"B",location:"Paragraph F"},{id:"robots-q40",number:40,type:"multiple-choice",text:"What does Richardson suggest could reduce people's fear of robots?",options:["Keeping fiction and science completely separate.","Stopping the creation of human-like machines.","Bringing different understandings together for a fuller perspective.","Focusing only on technical research evidence."],correctAnswer:"C",location:"Paragraph G"}]},Fe={id:"ielts-reading-full-vol5",title:"IELTS Reading Full Test 5 - Frozen Food, Coral Reefs, Robots and us",type:"Academic",module:"Reading",duration:60,totalQuestions:40,sections:[De,Oe,Ne]},V=["A","B","C","D","E","F"],x=["A","B","C","D","E","F","G","H"],B=["A. Mark VanDam","B. Nairan Ramirez-Esparza","C. Patricia Kuhl"],D=["A. Cameron Petrie","B. Ravindanath Singh","C. Yama Dixit","D. David Hodell"],Re={id:"coconut-palm-p1-v7",title:"Reading Passage 1: The coconut palm",paragraphs:[{label:"A",content:"For millennia, the coconut has been central to the lives of Polynesian and Asian peoples. In the western world, on the other hand, coconuts have always been exotic and unusual, sometimes rare. The Italian merchant traveller Marco Polo apparently saw coconuts in South Asia in the late 13th century, and among the mid-14th-century travel writings of Sir John Mandeville there is mention of 'great Notes of Ynde' (great Nuts of India). Today, images of palm-fringed tropical beaches are cliches in the west to sell holidays, chocolate bars, fizzy drinks and even romance."},{label:"B",content:"Typically, we envisage coconuts as brown cannonballs that, when opened, provide sweet white flesh. But we see only part of the fruit and none of the plant from which they come. The coconut palm has a smooth, slender, grey trunk, up to 30 metres tall. This is an important source of timber for building houses, and is increasingly being used as a replacement for endangered hardwoods in the furniture construction industry. The trunk is surmounted by a rosette of leaves, each of which may be up to six metres long. The leaves have hard veins in their centres which, in many parts of the world, are used as brushes after the green part of the leaf has been stripped away. Immature coconut flowers are tightly clustered together among the leaves at the top of the trunk. The flower stems may be tapped for their sap to produce a drink, and the sap can also be reduced by boiling to produce a type of sugar used for cooking."},{label:"C",content:"Coconut palms produce as many as seventy fruits per year, weighing more than a kilogram each. The wall of the fruit has three layers: a waterproof outer layer, a fibrous middle layer and a hard, inner layer. The thick fibrous middle layer produces coconut fibre, 'coir', which has numerous uses and is particularly important in manufacturing ropes. The woody innermost layer, the shell, with its three prominent 'eyes', surrounds the seed. An important product obtained from the shell is charcoal, which is widely used in various industries as well as in the home as a cooking fuel. When broken in half, the shells are also used as bowls in many parts of Asia."},{label:"D",content:"Inside the shell are the nutrients (endosperm) needed by the developing seed. Initially, the endosperm is a sweetish liquid, coconut water, which is enjoyed as a drink, but also provides the hormones which encourage other plants to grow more rapidly and produce higher yields. As the fruit matures, the coconut water gradually solidifies to form the brilliant white, fat-rich, edible flesh or meat. Dried coconut flesh, 'copra', is made into coconut oil and coconut milk, which are widely used in cooking in different parts of the world, as well as in cosmetics. A derivative of coconut fat, glycerine, acquired strategic importance in a quite different sphere, as Alfred Nobel introduced the world to his nitroglycerine-based invention: dynamite."},{label:"E",content:"Their biology would appear to make coconuts the great maritime voyagers and coastal colonizers of the plant world. The large, energy-rich fruits are able to float in water and tolerate salt, but cannot remain viable indefinitely; studies suggest after about 110 days at sea they are no longer able to germinate. Literally cast onto desert island shores, with little more than sand to grow in and exposed to the full glare of the tropical sun, coconut seeds are able to germinate and root. The air pocket in the seed, created as the endosperm solidifies, protects the embryo. In addition, the fibrous fruit wall that helped it to float during the voyage stores moisture that can be taken up by the roots of the coconut seedling as it starts to grow."},{label:"F",content:"There have been centuries of academic debate over the origins of the coconut. There were no coconut palms in West Africa, the Caribbean or the east coast of the Americas before the voyages of the European explorers Vasco da Gama and Columbus in the late 15th and early 16th centuries. 16th century trade and human migration patterns reveal that Arab traders and European sailors are likely to have moved coconuts from South and Southeast Asia to Africa and then across the Atlantic to the east coast of America."},{label:"G",content:"But the origin of coconuts discovered along the west coast of America by 16th century sailors has been the subject of centuries of discussion. Two diametrically opposed origins have been proposed: that they came from Asia, or that they were native to America. Both suggestions have problems. In Asia, there is a large degree of coconut diversity and evidence of millennia of human use - but there are no relatives growing in the wild. In America, there are close coconut relatives, but no evidence that coconuts are indigenous. These problems have led to the intriguing suggestion that coconuts originated on coral islands in the Pacific and were dispersed from there."}],questions:[{id:"coco-v7-q1",number:1,type:"note-completion",groupTitle:"Questions 1-8",instruction:"Choose ONE WORD ONLY from the passage for each answer.",text:"trunk: timber for houses and the making of ______",correctAnswer:"furniture",location:"Paragraph B"},{id:"coco-v7-q2",number:2,type:"note-completion",text:"flower stems provide sap, used as a drink or a source of ______",correctAnswer:"sugar",location:"Paragraph B"},{id:"coco-v7-q3",number:3,type:"note-completion",text:"middle layer (coir fibres): used for ______",correctAnswer:"ropes",location:"Paragraph C"},{id:"coco-v7-q4",number:4,type:"note-completion",text:"inner layer (shell): a source of ______",correctAnswer:"charcoal",location:"Paragraph C"},{id:"coco-v7-q5",number:5,type:"note-completion",text:"inner layer (shell), when halved: used for ______",correctAnswer:"bowls",location:"Paragraph C"},{id:"coco-v7-q6",number:6,type:"note-completion",text:"coconut water: a source of ______ for other plants",correctAnswer:"hormones",location:"Paragraph D"},{id:"coco-v7-q7",number:7,type:"note-completion",text:"coconut flesh: oil and milk for cooking and ______",correctAnswer:"cosmetics",location:"Paragraph D"},{id:"coco-v7-q8",number:8,type:"note-completion",text:"glycerine (an ingredient in ______)",correctAnswer:"dynamite",location:"Paragraph D"},{id:"coco-v7-q9",number:9,type:"true-false-not-given",groupTitle:"Questions 9-13",instruction:"Choose TRUE if the statement agrees with the information, FALSE if the statement contradicts the information, or NOT GIVEN if there is no information on this.",text:"Coconut seeds need shade in order to germinate.",correctAnswer:"FALSE",location:"Paragraph E"},{id:"coco-v7-q10",number:10,type:"true-false-not-given",text:"Coconuts were probably transported to Asia from America in the 16th century.",correctAnswer:"FALSE",location:"Paragraph F"},{id:"coco-v7-q11",number:11,type:"true-false-not-given",text:"Coconuts found on the west coast of America were a different type from those found on the east coast.",correctAnswer:"NOT GIVEN",location:"Paragraphs F-G"},{id:"coco-v7-q12",number:12,type:"true-false-not-given",text:"All the coconuts found in Asia are cultivated varieties.",correctAnswer:"TRUE",location:"Paragraph G"},{id:"coco-v7-q13",number:13,type:"true-false-not-given",text:"Coconuts are cultivated in different ways in America and the Pacific.",correctAnswer:"NOT GIVEN",location:"Paragraphs F-G"}]},We={id:"baby-talk-p2-v7",title:"Reading Passage 2: How baby talk gives infant brains a boost",paragraphs:[{label:"A",content:"The typical way of talking to a baby - high-pitched, exaggerated and repetitious - is a source of fascination for linguists who hope to understand how 'baby talk' impacts on learning. Most babies start developing their hearing while still in the womb, prompting some hopeful parents to play classical music to their pregnant bellies. Some research even suggests that infants are listening to adult speech as early as 10 weeks before being born, gathering the basic building blocks of their family's native tongue."},{label:"B",content:"Early language exposure seems to have benefits to the brain - for instance, studies suggest that babies raised in bilingual homes are better at learning how to mentally prioritize information. So how does the sweet if sometimes absurd sound of infant-directed speech influence a baby's development? Here are some recent studies that explore the science behind baby talk."},{label:"C",content:`Fathers don't use baby talk as often or in the same ways as mothers - and that's perfectly OK, according to a new study. Mark VanDam of Washington State University at Spokane and colleagues equipped parents with recording devices and speech-recognition software to study the way they interacted with their youngsters during a normal day. "We found that moms do exactly what you'd expect and what's been described many times over," VanDam explains. "But we found that dads aren't doing the same thing. Dads didn't raise their pitch or fundamental frequency when they talked to kids." Their role may be rooted in what is called the bridge hypothesis, which dates back to 1975. It suggests that fathers use less familial language to provide their children with a bridge to the kind of speech they'll hear in public. "The idea is that a kid gets to practice a certain kind of speech with mom and another kind of speech with dad, so the kid then has a wider repertoire of kinds of speech to practice," says VanDam.`},{label:"D",content:'Scientists from the University of Washington and the University of Connecticut collected thousands of 30-second conversations between parents and their babies, fitting 26 children with audio-recording vests that captured language and sound during a typical eight-hour day. The study found that the more baby talk parents used, the more their youngsters began to babble. And when researchers saw the same babies at age two, they found that frequent baby talk had dramatically boosted vocabulary, regardless of socioeconomic status. "Those children who listened to a lot of baby talk were talking more than the babies that listened to more adult talk or standard speech," says Nairan Ramirez-Esparza of the University of Connecticut. "We also found that it really matters whether you use baby talk in a one-on-one context," she adds. "The more parents use baby talk one-on-one, the more babies babble, and the more they babble, the more words they produce later in life."'},{label:"E",content:`Another study suggests that parents might want to pair their youngsters up so they can babble more with their own kind. Researchers from McGill University and Universite du Quebec a Montreal found that babies seem to like listening to each other rather than to adults - which may be why baby talk is such a universal tool among parents. They played repeating vowel sounds made by a special synthesizing device that mimicked sounds made by either an adult woman or another baby. This way, only the impact of the auditory cues was observed. The team then measured how long each type of sound held the infants' attention. They found that the 'infant' sounds held babies' attention nearly 40 percent longer. The baby noises also induced more reactions in the listening infants, like smiling or lip moving, which approximates sound making. The team theorizes that this attraction to other infant sounds could help launch the learning process that leads to speech. "It may be some property of the sound that is just drawing their attention," says study co-author Linda Polka. "Or maybe they are really interested in that particular type of sound because they are starting to focus on their own ability to make sounds. We are speculating here but it might catch their attention because they recognize it as a sound they could possibly make."`},{label:"F",content:`In a study published in Proceedings of the National Academy of Sciences, a total of 57 babies from two slightly different age groups - seven months and eleven and a half months - were played a number of syllables from both their native language (English) and a non-native tongue (Spanish). The infants were placed in a brain-activation scanner that recorded activity in a brain region known to guide the motor movements that produce speech. The results suggest that listening to baby talk prompts infant brains to start practicing their language skills. "Finding activation in motor areas of the brain when infants are simply listening is significant, because it means the baby brain is engaged in trying to talk back right from the start, and suggests that seven-month-olds' brains are already trying to figure out how to make the right movements that will produce words," says co-author Patricia Kuhl. Another interesting finding was that while the seven-month-olds responded to all speech sounds regardless of language, the brains of the older infants worked harder at the motor activations of non-native sounds compared to native sounds. The study may have also uncovered a process by which babies recognize differences between their native language and other tongues.`}],questions:[{id:"baby-v7-q14",number:14,type:"matching-information",groupTitle:"Questions 14-17",instruction:"Match each statement with the correct person.",text:"the importance of adults giving babies individual attention when talking to them",options:B,correctAnswer:"B",location:"Paragraph D"},{id:"baby-v7-q15",number:15,type:"matching-information",text:"the connection between what babies hear and their own efforts to create speech",options:B,correctAnswer:"C",location:"Paragraph F"},{id:"baby-v7-q16",number:16,type:"matching-information",text:"the advantage for the baby of having two parents each speaking in a different way",options:B,correctAnswer:"A",location:"Paragraph C"},{id:"baby-v7-q17",number:17,type:"matching-information",text:"the connection between the amount of baby talk babies hear and how much vocalising they do themselves",options:B,correctAnswer:"B",location:"Paragraph D"},{id:"baby-v7-q18",number:18,type:"summary-completion",groupTitle:"Questions 18-23",instruction:"Choose NO MORE THAN TWO WORDS from the passage for each answer.",text:"Researchers at Washington State University used ______, together with specialised computer programs, to analyse how parents interacted with their babies during a normal day.",correctAnswer:"recording devices",location:"Paragraph C"},{id:"baby-v7-q19",number:19,type:"summary-completion",text:"The study revealed that ______ tended not to modify their ordinary speech patterns when interacting with their babies.",correctAnswer:"fathers|dads",location:"Paragraph C"},{id:"baby-v7-q20",number:20,type:"summary-completion",text:"According to an idea known as the ______, they may use a more adult type of speech to prepare infants for the language they will hear outside the family home.",correctAnswer:"bridge hypothesis",location:"Paragraph C"},{id:"baby-v7-q21",number:21,type:"summary-completion",text:"According to the researchers, hearing baby talk from one parent and 'normal' language from the other expands the baby's ______ of types of speech which they can practise.",correctAnswer:"repertoire",location:"Paragraph C"},{id:"baby-v7-q22",number:22,type:"summary-completion",text:"Scientists from the University of Washington and the University of Connecticut recorded speech and sound using special ______ that the babies were equipped with.",correctAnswer:"audio-recording vests",location:"Paragraph D"},{id:"baby-v7-q23",number:23,type:"summary-completion",text:"When they studied the babies again at age two, they found that those who had heard a lot of baby talk in infancy had a much larger ______ than those who had not.",correctAnswer:"vocabulary",location:"Paragraph D"},{id:"baby-v7-q24",number:24,type:"matching-information",groupTitle:"Questions 24-26",instruction:"Which paragraph contains the following information? Choose the correct letter, A-F.",text:"a reference to a change which occurs in babies' brain activity before the end of their first year",options:V,correctAnswer:"F",location:"Paragraph F"},{id:"baby-v7-q25",number:25,type:"matching-information",text:"an example of what some parents do for their baby's benefit before birth",options:V,correctAnswer:"A",location:"Paragraph A"},{id:"baby-v7-q26",number:26,type:"matching-information",text:"a mention of babies' preference for the sounds that other babies make",options:V,correctAnswer:"E",location:"Paragraph E"}]},Ge={id:"harappan-civilisation-p3-v7",title:"Reading Passage 3: Whatever happened to the Harappan Civilisation?",paragraphs:[{label:"A",content:"The Harappan Civilisation of ancient Pakistan and India flourished 5,000 years ago, but a thousand years later their cities were abandoned. The Harappan Civilisation was a sophisticated Bronze Age society who built 'megacities' and traded internationally in luxury craft products, and yet seemed to have left almost no depictions of themselves. But their lack of self-imagery - at a time when the Egyptians were carving and painting representations of themselves all over their temples - is only part of the mystery."},{label:"B",content:`"There is plenty of archaeological evidence to tell us about the rise of the Harappan Civilisation, but relatively little about its fall," explains archaeologist Dr Cameron Petrie of the University of Cambridge. "As populations increased, cities were built that had great baths, craft workshops, palaces and halls laid out in distinct sectors. Houses were arranged in blocks, with wide main streets and narrow alleyways, and many had their own wells and drainage systems. It was very much a 'thriving' civilisation." Then around 2100 BC, a transformation began. Streets went uncleaned, buildings started to be abandoned, and ritual structures fell out of use. After their final demise, a millennium passed before really large-scale cities appeared once more in South Asia.`},{label:"C",content:'Some have claimed that major glacier-fed rivers changed their course, dramatically affecting the water supply and agriculture; or that the cities could not cope with an increasing population, they exhausted their resource base, the trading economy broke down or they succumbed to invasion and conflict; and yet others that climate change caused an environmental change that affected food and water provision. "It is unlikely that there was a single cause for the decline of the civilisation. But the fact is, until now, we have had little solid evidence from the area for most of the key elements," said Petrie. "A lot of the archaeological debate has really only been well-argued speculation."'},{label:"D",content:"A research team led by Petrie, together with Dr Ravindanath Singh of Banaras Hindu University in India, found early in their investigations that many of the archaeological sites were not where they were supposed to be, completely altering understanding of the way that this region was inhabited in the past. When they carried out a survey of how the larger area was settled in relation to sources of water, they found inaccuracies in the published geographic locations of ancient settlements ranging from several hundred metres to many kilometres. They realised that any attempts to use the existing data were likely to be fundamentally flawed. Over the course of several seasons of fieldwork they carried out new surveys, finding an astonishing 198 settlement sites that were previously unknown."},{label:"E",content:`Now, research published by Dr Yama Dixit and Professor David Hodell, both from Cambridge's Department of Earth Sciences, has provided the first definitive evidence for climate change affecting the plains of north-western India, where hundreds of Harappan sites are known to have been situated. The researchers gathered shells of "Melanoides tuberculata" snails from the sediments of an ancient lake and used geochemical analysis as a means of tracing the climate history of the region. "As today, the major source of water into the lake is likely to have been the summer monsoon," says Dixit. "But we have observed that there was an abrupt change about 4,100 years ago, when the amount of evaporation from the lake exceeded the rainfall - indicative of a drought." Hodell adds: "We estimate that the weakening of the Indian summer monsoon climate lasted about 200 years before recovering to the previous conditions, which we still see today."`},{label:"F",content:'It has long been thought that other great Bronze Age civilisations also declined at a similar time, with a global-scale climate event being seen as the cause. While it is possible that these local-scale processes were linked, the real archaeological interest lies in understanding the impact of these larger-scale events on different environments and different populations. "Considering the vast area of the Harappan Civilisation with its variable weather systems," explains Singh, "it is essential that we obtain more climate data from areas close to the two great cities at Mohenjodaro and Harappa and also from the Indian Punjab."'},{label:"G",content:"Petrie and Singh's team is now examining archaeological records and trying to understand details of how people led their lives in the region five millennia ago. They are analysing grains cultivated at the time, and trying to work out whether they were grown under extreme conditions of water stress, and whether they were adjusting the combinations of crops they were growing for different weather systems. They are also looking at whether the types of pottery used, and other aspects of their material culture, were distinctive to specific regions or were more similar across larger areas. This gives us insight into the types of interactive networks that the population was involved in, and whether those changed."},{label:"H",content:'Petrie believes that archaeologists are in a unique position to investigate how past societies responded to environmental and climatic change. "By investigating responses to environmental pressures and threats, we can learn from the past to engage with the public, and the relevant governmental and administrative bodies, to be more proactive in issues such as the management and administration of water supply, the balance of urban and rural development, and the importance of preserving cultural heritage in the future."'}],questions:[{id:"har-v7-q27",number:27,type:"matching-information",groupTitle:"Questions 27-31",instruction:"Reading Passage 3 has eight paragraphs, A-H. Which paragraph contains the following information?",text:"proposed explanations for the decline of the Harappan Civilisation",options:x,correctAnswer:"C",location:"Paragraph C"},{id:"har-v7-q28",number:28,type:"matching-information",text:"a reference to a present-day application of some archaeological research findings",options:x,correctAnswer:"H",location:"Paragraph H"},{id:"har-v7-q29",number:29,type:"matching-information",text:"a difference between the Harappan Civilisation and another culture of the same period",options:x,correctAnswer:"A",location:"Paragraph A"},{id:"har-v7-q30",number:30,type:"matching-information",text:"a description of some features of Harappan urban design",options:x,correctAnswer:"B",location:"Paragraph B"},{id:"har-v7-q31",number:31,type:"matching-information",text:"a reference to the discovery of errors made by previous archaeologists",options:x,correctAnswer:"D",location:"Paragraph D"},{id:"har-v7-q32",number:32,type:"summary-completion",groupTitle:"Questions 32-36",instruction:"Choose ONE WORD ONLY from the passage for each answer.",text:"By collecting the ______ of snails and analysing them, researchers discovered evidence of a change in water levels.",correctAnswer:"shells",location:"Paragraph E"},{id:"har-v7-q33",number:33,type:"summary-completion",text:"They discovered evidence of a change in water levels in a ______ in the region.",correctAnswer:"lake",location:"Paragraph E"},{id:"har-v7-q34",number:34,type:"summary-completion",text:"This occurred when there was less ______ than evaporation.",correctAnswer:"rainfall",location:"Paragraph E"},{id:"har-v7-q35",number:35,type:"summary-completion",text:"Petrie and Singh's team are now using archaeological records to look at ______ from five millennia ago.",correctAnswer:"grains",location:"Paragraph G"},{id:"har-v7-q36",number:36,type:"summary-completion",text:"They are also examining objects including ______, to find out about links between inhabitants of different parts of the region.",correctAnswer:"pottery",location:"Paragraph G"},{id:"har-v7-q37",number:37,type:"matching-information",groupTitle:"Questions 37-40",instruction:"Match each statement with the correct person.",text:"Finding further information about changes to environmental conditions in the region is vital.",options:D,correctAnswer:"B",location:"Paragraph F"},{id:"har-v7-q38",number:38,type:"matching-information",text:"Examining previous patterns of behaviour may have long-term benefits.",options:D,correctAnswer:"A",location:"Paragraph H"},{id:"har-v7-q39",number:39,type:"matching-information",text:"Rough calculations indicate the approximate length of a period of water shortage.",options:D,correctAnswer:"D",location:"Paragraph E"},{id:"har-v7-q40",number:40,type:"matching-information",text:"Information about the decline of the Harappan Civilisation has been lacking.",options:D,correctAnswer:"A",location:"Paragraph B"}]},Me={id:"ielts-reading-full-vol7",title:"IELTS Reading Full Test 7 - The coconut palm, Baby talk, Harappan Civilisation",type:"Academic",module:"Reading",duration:60,totalQuestions:40,sections:[Re,We,Ge]},T=["A","B","C","D","E","F","G"],P=["A. Peter Fleming","B. Ran Fiennes","C. Chris Bonington","D. Robin Hanbury-Tenison","E. Wilfred Thesiger"],He={id:"nutmeg-p1-v8",title:"Reading Passage 1: Nutmeg - a valuable spice",paragraphs:[{label:"A",content:"The nutmeg tree, Myristica fragrans, is a large evergreen tree native to Southeast Asia. Until the late 18th century, it only grew in one place in the world: a small group of islands in the Banda Sea, part of the Moluccas - or Spice Islands - in northeastern Indonesia. The tree is thickly branched with dense foliage of tough, dark green oval leaves, and produces small, yellow, bell-shaped flowers and pale yellow pear-shaped fruits. The fruit is encased in a fleshy husk. When the fruit is ripe, this husk splits into two halves along a ridge running the length of the fruit. Inside is a purple-brown shiny seed, 2-3 cm long by about 2 cm across, surrounded by a lacy red or crimson covering called an 'aril'. These are the sources of the two spices nutmeg and mace, the former being produced from the dried seed and the latter from the aril."},{label:"B",content:"Nutmeg was a highly prized and costly ingredient in European cuisine in the Middle Ages, and was used as a flavouring, medicinal, and preservative agent. Throughout this period, the Arabs were the exclusive importers of the spice to Europe. They sold nutmeg for high prices to merchants based in Venice, but they never revealed the exact location of the source of this extremely valuable commodity. The Arab-Venetian dominance of the trade finally ended in 1512, when the Portuguese reached the Banda Islands and began exploiting its precious resources."},{label:"C",content:"Always in danger of competition from neighbouring Spain, the Portuguese began subcontracting their spice distribution to Dutch traders. Profits began to flow into the Netherlands, and the Dutch commercial fleet swiftly grew into one of the largest in the world. The Dutch quietly gained control of most of the shipping and trading of spices in Northern Europe. Then, in 1580, Portugal fell under Spanish rule, and by the end of the 16th century the Dutch found themselves locked out of the market. As prices for pepper, nutmeg, and other spices soared across Europe, they decided to fight back."},{label:"D",content:"In 1602, Dutch merchants founded the VOC, a trading corporation better known as the Dutch East India Company. By 1617, the VOC was the richest commercial operation in the world. The company had 50,000 employees worldwide, with a private army of 30,000 men and a fleet of 200 ships. At the same time, thousands of people across Europe were dying of the plague, a highly contagious and deadly disease. Doctors were desperate for a way to stop the spread of this disease, and they decided nutmeg held the cure. Everybody wanted nutmeg, and many were willing to spare no expense to have it. Nutmeg bought for a few pennies in Indonesia could be sold for 68,000 times its original cost on the streets of London. The only problem was the short supply. And that is where the Dutch found their opportunity."},{label:"E",content:"The Banda Islands were ruled by local sultans who insisted on maintaining a neutral trading policy towards foreign powers. This allowed them to avoid the presence of Portuguese or Spanish troops on their soil, but it also left them unprotected from other invaders. In 1621, the Dutch arrived and took over. Once securely in control of the Bandas, the Dutch went to work protecting their new investment. They concentrated all nutmeg production into a few easily guarded areas, uprooting and destroying any trees outside the plantation zones. Anyone caught growing a nutmeg seedling or carrying seeds without the proper authority was severely punished. In addition, all exported nutmeg was covered with lime to make sure there was no chance a fertile seed which could be grown elsewhere would leave the islands. There was only one obstacle to Dutch domination. One of the Banda Islands, a sliver of land called Run, only 3 km long by less than 1 km wide, was under the control of the British. After decades of fighting for control of this tiny island, the Dutch and British arrived at a compromise settlement, the Treaty of Breda, in 1667. Intent on securing their hold over every nutmeg-producing island, the Dutch offered a trade: if the British would give them the island of Run, they would in turn give Britain a distant and much less valuable island in North America. The British agreed. That other island was Manhattan, which is how New Amsterdam became New York. The Dutch now had a monopoly over the nutmeg trade which would last for another century."},{label:"F",content:"Then, in 1770, a Frenchman named Pierre Poivre successfully smuggled nutmeg plants to safety in Mauritius, an island off the coast of Africa. Some of these were later exported to the Caribbean where they thrived, especially on the island of Grenada. Next, in 1778, a volcanic eruption in the Banda region caused a tsunami that wiped out half the nutmeg groves. Finally, in 1809, the British returned to Indonesia and seized the Banda Islands by force. They returned the islands to the Dutch in 1817, but not before transplanting hundreds of nutmeg seedlings to plantations in several locations across southern Asia. The Dutch nutmeg monopoly was over."},{label:"G",content:"Today, nutmeg is grown in Indonesia, the Caribbean, India, Malaysia, Papua New Guinea and Sri Lanka, and world nutmeg production is estimated to average between 10,000 and 12,000 tonnes per year."}],questions:[{id:"nutmeg-v8-q1",number:1,type:"note-completion",groupTitle:"Questions 1-4",instruction:"Choose ONE WORD ONLY from the passage for each answer.",text:"the leaves of the tree are ______ in shape",correctAnswer:"oval",location:"Paragraph A"},{id:"nutmeg-v8-q2",number:2,type:"note-completion",text:"the ______ surrounds the fruit and breaks open when the fruit is ripe",correctAnswer:"husk",location:"Paragraph A"},{id:"nutmeg-v8-q3",number:3,type:"note-completion",text:"the ______ is used to produce the spice nutmeg",correctAnswer:"seed",location:"Paragraph A"},{id:"nutmeg-v8-q4",number:4,type:"note-completion",text:"the covering known as the aril is used to produce ______",correctAnswer:"mace",location:"Paragraph A"},{id:"nutmeg-v8-q5",number:5,type:"true-false-not-given",groupTitle:"Questions 5-7",instruction:"Choose TRUE if the statement agrees with the information, FALSE if the statement contradicts the information, or NOT GIVEN if there is no information on this.",text:"In the Middle Ages, most Europeans knew where nutmeg was grown.",correctAnswer:"FALSE",location:"Paragraph B"},{id:"nutmeg-v8-q6",number:6,type:"true-false-not-given",text:"The VOC was the world's first major trading company.",correctAnswer:"NOT GIVEN",location:"Paragraph D"},{id:"nutmeg-v8-q7",number:7,type:"true-false-not-given",text:"Following the Treaty of Breda, the Dutch had control of all the islands where nutmeg grew.",correctAnswer:"TRUE",location:"Paragraph E"},{id:"nutmeg-v8-q8",number:8,type:"note-completion",groupTitle:"Questions 8-13",instruction:"Complete the table below. Write ONLY ONE WORD from the passage.",text:"Nutmeg was brought to Europe by the ______",correctAnswer:"Arabs",location:"Paragraph B"},{id:"nutmeg-v8-q9",number:9,type:"note-completion",text:"Demand for nutmeg grew, as it was believed to be effective against the disease known as the ______",correctAnswer:"plague",location:"Paragraph D"},{id:"nutmeg-v8-q10",number:10,type:"note-completion",text:"The Dutch put ______ on nutmeg to avoid it being cultivated outside the islands",correctAnswer:"lime",location:"Paragraph E"},{id:"nutmeg-v8-q11",number:11,type:"note-completion",text:"The Dutch finally obtained the island of ______ from the British",correctAnswer:"Run",location:"Paragraph E"},{id:"nutmeg-v8-q12",number:12,type:"note-completion",text:"1770 - nutmeg plants were secretly taken to ______",correctAnswer:"Mauritius",location:"Paragraph F"},{id:"nutmeg-v8-q13",number:13,type:"note-completion",text:"1778 - half the Banda Islands' nutmeg plantations were destroyed by a ______",correctAnswer:"tsunami",location:"Paragraph F"}]},je={id:"driverless-cars-p2-v8",title:"Reading Passage 2: Driverless cars",paragraphs:[{label:"A",content:`The automotive sector is well used to adapting to automation in manufacturing. The implementation of robotic car manufacture from the 1970s onwards led to significant cost savings and improvements in the reliability and flexibility of vehicle mass production. A new challenge to vehicle production is now on the horizon and, again, it comes from automation. However, this time it is not to do with the manufacturing process, but with the vehicles themselves.

Research projects on vehicle automation are not new. Vehicles with limited self-driving capabilities have been around for more than 50 years, resulting in significant contributions towards driver assistance systems. But since Google announced in 2010 that it had been trialling self-driving cars on the streets of California, progress in this field has quickly gathered pace.`},{label:"B",content:`There are many reasons why technology is advancing so fast. One frequently cited motive is safety; indeed, research at the UK's Transport Research Laboratory has demonstrated that more than 90 percent of road collisions involve human error as a contributory factor, and it is the primary cause in the vast majority. Automation may help to reduce the incidence of this.

Another aim is to free the time people spend driving for other purposes. If the vehicle can do some or all of the driving, it may be possible to be productive, to socialise or simply to relax while automation systems have responsibility for safe control of the vehicle. If the vehicle can do the driving, those who are challenged by existing mobility models - such as older or disabled travellers - may be able to enjoy significantly greater travel autonomy.`},{label:"C",content:"Beyond these direct benefits, we can consider the wider implications for transport and society, and how manufacturing processes might need to respond as a result. At present, the average car spends more than 90 percent of its life parked. Automation means that initiatives for car-sharing become much more viable, particularly in urban areas with significant travel demand. If a significant proportion of the population choose to use shared automated vehicles, mobility demand can be met by far fewer vehicles."},{label:"D",content:`The Massachusetts Institute of Technology investigated automated mobility in Singapore, finding that fewer than 30 percent of the vehicles currently used would be required if fully automated car sharing could be implemented. If this is the case, it might mean that we need to manufacture far fewer vehicles to meet demand. However, the number of trips being taken would probably increase, partly because empty vehicles would have to be moved from one customer to the next.

Modelling work by the University of Michigan Transportation Research Institute suggests automated vehicles might reduce vehicle ownership by 43 percent, but that vehicles' average annual mileage would double as a result. As a consequence, each vehicle would be used more intensively, and might need replacing sooner. This faster rate of turnover may mean that vehicle production will not necessarily decrease.`},{label:"E",content:`Automation may prompt other changes in vehicle manufacture. If we move to a model where consumers are tending not to own a single vehicle but to purchase access to a range of vehicles through a mobility provider, drivers will have the freedom to select one that best suits their needs for a particular journey, rather than making a compromise across all their requirements.

Since, for most of the time, most of the seats in most cars are unoccupied, this may boost production of a smaller, more efficient range of vehicles that suit the needs of individuals. Specialised vehicles may then be available for exceptional journeys, such as going on a family camping trip or helping a son or daughter move to university.`},{label:"F",content:"There are a number of hurdles to overcome in delivering automated vehicles to our roads. These include the technical difficulties in ensuring that the vehicle works reliably in the infinite range of traffic, weather and road situations it might encounter; the regulatory challenges in understanding how liability and enforcement might change when drivers are no longer essential for vehicle operation; and the societal changes that may be required for communities to trust and accept automated vehicles as being a valuable part of the mobility landscape."},{label:"G",content:"It is clear that there are many challenges that need to be addressed but, through robust and targeted research, these can most probably be conquered within the next 10 years. Mobility will change in such potentially significant ways and in association with so many other technological developments, such as telepresence and virtual reality, that it is hard to make concrete predictions about the future. However, one thing is certain: change is coming, and the need to be flexible in response to this will be vital for those involved in manufacturing the vehicles that will deliver future mobility."}],questions:[{id:"driverless-v8-q14",number:14,type:"matching-information",groupTitle:"Questions 14-18",instruction:"Which paragraph contains the following information? Choose the correct letter, A-G.",text:"reference to the amount of time when a car is not in use",options:T,correctAnswer:"C",location:"Paragraph C"},{id:"driverless-v8-q15",number:15,type:"matching-information",text:"mention of several advantages of driverless vehicles for individual road-users",options:T,correctAnswer:"B",location:"Paragraph B"},{id:"driverless-v8-q16",number:16,type:"matching-information",text:"reference to the opportunity of choosing the most appropriate vehicle for each trip",options:T,correctAnswer:"E",location:"Paragraph E"},{id:"driverless-v8-q17",number:17,type:"matching-information",text:"an estimate of how long it will take to overcome a number of problems",options:T,correctAnswer:"G",location:"Paragraph G"},{id:"driverless-v8-q18",number:18,type:"matching-information",text:"a suggestion that the use of driverless cars may have no effect on the number of vehicles manufactured",options:T,correctAnswer:"D",location:"Paragraph D"},{id:"driverless-v8-q19",number:19,type:"summary-completion",groupTitle:"Questions 19-22",instruction:"Choose NO MORE THAN TWO WORDS from the passage for each answer.",text:"Figures from the Transport Research Laboratory indicate that most motor accidents are partly due to ______.",correctAnswer:"human error",location:"Paragraph B"},{id:"driverless-v8-q20",number:20,type:"summary-completion",text:"In addition to the direct benefits of automation, schemes for ______ will be more workable, especially in towns and cities.",correctAnswer:"car sharing",location:"Paragraph C"},{id:"driverless-v8-q21",number:21,type:"summary-completion",text:"According to the University of Michigan Transportation Research Institute, there could be a 43 percent drop in ______ of cars.",correctAnswer:"ownership",location:"Paragraph D"},{id:"driverless-v8-q22",number:22,type:"summary-completion",text:"However, this would mean that the yearly ______ of each car would, on average, be twice as high as it is currently.",correctAnswer:"mileage",location:"Paragraph D"},{id:"driverless-v8-q23",number:23,type:"five-true-statements",groupTitle:"Questions 23-24",instruction:"Choose TWO letters, A-E.",text:"Which TWO benefits of automated vehicles does the writer mention?",options:["A. Car travellers could enjoy considerable cost savings.","B. It would be easier to find parking spaces in urban areas.","C. Travellers could spend journeys doing something other than driving.","D. People who find driving physically difficult could travel independently.","E. A reduction in the number of cars would mean a reduction in pollution."],correctAnswer:["C","D"],location:"Paragraph B"},{id:"driverless-v8-q25",number:25,type:"five-true-statements",groupTitle:"Questions 25-26",instruction:"Choose TWO letters, A-E.",text:"Which TWO challenges to automated vehicle development does the writer mention?",options:["A. making sure the general public has confidence in automated vehicles","B. managing the pace of transition from conventional to automated vehicles","C. deciding how to compensate professional drivers who become redundant","D. setting up the infrastructure to make roads suitable for automated vehicles","E. getting automated vehicles to adapt to various different driving conditions"],correctAnswer:["A","E"],location:"Paragraph F"}]},Le={id:"what-is-exploration-p3-v8",title:"Reading Passage 3: What is exploration?",paragraphs:[{label:"A",content:"We are all explorers. Our desire to discover, and then share that new-found knowledge, is part of what makes us human - indeed, this has played an important part in our success as a species. Long before the first caveman slumped down beside the fire and grunted news that there were plenty of wildebeest over yonder, our ancestors had learnt the value of sending out scouts to investigate the unknown. This questing nature of ours undoubtedly helped our species spread around the globe, just as it nowadays no doubt helps the last nomadic Penan maintain their existence in the depleted forests of Borneo, and a visitor negotiate the subways of New York."},{label:"B",content:"Over the years, we have come to think of explorers as a peculiar breed - different from the rest of us, different from those of us who are merely 'well travelled', even; and perhaps there is a type of person more suited to seeking out the new, a type of caveman more inclined to risk venturing out. That, however, does not take away from the fact that we all have this enquiring instinct, even today; and that in all sorts of professions - whether artist, marine biologist or astronomer - borders of the unknown are being tested each day."},{label:"C",content:'Thomas Hardy set some of his novels in Egdon Heath, a fictional area of uncultivated land, and used the landscape to suggest the desires and fears of his characters. He is delving into matters we all recognise because they are common to humanity. This is surely an act of exploration, and into a world as remote as the author chooses. Explorer and travel writer Peter Fleming talks of the moment when the explorer returns to the existence he has left behind with his loved ones. The traveller "who has for weeks or months seen himself only as a puny and irrelevant alien crawling laboriously over a country in which he has no roots and no background, suddenly encounters his other self, a relatively solid figure, with a place in the minds of certain people".'},{label:"D",content:"In this book about the exploration of the earth's surface, I have confined myself to those whose travels were real and who also aimed at more than personal discovery. But that still left me with another problem: the word 'explorer' has become associated with a past era. We think back to a golden age, as if exploration peaked somehow in the 19th century - as if the process of discovery is now on the decline, though the truth is that we have named only one and a half million of this planet's species, and there may be more than 10 million - and that is not including bacteria. We have studied only 5 percent of the species we know. We have scarcely mapped the ocean floors, and know even less about ourselves; we fully understand the workings of only 10 percent of our brains."},{label:"E",content:`Here is how some of today's "explorers" define the word. Ran Fiennes, dubbed the "greatest living explorer", said, "An explorer is someone who has done something that no human has done before - and also done something scientifically useful." Chris Bonington, a leading mountaineer, felt exploration was to be found in the act of physically touching the unknown: "You have to have gone somewhere new." Then Robin Hanbury-Tenison, a campaigner on behalf of remote so-called "tribal" peoples, said, "A traveller simply records information about some far-off world, and reports back; but an explorer 'changes' the world." Wilfred Thesiger, who crossed Arabia's Empty Quarter in 1946, and belongs to an era of unmechanised travel now lost to the rest of us, told me, "If I had gone across by camel when I could have gone by car, it would have been a stunt." To him, exploration meant bringing back information from a remote place regardless of any great self-discovery.`},{label:"F",content:"Each definition is slightly different - and tends to reflect the field of endeavour of each pioneer. It was the same whoever I asked: the prominent historian would say exploration was a thing of the past, the cutting-edge scientist would say it was of the present. And so on. They each set their own particular criteria; the common factor in their approach being that they all had, unlike many of us who simply enjoy travel or discovering new things, both a very definite objective from the outset and also a desire to record their findings."},{label:"G",content:"I had best declare my own bias. As a writer, I am interested in the exploration of ideas. I have done a great many expeditions and each one was unique. I have lived for months alone with isolated groups of people all around the world, even two 'uncontacted tribes'. But none of these things is of the slightest interest to anyone unless, through my books, I have found a new slant, explored a new idea."},{label:"H",content:"Why? Because the world has moved on. The time has long passed for the great continental voyages - another walk to the poles, another crossing of the Empty Quarter. We know how the land surface of our planet lies; exploration of it is now down to the details - the habits of microbes, say, or the grazing behaviour of buffalo. Aside from the deep sea and deep underground, it is the era of specialists. However, this is to disregard the role the human mind has in conveying remote places; and this is what interests me: how a fresh interpretation, even of a well-travelled route, can give its readers new insights."}],questions:[{id:"explore-v8-q27",number:27,type:"multiple-choice",groupTitle:"Question 27",instruction:"Choose the correct letter, A, B, C or D.",text:"The writer refers to visitors to New York to illustrate the point that",options:["exploration is an intrinsic element of being human.","most people are enthusiastic about exploring.","exploration can lead to surprising results.","most people find exploration daunting."],correctAnswer:"A",location:"Paragraph A"},{id:"explore-v8-q28",number:28,type:"multiple-choice",groupTitle:"Question 28",instruction:"Choose the correct letter, A, B, C or D.",text:"According to the second paragraph, what is the writer's view of explorers?",options:["Their discoveries have brought both benefits and disadvantages.","Their main value is in teaching others.","They act on an urge that is common to everyone.","They tend to be more attracted to certain professions than to others."],correctAnswer:"C",location:"Paragraph B"},{id:"explore-v8-q29",number:29,type:"multiple-choice",groupTitle:"Question 29",instruction:"Choose the correct letter, A, B, C or D.",text:"The writer refers to a description of Egdon Heath to suggest that",options:["Hardy was writing about his own experience of exploration.","Hardy was mistaken about the nature of exploration.","Hardy's aim was to investigate people's emotional states.","Hardy's aim was to show the attraction of isolation."],correctAnswer:"C",location:"Paragraph C"},{id:"explore-v8-q30",number:30,type:"multiple-choice",groupTitle:"Question 30",instruction:"Choose the correct letter, A, B, C or D.",text:"In the fourth paragraph, the writer refers to 'a golden age' to suggest that",options:["the amount of useful information produced by exploration has decreased.","fewer people are interested in exploring than in the 19th century.","recent developments have made exploration less exciting.","we are wrong to think that exploration is no longer necessary."],correctAnswer:"D",location:"Paragraph D"},{id:"explore-v8-q31",number:31,type:"multiple-choice",groupTitle:"Question 31",instruction:"Choose the correct letter, A, B, C or D.",text:"In the sixth paragraph, when discussing the definition of exploration, the writer argues that",options:["certain people are likely to misunderstand the nature of exploration.","exploration can lead to surprising results.","most people find exploration daunting.","people tend to relate exploration to their own professional interests."],correctAnswer:"D",location:"Paragraph F"},{id:"explore-v8-q32",number:32,type:"multiple-choice",groupTitle:"Question 32",instruction:"Choose the correct letter, A, B, C or D.",text:"In the last paragraph, the writer explains that he is interested in",options:["how someone's personality is reflected in their choice of places to visit.","the human ability to cast new light on places that may be familiar.","how travel writing has evolved to meet changing demands.","the feelings that writers develop about the places that they explore."],correctAnswer:"B",location:"Paragraph H"},{id:"explore-v8-q33",number:33,type:"matching-information",groupTitle:"Questions 33-37",instruction:"Choose the correct letter. NB You may use any letter more than once.",text:"He referred to the relevance of the form of transport used.",options:P,correctAnswer:"E",location:"Paragraph E"},{id:"explore-v8-q34",number:34,type:"matching-information",text:"He described feelings on coming back home after a long journey.",options:P,correctAnswer:"A",location:"Paragraph C"},{id:"explore-v8-q35",number:35,type:"matching-information",text:"He worked for the benefit of specific groups of people.",options:P,correctAnswer:"D",location:"Paragraph E"},{id:"explore-v8-q36",number:36,type:"matching-information",text:"He did not consider learning about oneself an essential part of exploration.",options:P,correctAnswer:"E",location:"Paragraph E"},{id:"explore-v8-q37",number:37,type:"matching-information",text:"He defined exploration as being both unique and of value to others.",options:P,correctAnswer:"B",location:"Paragraph E"},{id:"explore-v8-q38",number:38,type:"summary-completion",groupTitle:"Questions 38-40",instruction:"Choose NO MORE THAN TWO WORDS from the passage for each answer.",text:"The writer has encountered a wide variety of ______.",correctAnswer:"expeditions",location:"Paragraph G"},{id:"explore-v8-q39",number:39,type:"summary-completion",text:"He was the first outsider many previously ______ individuals had met.",correctAnswer:"uncontacted",location:"Paragraph G"},{id:"explore-v8-q40",number:40,type:"summary-completion",text:"He believes there is no need to further explore Earth's ______, except to address specific questions.",correctAnswer:"land surface",location:"Paragraph H"}]},Qe={id:"ielts-reading-full-vol8",title:"IELTS Reading Full Test 8 - Nutmeg, Driverless cars, What is exploration?",type:"Academic",module:"Reading",duration:60,totalQuestions:40,sections:[He,je,Le]},q=["A","B","C","D","E"],C=["A. Jorg Kudla","B. Caixia Gao","C. Joyce Van Eck","D. Jonathan Jones"],ze={id:"dead-sea-scrolls-p1-v9",title:"Reading Passage 1: The Dead Sea Scrolls",paragraphs:[{label:"A",content:"In late 1946 or early 1947, three Bedouin teenagers were tending their goats and sheep near the ancient settlement of Qumran, located on the northwest shore of the Dead Sea in what is now known as the West Bank. One of these young shepherds tossed a rock into an opening on the side of a cliff and was surprised to hear a shattering sound. He and his companions later entered the cave and stumbled across a collection of large clay jars, seven of which contained scrolls with writing on them. The teenagers took the seven scrolls to a nearby town where they were sold for a small sum to a local antiquities dealer. Word of the find spread, and Bedouins and archaeologists eventually unearthed tens of thousands of additional scroll fragments from 10 nearby caves; together they make up between 800 and 900 manuscripts. It soon became clear that this was one of the greatest archaeological discoveries ever made."},{label:"B",content:"The origin of the Dead Sea Scrolls, which were written around 2,000 years ago between 150 BCE and 70 CE, is still the subject of scholarly debate even today. According to the prevailing theory, they are the work of a population that inhabited the area until Roman troops destroyed the settlement around 70 CE. The area was known as Judea at that time, and the people are thought to have belonged to a group called the Essenes, a devout Jewish sect."},{label:"C",content:"The majority of the texts on the Dead Sea Scrolls are in Hebrew, with some fragments written in an ancient version of its alphabet thought to have fallen out of use in the fifth century BCE. But there are other languages as well. Some scrolls are in Aramaic, the language spoken by many inhabitants of the region from the sixth century BCE to the siege of Jerusalem in 70 CE. In addition, several texts feature translations of the Hebrew Bible into Greek."},{label:"D",content:"The Dead Sea Scrolls include fragments from every book of the Old Testament of the Bible except for the Book of Esther. The only entire book of the Hebrew Bible preserved among the manuscripts from Qumran is Isaiah; this copy, dated to the first century BCE, is considered the earliest biblical manuscript still in existence. Along with biblical texts, the scrolls include documents about sectarian regulations and religious writings that do not appear in the Old Testament."},{label:"E",content:"The writing on the Dead Sea Scrolls is mostly in black or occasionally red ink, and the scrolls themselves are nearly all made of either parchment (animal skin) or an early form of paper called papyrus. The only exception is the scroll numbered 3Q15, which was created out of a combination of copper and tin. Known as the Copper Scroll, this curious document features letters chiselled onto metal - perhaps, as some have theorized, to better withstand the passage of time. One of the most intriguing manuscripts from Qumran, this is a sort of ancient treasure map that lists dozens of gold and silver caches. Using an unconventional vocabulary and odd spelling, it describes 64 underground hiding places that supposedly contain riches buried for safekeeping. None of these hoards have been recovered, possibly because the Romans pillaged Judea during the first century CE. According to various hypotheses, the treasure belonged to local people or was rescued from the Second Temple before its destruction or never existed to begin with."},{label:"F",content:"Some of the Dead Sea Scrolls have been on interesting journeys. In 1948, a Syrian Orthodox archbishop known as Mar Samuel acquired four of the original seven scrolls from a Jerusalem shoemaker and part-time antiquity dealer, paying less than $100 for them. He then travelled to the United States and unsuccessfully offered them to a number of universities, including Yale. Finally, in 1954, he placed an advertisement in the business newspaper The Wall Street Journal - under the category Miscellaneous Items for Sale - that read: Biblical Manuscripts dating back to at least 200 B.C. are for sale. This would be an ideal gift to an educational or religious institution by an individual or group. Fortunately, Israeli archaeologist and statesman Yigael Yadin negotiated their purchase and brought the scrolls back to Jerusalem, where they remain to this day."},{label:"G",content:"In 2017, researchers from the University of Haifa restored and deciphered one of the last untranslated scrolls. The university's Eshbal Ratson and Jonathan Ben-Dov spent one year reassembling the 60 fragments that make up the scroll. Deciphered from a band of coded text on parchment, the find provides insight into the community of people who wrote it and the 364-day calendar they would have used. The scroll names celebrations that indicate shifts in seasons and details two yearly religious events known from another Dead Sea Scroll. Only one more known scroll remains untranslated."}],questions:[{id:"dss-v9-q1",number:1,type:"note-completion",groupTitle:"Questions 1-5",instruction:"Complete the notes below. Choose ONE WORD ONLY from the passage for each answer.",text:"heard a noise of breaking when one teenager threw a ______",correctAnswer:"rock",location:"Paragraph A"},{id:"dss-v9-q2",number:2,type:"note-completion",text:"teenagers went into the ______ and found a number of containers",correctAnswer:"cave",location:"Paragraph A"},{id:"dss-v9-q3",number:3,type:"note-completion",text:"containers were made of ______",correctAnswer:"clay",location:"Paragraph A"},{id:"dss-v9-q4",number:4,type:"note-completion",text:"thought to have been written by a group of people known as the ______",correctAnswer:"Essenes",location:"Paragraph B"},{id:"dss-v9-q5",number:5,type:"note-completion",text:"written mainly in the ______ language",correctAnswer:"Hebrew",location:"Paragraph C"},{id:"dss-v9-q6",number:6,type:"true-false-not-given",groupTitle:"Questions 6-13",instruction:"Choose TRUE if the statement agrees with the information given in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"The Bedouin teenagers who found the scrolls were disappointed by how little money they received for them.",correctAnswer:"NOT GIVEN",location:"Paragraph A"},{id:"dss-v9-q7",number:7,type:"true-false-not-given",text:"There is agreement among academics about the origin of the Dead Sea Scrolls.",correctAnswer:"FALSE",location:"Paragraph B"},{id:"dss-v9-q8",number:8,type:"true-false-not-given",text:"Most of the books of the Bible written on the scrolls are incomplete.",correctAnswer:"TRUE",location:"Paragraph D"},{id:"dss-v9-q9",number:9,type:"true-false-not-given",text:"The information on the Copper Scroll is written in an unusual way.",correctAnswer:"TRUE",location:"Paragraph E"},{id:"dss-v9-q10",number:10,type:"true-false-not-given",text:"Mar Samuel was given some of the scrolls as a gift.",correctAnswer:"FALSE",location:"Paragraph F"},{id:"dss-v9-q11",number:11,type:"true-false-not-given",text:"In the early 1950s, a number of educational establishments in the US were keen to buy scrolls from Mar Samuel.",correctAnswer:"FALSE",location:"Paragraph F"},{id:"dss-v9-q12",number:12,type:"true-false-not-given",text:"The scroll that was pieced together in 2017 contains information about annual occasions in the Qumran area 2,000 years ago.",correctAnswer:"TRUE",location:"Paragraph G"},{id:"dss-v9-q13",number:13,type:"true-false-not-given",text:"Academics at the University of Haifa are currently researching how to decipher the final scroll.",correctAnswer:"FALSE",location:"Paragraph G"}]},Ue={id:"tomato-domestication-p2-v9",title:"Reading Passage 2: A second attempt at domesticating the tomato",paragraphs:[{label:"A",content:"It took at least 3,000 years for humans to learn how to domesticate the wild tomato and cultivate it for food. Now two separate teams in Brazil and China have done it all over again in less than three years. And they have done it better in some ways, as the re-domesticated tomatoes are more nutritious than the ones we eat at present. This approach relies on the revolutionary CRISPR genome editing technique, in which changes are deliberately made to the DNA of a living cell, allowing genetic material to be added, removed or altered. The technique could not only improve existing crops, but could also be used to turn thousands of wild plants into useful and appealing foods. In fact, a third team in the US has already begun to do this with a relative of the tomato called the groundcherry."},{label:"B",content:"This fast-track domestication could help make the worlds food supply healthier and far more resistant to diseases, such as the rust fungus devastating wheat crops. This could transform what we eat, says Jorg Kudla at the University of Munster in Germany, a member of the Brazilian team. There are 50,000 edible plants in the world, but 90 percent of our energy comes from just 15 crops. We can now mimic the known domestication course of major crops like rice, maize, sorghum or others, says Caixia Gao of the Chinese Academy of Sciences in Beijing. Then we might try to domesticate plants that have never been domesticated."},{label:"C",content:"Wild tomatoes, which are native to the Andes region in South America, produce pea-sized fruits. Over many generations, peoples such as the Aztecs and Incas transformed the plant by selecting and breeding plants with mutations in their genetic structure, which resulted in desirable traits such as larger fruit. But every time a single plant with a mutation is taken from a larger population for breeding, much genetic diversity is lost. And sometimes the desirable mutations come with less desirable traits. For instance, the tomato strains grown for supermarkets have lost much of their flavour. By comparing the genomes of modern plants to those of their wild relatives, biologists have been working out what genetic changes occurred as plants were domesticated."},{label:"D",content:"The teams in Brazil and China have now used this knowledge to reintroduce these changes from scratch while maintaining or even enhancing the desirable traits of wild strains. Kudlas team made six changes altogether. For instance, they tripled the size of fruit by editing a gene called FRUIT WEIGHT, and increased the number of tomatoes per truss by editing another called MULTIFLORA. While the historical domestication of tomatoes reduced levels of the red pigment lycopene - thought to have potential health benefits - the team in Brazil managed to boost it instead. The wild tomato has twice as much lycopene as cultivated ones; the newly domesticated one has five times as much. They are quite tasty, says Kudla. A little bit strong. And very aromatic."},{label:"E",content:"The team in China re-domesticated several strains of wild tomatoes with desirable traits lost in domesticated tomatoes. In this way they managed to create a strain resistant to a common disease called bacterial spot race, which can devastate yields. They also created another strain that is more salt tolerant - and has higher levels of vitamin C. Meanwhile, Joyce Van Eck at the Boyce Thompson Institute in New York state decided to use the same approach to domesticate the groundcherry or goldenberry (Physalis pruinosa) for the first time. Groundcherries are already sold to a limited extent in the US but they are hard to produce. Van Eck says there is potential for this to be a commercial crop, but adds that taking the work further would be expensive because of licensing and regulatory approval. Jonathan Jones of the Sainsbury Lab says the approach could boost many obscure plants, but it will be hard for new foods to become major staple crops. By choosing wild plants that are drought or heat tolerant, says Gao, we could create crops that will thrive even as the planet warms. Kudla did not want to reveal which species were in his teams sights because CRISPR has made the process so easy."}],questions:[{id:"tomato-v9-q14",number:14,type:"matching-information",groupTitle:"Questions 14-18",instruction:"Reading Passage 2 has five sections. Which section contains the following information? NB You may use any letter more than once.",text:"a reference to a type of tomato that can resist a dangerous infection",options:q,correctAnswer:"C",location:"Section C"},{id:"tomato-v9-q15",number:15,type:"matching-information",text:"an explanation of how problems can arise from focusing only on a certain type of tomato plant",options:q,correctAnswer:"B",location:"Section B"},{id:"tomato-v9-q16",number:16,type:"matching-information",text:"a number of examples of plants that are not cultivated at present but could be useful as food sources",options:q,correctAnswer:"E",location:"Section E"},{id:"tomato-v9-q17",number:17,type:"matching-information",text:"a comparison between the early domestication of the tomato and more recent research",options:q,correctAnswer:"A",location:"Section A"},{id:"tomato-v9-q18",number:18,type:"matching-information",text:"a personal reaction to the flavour of a tomato that has been genetically edited",options:q,correctAnswer:"C",location:"Section C"},{id:"tomato-v9-q19",number:19,type:"matching-information",groupTitle:"Questions 19-23",instruction:"Match each statement with the correct researcher. NB You may use any letter more than once.",text:"Domestication of certain plants could allow them to adapt to future environmental challenges.",options:C,correctAnswer:"B",location:"Section E"},{id:"tomato-v9-q20",number:20,type:"matching-information",text:"The idea of growing and eating unusual plants may not be accepted on a large scale.",options:C,correctAnswer:"D",location:"Section E"},{id:"tomato-v9-q21",number:21,type:"matching-information",text:"It is not advisable for the future direction of certain research to be made public.",options:C,correctAnswer:"A",location:"Section E"},{id:"tomato-v9-q22",number:22,type:"matching-information",text:"Present efforts to domesticate one wild fruit are limited by the costs involved.",options:C,correctAnswer:"C",location:"Section E"},{id:"tomato-v9-q23",number:23,type:"matching-information",text:"Humans only make use of a small proportion of the plant food available on Earth.",options:C,correctAnswer:"A",location:"Section B"},{id:"tomato-v9-q24",number:24,type:"summary-completion",groupTitle:"Questions 24-26",instruction:"Complete the sentences below. Choose ONE WORD ONLY from the passage for each answer.",text:"An undesirable trait such as loss of ______ may be caused by a mutation in a tomato gene.",correctAnswer:"flavour",location:"Section C"},{id:"tomato-v9-q25",number:25,type:"summary-completion",text:"By modifying one gene in a tomato plant, researchers made the tomato three times its original ______.",correctAnswer:"size",location:"Section D"},{id:"tomato-v9-q26",number:26,type:"summary-completion",text:"A type of tomato which was not badly affected by ______, and was rich in vitamin C, was produced by a team of researchers in China.",correctAnswer:"salt",location:"Section E"}]},Ve={id:"insight-evolution-p3-v9",title:"Reading Passage 3: Insight or evolution?",paragraphs:[{label:"A",content:"Scientific discovery is popularly believed to result from the sheer genius of such intellectual stars as naturalist Charles Darwin and theoretical physicist Albert Einstein. Our view of such unique contributions to science often disregards the person's prior experience and the efforts of their lesser-known predecessors. Conventional wisdom also places great weight on insight in promoting breakthrough scientific achievements, as if ideas spontaneously pop into someone's head - fully formed and functional."},{label:"B",content:"There may be some limited truth to this view. However, we believe that it largely misrepresents the real nature of scientific discovery, as well as that of creativity and innovation in many other realms of human endeavour."},{label:"C",content:"Setting aside such greats as Darwin and Einstein - whose monumental contributions are duly celebrated - we suggest that innovation is more a process of trial and error, where two steps forward may sometimes come with one step back, as well as one or more steps to the right or left. This evolutionary view of human innovation undermines the notion of creative genius and recognizes the cumulative nature of scientific progress."},{label:"D",content:"Consider one unheralded scientist: John Nicholson, a mathematical physicist working in the 1910s who postulated the existence of proto-elements in outer space. By combining different numbers of weights of these proto-elements atoms, Nicholson could recover the weights of all the elements in the then-known periodic table. These successes are all the more noteworthy given the fact that Nicholson was wrong about the presence of proto-elements: they do not actually exist. Yet, amid his often fanciful theories and wild speculations, Nicholson also proposed a novel theory about the structure of atoms. Niels Bohr, the Nobel prize-winning father of modern atomic theory, jumped off from this interesting idea to conceive his now-famous model of the atom."},{label:"E",content:"What are we to make of this story? One might simply conclude that science is a collective and cumulative enterprise. That may be true, but there may be a deeper insight to be gleaned. We propose that science is constantly evolving, much as species of animals do. In biological systems, organisms may display new characteristics that result from random genetic mutations. In the same way, random, arbitrary or accidental mutations of ideas may help pave the way for advances in science. If mutations prove beneficial, then the animal or the scientific theory will continue to thrive and perhaps reproduce."},{label:"F",content:"Support for this evolutionary view of behavioural innovation comes from many domains. Consider one example of an influential innovation in US horseracing. The so-called acey-deucy stirrup placement, in which the rider's foot in his left stirrup is placed as much as 25 centimetres lower than the right, is believed to confer important speed advantages when turning on oval tracks. It was developed by a relatively unknown jockey named Jackie Westrope. Had Westrope conducted methodical investigations or examined extensive film records in a shrewd plan to outrun his rivals? Had he foreseen the speed advantage that would be conferred by riding acey-deucy? No. He suffered a leg injury, which left him unable to fully bend his left knee. His modification just happened to coincide with enhanced left-hand turning performance. This led to the rapid and widespread adoption of riding acey-deucy by many riders, a racing style which continues in todays thoroughbred racing."},{label:"G",content:"Plenty of other stories show that fresh advances can arise from error, misadventure, and also pure serendipity - a happy accident. For example, in the early 1970s, two employees of the company 3M each had a problem: Spencer Silver had a product - a glue which was only slightly sticky - and no use for it, while his colleague Art Fry was trying to figure out how to affix temporary bookmarks in his hymn book without damaging its pages. The solution to both these problems was the invention of the brilliantly simple yet phenomenally successful Post-It note. Such examples give lie to the claim that ingenious, designing minds are responsible for human creativity and invention. Far more banal and mechanical forces may be at work; forces that are fundamentally connected to the laws of science."},{label:"H",content:"The notions of insight, creativity and genius are often invoked, but they remain vague and of doubtful scientific utility, especially when one considers the diverse and enduring contributions of individuals such as Plato, Leonardo da Vinci, Shakespeare, Beethoven, Galileo, Newton, Kepler, Curie, Pasteur and Edison. These notions merely label rather than explain the evolution of human innovations. We need another approach, and there is a promising candidate."},{label:"I",content:"The Law of Effect was advanced by psychologist Edward Thorndike in 1898, some 40 years after Charles Darwin published his groundbreaking work on biological evolution, On the Origin of Species. This simple law holds that organisms tend to repeat successful behaviors and to refrain from performing unsuccessful ones. Just like Darwins Law of Natural Selection, the Law of Effect involves an entirely mechanical process of variation and selection, without any end objective in sight."},{label:"J",content:"Of course, the origin of human innovation demands much further study. In particular, the provenance of the raw material on which the Law of Effect operates is not as clearly known as that of the genetic mutations on which the Law of Natural Selection operates. The generation of novel ideas and behaviors may not be entirely random, but constrained by prior successes and failures - of the current individual (such as Bohr) or of predecessors (such as Nicholson)."},{label:"K",content:"The time seems right for abandoning the naive notions of intelligent design and genius, and for scientifically exploring the true origins of creative behavior."}],questions:[{id:"insight-v9-q27",number:27,type:"multiple-choice",groupTitle:"Question 27",instruction:"Choose the correct letter.",text:"The purpose of the first paragraph is to",options:["defend particular ideas.","compare certain beliefs.","disprove a widely held view.","outline a common assumption."],correctAnswer:"D",location:"Paragraph A"},{id:"insight-v9-q28",number:28,type:"multiple-choice",groupTitle:"Question 28",instruction:"Choose the correct letter.",text:"What are the writers doing in the second paragraph?",options:["criticising an opinion","justifying a standpoint","explaining an approach","supporting an argument"],correctAnswer:"A",location:"Paragraph B"},{id:"insight-v9-q29",number:29,type:"multiple-choice",groupTitle:"Question 29",instruction:"Choose the correct letter.",text:"In the third paragraph, what do the writers suggest about Darwin and Einstein?",options:["They represent an exception to a general rule.","Their way of working has been misunderstood.","They are an ideal which others should aspire to.","Their achievements deserve greater recognition."],correctAnswer:"A",location:"Paragraph C"},{id:"insight-v9-q30",number:30,type:"multiple-choice",groupTitle:"Question 30",instruction:"Choose the correct letter.",text:"John Nicholson is an example of a person whose idea",options:["established his reputation as an influential scientist.","was only fully understood at a later point in history.","laid the foundations for someone else's breakthrough.","initially met with scepticism from the scientific community."],correctAnswer:"C",location:"Paragraph D"},{id:"insight-v9-q31",number:31,type:"multiple-choice",groupTitle:"Question 31",instruction:"Choose the correct letter.",text:"What is the key point of interest about the 'acey-deucy' stirrup placement?",options:["the simple reason why it was invented","the enthusiasm with which it was adopted","the research that went into its development","the cleverness of the person who first used it"],correctAnswer:"A",location:"Paragraph F"},{id:"insight-v9-q32",number:32,type:"yes-no-not-given",groupTitle:"Questions 32-36",instruction:"Choose YES if the statement agrees with the information given in the text, choose NO if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Acknowledging people such as Plato or da Vinci as geniuses will help us understand the process by which great minds create new ideas.",correctAnswer:"NO",location:"Paragraph H"},{id:"insight-v9-q33",number:33,type:"yes-no-not-given",text:"The Law of Effect was discovered at a time when psychologists were seeking a scientific reason why creativity occurs.",correctAnswer:"NOT GIVEN",location:"Paragraph I"},{id:"insight-v9-q34",number:34,type:"yes-no-not-given",text:"The Law of Effect states that no planning is involved in the behaviour of organisms.",correctAnswer:"YES",location:"Paragraph I"},{id:"insight-v9-q35",number:35,type:"yes-no-not-given",text:"The Law of Effect sets out clear explanations about the sources of new ideas and behaviours.",correctAnswer:"NO",location:"Paragraph J"},{id:"insight-v9-q36",number:36,type:"yes-no-not-given",text:"Many scientists are now turning away from the notion of intelligent design and genius.",correctAnswer:"YES",location:"Paragraph K"},{id:"insight-v9-q37",number:37,type:"drag-drop-summary",groupTitle:"Questions 37-40",instruction:"Complete the summary by dragging the correct words into the gaps.",text:`The traditional view of scientific discovery is that breakthroughs happen when a single great mind has sudden ______.
Although this can occur, it is not often the case. Advances are more likely to be the result of a longer process. In some cases, this process involves ______, such as Nicholson's early ideas.
In others, simple necessity may provoke innovation, as with Westrope's decision to modify the position of his riding stirrups. There is also often an element of ______, for example, the coincidence of ideas that led to the invention of the Post-it note.
With both the Law of Natural Selection and the Law of Effect, there may be no clear ______ involved, but merely a process of variation and selection.`,options:["invention","goals","compromise","mistakes","luck","inspiration","experiments"],correctAnswer:["inspiration","experiments","luck","goals"],location:"Paragraphs A-K"}]},Je={id:"ielts-reading-full-vol9",title:"IELTS Reading Full Test 9 - Dead Sea Scrolls, Tomato domestication, Insight or evolution?",type:"Academic",module:"Reading",duration:60,totalQuestions:40,sections:[ze,Ue,Ve]},h=["A. The areas and artefacts within the pyramid itself","B. A difficult task for those involved","C. A king who saved his people","D. A single certainty among other less definite facts","E. An overview of the external buildings and areas","F. A pyramid design that others copied","G. An idea for changing the design of burial structures","H. An incredible experience despite the few remains","I. The answers to some unexpected questions"],u=["A. Stella Pachidi","B. Hamish Low","C. Ewan McGaughey"],Ye={id:"polar-bears-p1-v10",title:"Reading Passage 1: Why we need to protect polar bears",paragraphs:[{label:"A",content:"Polar bears are being increasingly threatened by the effects of climate change, but their disappearance could have far-reaching consequences. They are uniquely adapted to the extreme conditions of the Arctic Circle, where temperatures can reach -40C. One reason for this is that they have up to 11 centimetres of fat underneath their skin. Humans with comparative levels of adipose tissue would be considered obese and would be likely to suffer from diabetes and heart disease. Yet the polar bear experiences no such consequences."},{label:"B",content:"A 2014 study by Shi Ping Liu and colleagues sheds light on this mystery. They compared the genetic structure of polar bears with that of their closest relatives from a warmer climate, the brown bears. This allowed them to determine the genes that have allowed polar bears to survive in one of the toughest environments on Earth. Liu and his colleagues found the polar bears had a gene known as APoB, which reduces levels of low-density lipoproteins (LDLs) - a form of bad cholesterol. In humans, mutations of this gene are associated with increased risk of heart disease. Polar bears may therefore be an important study model to understand heart disease in humans."},{label:"C",content:"The genome of the polar bear may also provide the solution for another condition, one that particularly affects our older generation: osteoporosis. This is a disease where bones show reduced density, usually caused by insufficient exercise, reduced calcium intake or food starvation. Bone tissue is constantly being remodelled, meaning that bone is added or removed, depending on nutrient availability and the stress that the bone is under. Female polar bears, however, undergo extreme conditions during every pregnancy. Once autumn comes around, these females will dig maternity dens in the snow and will remain there throughout the winter, both before and after the birth of their cubs. This process results in about six months of fasting, where the female bears have to keep themselves and their cubs alive, depleting their own calcium and calorie reserves. Despite this, their bones remain strong and dense."},{label:"D",content:"Physiologists Alanda Lennox and Allen Goodship found an explanation for this paradox in 2008. They discovered that pregnant bears were able to increase the density of their bones before they started to build their dens. In addition, six months later, when they finally emerged from the den with their cubs, there was no evidence of significant loss of bone density. Hibernating brown bears do not have this capacity and must therefore resort to major bone reformation in the following spring. If the mechanism of bone remodelling in polar bears can be understood, many bedridden humans, and even astronauts, could potentially benefit."},{label:"E",content:"The medical benefits of the polar bear for humanity certainly have their importance in our conservation efforts, but these should not be the only factors taken into consideration. We tend to want to protect animals we think are intelligent and possess emotions, such as elephants and primates. Bears, on the other hand, seem to be perceived as stupid and in many cases violent. And yet anecdotal evidence from the field challenges those assumptions, suggesting for example that polar bears have good problem-solving abilities. A male bear called GoGo in Tennoji Zoo, Osaka, has even been observed making use of a tool to manipulate his environment. The bear used a tree branch on multiple occasions to dislodge a piece of meat hung out of his reach. Problem-solving ability has also been witnessed in wild polar bears, although not as obviously as with Gogo. A calculated move by a male bear involved running and jumping onto barrels in an attempt to get to a photographer standing on a platform four metres high."},{label:"F",content:"In other studies, such as one by Alison Ames in 2008, polar bears showed deliberate and focused manipulation. For example, Ames observed bears putting objects in piles and then knocking them over in what appeared to be a game. The study demonstrates that bears are capable of agile and thought-out behaviours. These examples suggest bears have greater creativity and problem-solving abilities than previously thought."},{label:"G",content:"As for emotions, while the evidence is once again anecdotal, many bears have been seen to hit out at ice and snow - seemingly out of frustration - when they have just missed out on a kill. Moreover, polar bears can form unusual relationships with other species, including playing with the dogs used to pull sleds in the Arctic. Remarkably, one hand-raised polar bear called Agee has formed a close relationship with her owner Mark Dumas to the point where they even swim together. This is even more astonishing since polar bears are known to actively hunt humans in the wild."},{label:"H",content:"If climate change were to lead to their extinction, this would mean not only the loss of potential breakthroughs in human medicine, but more importantly, the disappearance of an intelligent, majestic animal."}],questions:[{id:"polar-v10-q1",number:1,type:"true-false-not-given",groupTitle:"Questions 1-7",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Polar bears suffer from various health problems due to the build-up of fat under their skin.",correctAnswer:"FALSE",location:"Paragraph A"},{id:"polar-v10-q2",number:2,type:"true-false-not-given",text:"The study done by Liu and his colleagues compared different groups of polar bears.",correctAnswer:"FALSE",location:"Paragraph B"},{id:"polar-v10-q3",number:3,type:"true-false-not-given",text:"Liu and colleagues were the first researchers to compare polar bears and brown bears genetically.",correctAnswer:"NOT GIVEN",location:"Paragraph B"},{id:"polar-v10-q4",number:4,type:"true-false-not-given",text:"Polar bears are able to control their levels of bad cholesterol by genetic means.",correctAnswer:"TRUE",location:"Paragraph B"},{id:"polar-v10-q5",number:5,type:"true-false-not-given",text:"Female polar bears are able to survive for about six months without food.",correctAnswer:"TRUE",location:"Paragraph C"},{id:"polar-v10-q6",number:6,type:"true-false-not-given",text:"It was found that the bones of female polar bears were very weak when they came out of their dens in spring.",correctAnswer:"FALSE",location:"Paragraph D"},{id:"polar-v10-q7",number:7,type:"true-false-not-given",text:"The polar bear's mechanism for increasing bone density could also be used by people one day.",correctAnswer:"FALSE",location:"Paragraph D"},{id:"polar-v10-q8",number:8,type:"note-completion",groupTitle:"Questions 8-13",instruction:"Complete the notes below. Choose ONE WORD ONLY from the passage for each answer.",text:"People think of bears as unintelligent and ______.",correctAnswer:"violent",location:"Paragraph E"},{id:"polar-v10-q9",number:9,type:"note-completion",text:"In Tennoji Zoo, a bear has been seen using a branch as a ______.",correctAnswer:"tool",location:"Paragraph E"},{id:"polar-v10-q10",number:10,type:"note-completion",text:"This allowed him to knock down some ______.",correctAnswer:"meat",location:"Paragraph E"},{id:"polar-v10-q11",number:11,type:"note-completion",text:"A wild polar bear worked out a method of reaching a platform where a ______ was located.",correctAnswer:"photographer",location:"Paragraph E"},{id:"polar-v10-q12",number:12,type:"note-completion",text:"Polar bears have displayed behaviour such as conscious manipulation of objects and activity similar to a ______.",correctAnswer:"game",location:"Paragraph F"},{id:"polar-v10-q13",number:13,type:"note-completion",text:"They may make movements suggesting ______ if disappointed when hunting.",correctAnswer:"frustration",location:"Paragraph G"}]},Ke={id:"step-pyramid-p2-v10",title:"Reading Passage 2: The Step Pyramid of Djoser",paragraphs:[{label:"A",content:"The pyramids are the most famous monuments of ancient Egypt and still hold enormous interest for people in the present day. These grand, impressive tributes to the memory of the Egyptian kings have become linked with the country even though other cultures, such as the Chinese and Mayan, also built pyramids. The evolution of the pyramid form has been written and argued about for centuries. However, there is no question that, as far as Egypt is concerned, it began with one monument to one king designed by one brilliant architect: the Step Pyramid of Djoser at Saqqara."},{label:"B",content:"Djoser was the first king of the Third Dynasty of Egypt and the first to build in stone. Prior to Djosers reign, tombs were rectangular monuments made of dried clay brick, which covered underground passages where the deceased person was buried. For reasons which remain unclear, Djosers main official, whose name was Imhotep, conceived of building a taller, more impressive tomb for his king by stacking stone slabs on top of one another, progressively making them smaller, to form the shape now known as the Step Pyramid. Djoser is thought to have reigned for 19 years, but some historians and scholars attribute a much longer time for his rule, owing to the number and size of the monuments he built."},{label:"C",content:"The Step Pyramid has been thoroughly examined and investigated over the last century, and it is now known that the building process went through many different stages. Historian Marc Van de Mieroop comments on this, writing: Much experimentation was involved, which is especially clear in the construction of the pyramid in the center of the complex. It had several plans before it became the first Step Pyramid in history, piling six levels on top of one another. The weight of the enormous mass was a challenge for the builders, who placed the stones at an inward incline in order to prevent the monument breaking up."},{label:"D",content:"When finally completed, the Step Pyramid rose 62 metres high and was the tallest structure of its time. The complex in which it was built was the size of a city in ancient Egypt and included a temple, courtyards, shrines, and living quarters for the priests. It covered a region of 16 hectares and was surrounded by a wall 10.5 meters high. The wall had 13 false doors cut into it with only one true entrance cut into the south-east corner; the entire wall was then ringed by a trench 750 meters long and 40 meters wide. The false doors and the trench were incorporated into the complex to discourage unwanted visitors. If someone wished to enter, he or she would have needed to know in advance how to find the location of the true opening in the wall. Djoser was so proud of his accomplishment that he broke the tradition of having only his own name on the monument and had Imhoteps name carved on it as well."},{label:"E",content:"The burial chamber of the tomb, where the kings body was laid to rest, was dug beneath the base of the pyramid, surrounded by a vast maze of long tunnels that had rooms off them to discourage robbers. One of the most mysterious discoveries found inside the pyramid was a large number of stone vessels. Over 40,000 of these vessels, of various forms and shapes, were discovered in storerooms off the pyramids underground passages. They are inscribed with the names of rulers from the First and Second Dynasties of Egypt and made from different kinds of stone. There is no agreement among scholars and archaeologists on why the vessels were placed in the tomb of Djoser or what they were supposed to represent. The archaeologist Jean-Philippe Lauer, who excavated most of the pyramid and complex, believes they were originally stored and then given a proper burial by Djoser in his pyramid to honor his predecessors. There are other historians, however, who claim the vessels were dumped into the shafts as yet another attempt to prevent grave robbers from getting to the kings burial chamber."},{label:"F",content:"Unfortunately, all of the precautions and intricate design of the underground network did not prevent ancient robbers from finding a way in. Djosers grave goods, and even his body, were stolen at some point in the past and all archaeologists found were a small number of his valuables overlooked by the thieves. There was enough left throughout the pyramid and its complex, however, to astonish and amaze the archaeologists who excavated it."},{label:"G",content:"Egyptologist Miroslav Verner writes, Few monuments hold a place in human history as significant as that of the Step Pyramid in Saqqara. It can be said without exaggeration that this pyramid complex constitutes a milestone in the evolution of monumental stone architecture in Egypt and in the world as a whole. The Step Pyramid was a revolutionary advance in architecture and became the archetype which all the other great pyramid builders of Egypt would follow."}],questions:[{id:"step-v10-q14",number:14,type:"matching-headings",groupTitle:"Questions 14-20",instruction:"Reading Passage 2 has seven paragraphs. Choose the correct heading for each paragraph from the list of headings below.",text:"Paragraph A",options:h,correctAnswer:"D",location:"Paragraph A"},{id:"step-v10-q15",number:15,type:"matching-headings",text:"Paragraph B",options:h,correctAnswer:"G",location:"Paragraph B"},{id:"step-v10-q16",number:16,type:"matching-headings",text:"Paragraph C",options:h,correctAnswer:"B",location:"Paragraph C"},{id:"step-v10-q17",number:17,type:"matching-headings",text:"Paragraph D",options:h,correctAnswer:"E",location:"Paragraph D"},{id:"step-v10-q18",number:18,type:"matching-headings",text:"Paragraph E",options:h,correctAnswer:"A",location:"Paragraph E"},{id:"step-v10-q19",number:19,type:"matching-headings",text:"Paragraph F",options:h,correctAnswer:"H",location:"Paragraph F"},{id:"step-v10-q20",number:20,type:"matching-headings",text:"Paragraph G",options:h,correctAnswer:"F",location:"Paragraph G"},{id:"step-v10-q21",number:21,type:"note-completion",groupTitle:"Questions 21-24",instruction:"Complete the notes below. Choose ONE WORD ONLY from the passage for each answer.",text:"The complex that includes the Step Pyramid and its surroundings is considered to be as big as an Egyptian ______ of the past.",correctAnswer:"city",location:"Paragraph D"},{id:"step-v10-q22",number:22,type:"note-completion",text:"The area outside the pyramid included accommodation that was occupied by ______.",correctAnswer:"priests",location:"Paragraph D"},{id:"step-v10-q23",number:23,type:"note-completion",text:"In addition, a long ______ encircled the wall.",correctAnswer:"trench",location:"Paragraph D"},{id:"step-v10-q24",number:24,type:"note-completion",text:"As a result, any visitors who had not been invited were prevented from entering unless they knew the ______ of the real entrance.",correctAnswer:"location",location:"Paragraph D"},{id:"step-v10-q25",number:25,type:"five-true-statements",groupTitle:"Questions 25-26",instruction:"Choose TWO correct answers.",text:"Which TWO of the following points does the writer make about King Djoser?",options:["A. initially he had to be persuaded to build in stone rather than clay.","B. There is disagreement concerning the length of his reign.","C. He failed to appreciate Imhotep's part in the design of the Step Pyramid.","D. A few of his possessions were still in his tomb when archaeologists found it.","E. He criticised the design and construction of other pyramids in Egypt."],correctAnswer:["B","D"],location:"Paragraphs B and F"}]},$e={id:"future-work-p3-v10",title:"Reading Passage 3: The future of work",paragraphs:[{label:"A",content:"According to a leading business consultancy, 3-14% of the global workforce will need to switch to a different occupation within the next 10-15 years, and all workers will need to adapt as their occupations evolve alongside increasingly capable machines. Automation - or embodied artificial intelligence (AI) - is one aspect of the disruptive effects of technology on the labour market. Disembodied AI, like the algorithms running in our smartphones, is another."},{label:"B",content:"Dr Stella Pachidi from Cambridge Judge Business School believes that some of the most fundamental changes are happening as a result of the algorithmication of jobs that are dependent on data rather than on production - the so-called knowledge economy. Algorithms are capable of learning from data to undertake tasks that previously needed human judgement, such as reading legal contracts, analysing medical scans and gathering market intelligence."},{label:"C",content:"In many cases, they can outperform humans, says Pachidi. Organisations are attracted to using algorithms because they want to make choices based on what they consider is perfect information, as well as to reduce costs and enhance productivity."},{label:"D",content:"But these enhancements are not without consequences, says Pachidi. If routine cognitive tasks are taken over by AI, how do professions develop their future experts? she asks. One way of learning about a job is legitimate peripheral participation - a novice stands next to experts and learns by observation. If this is not happening, then you need to find new ways to learn."},{label:"E",content:"Another issue is the extent to which the technology influences or even controls the workforce. For over two years, Pachidi monitored a telecommunications company. The way telecoms salespeople work is through personal and frequent contact with clients, using the benefit of experience to assess a situation and reach a decision. However, the company had started using an algorithm that defined when account managers should contact certain customers about which kinds of campaigns and what to offer them."},{label:"F",content:"The algorithm - usually built by external designers - often becomes the keeper of knowledge, she explains. In cases like this, Pachidi believes, a short-sighted view begins to creep into working practices whereby workers learn through the algorithms eyes and become dependent on its instructions. Alternative explorations - where experimentation and human instinct lead to progress and new ideas - are effectively discouraged."},{label:"G",content:"Pachidi and colleagues even observed people developing strategies to make the algorithm work to their own advantage. We are seeing cases where workers feed the algorithm with false data to reach their targets, she reports."},{label:"H",content:"It is scenarios like these that many researchers are working to avoid. Their objective is to make AI technologies more trustworthy and transparent, so that organisations and individuals understand how AI decisions are made. In the meantime, says Pachidi, We need to make sure we fully understand the dilemmas that this new world raises regarding expertise, occupational boundaries and control."},{label:"I",content:"Economist Professor Hamish Low believes that the future of work will involve major transitions across the whole life course for everyone: The traditional trajectory of full-time education followed by full-time work followed by a pensioned retirement is a thing of the past, says Low. Instead, he envisages a multistage employment life: one where retraining happens across the life course, and where multiple jobs and no job happen by choice at different stages."},{label:"J",content:"On the subject of job losses, Low believes the predictions are founded on a fallacy: It assumes that the number of jobs is fixed. If in 30 years, half of 100 jobs are being carried out by robots, that does not mean we are left with just 50 jobs for humans. The number of jobs will increase: we would expect there to be 150 jobs."},{label:"K",content:"Dr Ewan McGaughey, at Cambridges Centre for Business Research and Kings College London, agrees that apocalyptic views about the future of work are misguided. It is the laws that restrict the supply of capital to the job market, not the advent of new technologies that causes unemployment."},{label:"L",content:"His recently published research answers the question of whether automation, AI and robotics will mean a jobless future by looking at the causes of unemployment. History is clear that change can mean redundancies. But social policies can tackle this through retraining and redeployment."},{label:"M",content:"He adds: If there is going to be change to jobs as a result of AI and robotics then Id like to see governments seizing the opportunity to improve policy to enforce good job security. We can reprogramme the law to prepare for a fairer future of work and leisure. McGaughey's findings are a call to arms to leaders of organisations, governments and banks to pre-empt the coming changes with bold new policies that guarantee full employment, fair incomes and a thriving economic democracy."},{label:"N",content:"The promises of these new technologies are astounding. They deliver humankind the capacity to live in a way that nobody could have once imagined, he adds. Just as the industrial revolution brought people past subsistence agriculture, and the corporate revolution enabled mass production, a third revolution has been pronounced. But it will not only be one of technology. The next revolution will be social."}],questions:[{id:"future-v10-q27",number:27,type:"multiple-choice",groupTitle:"Question 27",instruction:"Choose the correct answer.",text:"The first paragraph tells us about",options:["the kinds of jobs that will be most affected by the growth of AI","the extent to which AI will alter the nature of the work that people do","the proportion of the world's labour force who will have jobs in AI in the future","the difference between ways that embodied and disembodied AI will impact on workers"],correctAnswer:"B",location:"Paragraph A"},{id:"future-v10-q28",number:28,type:"multiple-choice",groupTitle:"Question 28",instruction:"Choose the correct answer.",text:"According to the second paragraph, what is Stella Pachidi's view of the knowledge economy?",options:["It is having an influence on the number of jobs available.","It is changing people's attitudes towards their occupations.","It is the main reason why the production sector is declining.","It is a key factor driving current developments in the workplace."],correctAnswer:"D",location:"Paragraph B"},{id:"future-v10-q29",number:29,type:"multiple-choice",groupTitle:"Question 29",instruction:"Choose the correct answer.",text:"What did Pachidi observe at the telecommunications company?",options:["staff disagreeing with the recommendations of AI","staff feeling resentful about the intrusion of AI in their work","staff making sure that AI produces the results that they want","staff allowing AI to carry out tasks they ought to do themselves"],correctAnswer:"C",location:"Paragraph G"},{id:"future-v10-q30",number:30,type:"multiple-choice",groupTitle:"Question 30",instruction:"Choose the correct answer.",text:"In his recently published research, Ewan McGaughey",options:["challenges the idea that redundancy is a negative thing","shows the profound effect of mass unemployment on society","highlights some differences between past and future job losses","illustrates how changes in the job market can be successfully handled"],correctAnswer:"D",location:"Paragraph L"},{id:"future-v10-q31",number:31,type:"drag-drop-summary",groupTitle:"Questions 31-34",instruction:"Complete the summary by dragging the correct words into the gaps.",text:`Stella Pachidi of Cambridge Judge Business School has been focusing on the algorithmication of jobs which rely not on production but on ______.
While monitoring a telecommunications company, Pachidi observed a growing ______ on the recommendations made by AI, as workers begin to learn through the algorithm's eyes.
Meanwhile, staff are deterred from experimenting and using their own ______, and are therefore prevented from achieving innovation.
To avoid the kind of situations which Pachidi observed, researchers are trying to make AI's decision-making process easier to comprehend, and to increase users' ______ with regard to the technology.`,options:["pressure","satisfaction","intuition","promotion","reliance","confidence","information"],correctAnswer:["information","reliance","intuition","confidence"],location:"Paragraphs B-H"},{id:"future-v10-q35",number:35,type:"matching-information",groupTitle:"Questions 35-40",instruction:"Match each statement with the correct person. NB You may use any letter more than once.",text:"Greater levels of automation will not result in lower employment.",options:u,correctAnswer:"B",location:"Paragraph J"},{id:"future-v10-q36",number:36,type:"matching-information",text:"There are several reasons why AI is appealing to businesses.",options:u,correctAnswer:"A",location:"Paragraph C"},{id:"future-v10-q37",number:37,type:"matching-information",text:"AI's potential to transform people's lives has parallels with major cultural shifts which occurred in previous eras.",options:u,correctAnswer:"C",location:"Paragraph N"},{id:"future-v10-q38",number:38,type:"matching-information",text:"It is important to be aware of the range of problems that AI causes.",options:u,correctAnswer:"A",location:"Paragraph H"},{id:"future-v10-q39",number:39,type:"matching-information",text:"People are going to follow a less conventional career path than in the past.",options:u,correctAnswer:"B",location:"Paragraph I"},{id:"future-v10-q40",number:40,type:"matching-information",text:"Authorities should take measures to ensure that there will be adequately paid work for everyone.",options:u,correctAnswer:"C",location:"Paragraph M"}]},Ze={id:"ielts-reading-full-vol10",title:"IELTS Reading Full Test 10 - Polar bears, Step Pyramid of Djoser, The future of work",type:"Academic",module:"Reading",duration:60,totalQuestions:40,sections:[Ye,Ke,$e]},r=["A","B","C","D","E","F","G"],p=["A. both Chinese and Japanese pagodas","B. only Chinese pagodas","C. only Japanese pagodas"],O=["A. MIRTP as a future model","B. Identifying the main transport problems","C. Preference for motorised vehicles","D. Government authorities' instructions","E. Initial improvements in mobility and transport modes","F. Request for improved transport in Makete","G. Transport improvements in the northern part of the district","H. Improvements in the rail network","I. Effects of initial MIRTP measures","J. Co-operation of district officials","K. Role of wheelbarrows and donkeys"],N=["A. provided the people of Makete with experience in running bus and truck services.","B. was especially successful in the northern part of the district.","C. differed from earlier phases in that the community became less actively involved.","D. improved paths used for transport up and down hillsides.","E. was no longer a problem once the roads had been improved.","F. cost less than locally made wheelbarrows.","G. was done only at the request of local people who were willing to lend a hand.","H. was at first considered by MIRTP to be affordable for the people of the district.","I. hindered attempts to make the existing transport services more efficient.","J. was thought to be the most important objective of Phase III."],F=["A. be discouraged by difficulties.","B. travel on open land where they can look out for predators.","C. eat more than they need for immediate purposes.","D. be repeated daily.","E. ignore distractions.","F. be governed by the availability of water.","G. follow a straight line."],l=["A. The areas and artefacts within the pyramid itself","B. A difficult task for those involved","C. A king who saved his people","D. A single certainty among other less definite facts","E. An overview of the external buildings and areas","F. A pyramid design that others copied","G. An idea for changing the design of burial structures","H. An incredible experience despite the few remains","I. The answers to some unexpected questions"],Xe=["A. Initially he had to be persuaded to build in stone rather than clay.","B. There is disagreement concerning the length of his reign.","C. He failed to appreciate Imhotep's part in the design of the Step Pyramid.","D. A few of his possessions were still in his tomb when archaeologists found it.","E. He criticised the design and construction of other pyramids in Egypt."],et=["pressure","satisfaction","intuition","promotion","reliance","confidence","information"],m=["A Stella Pachidi","B Hamish Low","C Ewan McGaughey"],tt=[{id:"day14-q1",number:1,type:"yes-no-not-given",groupTitle:"Questions 1-4",instruction:"Choose YES if the statement agrees with the information in the text, choose NO if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Only two Japanese pagodas have collapsed in 1400 years.",correctAnswer:"YES",location:"Paragraph A"},{id:"day14-q2",number:2,type:"yes-no-not-given",text:"The Hanshin earthquake of 1995 destroyed the pagoda at the Toji temple.",correctAnswer:"NO",location:"Paragraph A"},{id:"day14-q3",number:3,type:"yes-no-not-given",text:"The other buildings near the Toji pagoda had been built in the last 30 years.",correctAnswer:"NOT GIVEN",location:"Paragraph A"},{id:"day14-q4",number:4,type:"yes-no-not-given",text:"The builders of pagodas knew how to absorb some of the power produced by severe weather conditions.",correctAnswer:"YES",location:"Paragraphs E-F"},{id:"day14-q5",number:5,type:"matching-information",groupTitle:"Questions 5-10",instruction:"Classify the following as typical of A, B or C.",text:"easy interior access to top",options:p,correctAnswer:"B",location:"Paragraph C"},{id:"day14-q6",number:6,type:"matching-information",text:"tiles on eaves",options:p,correctAnswer:"A",location:"Paragraph D"},{id:"day14-q7",number:7,type:"matching-information",text:"use as observation post",options:p,correctAnswer:"B",location:"Paragraph C"},{id:"day14-q8",number:8,type:"matching-information",text:"size of eaves up to half the width of the building",options:p,correctAnswer:"C",location:"Paragraph D"},{id:"day14-q9",number:9,type:"matching-information",text:"original religious purpose",options:p,correctAnswer:"A",location:"Paragraph C"},{id:"day14-q10",number:10,type:"matching-information",text:"floors fitting loosely over each other",options:p,correctAnswer:"C",location:"Paragraph F"},{id:"day14-q11",number:11,type:"multiple-choice",groupTitle:"Question 11",instruction:"Choose the correct answer.",text:"In a Japanese pagoda, the shinbashira",options:["bears the full weight of the building.","bends under pressure like a tree.","connects the floors with the foundations.","stops the floors moving too far."],correctAnswer:"D",location:"Paragraph F"},{id:"day14-q12",number:12,type:"multiple-choice",groupTitle:"Question 12",instruction:"Choose the correct answer.",text:"Shuzo Ishida performs experiments in order to",options:["improve skyscraper design.","be able to build new pagodas.","learn about the dynamics of pagodas.","understand ancient mathematics."],correctAnswer:"C",location:"Paragraph F"},{id:"day14-q13",number:13,type:"multiple-choice",groupTitle:"Question 13",instruction:"Choose the correct answer.",text:"The storeys of a Japanese pagoda are",options:["linked only by wood.","fastened only to the central pillar.","fitted loosely on top of each other.","joined by special weights."],correctAnswer:"C",location:"Paragraph G"}],at=[{id:"day15-q14",number:14,type:"matching-information",groupTitle:"Questions 14-17",instruction:"Reading Passage 2 has seven paragraphs. Which paragraph contains the following information? NB You may use any letter more than once.",text:"a cost involved in purifying domestic water",options:r,correctAnswer:"E",location:"Paragraph E"},{id:"day15-q15",number:15,type:"matching-information",text:"the stages in the development of the farming industry",options:r,correctAnswer:"B",location:"Paragraph B"},{id:"day15-q16",number:16,type:"matching-information",text:"the term used to describe hidden costs",options:r,correctAnswer:"C",location:"Paragraph C"},{id:"day15-q17",number:17,type:"matching-information",text:"one effect of chemicals on water sources",options:r,correctAnswer:"B",location:"Paragraph B"},{id:"day15-q18",number:18,type:"yes-no-not-given",groupTitle:"Questions 18-21",instruction:"Choose YES if the statement agrees with the information in the text, choose NO if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Several species of wildlife in the British countryside are declining.",correctAnswer:"YES",location:"Paragraph B"},{id:"day15-q19",number:19,type:"yes-no-not-given",text:"The taste of food has deteriorated in recent years.",correctAnswer:"NOT GIVEN",location:"Paragraphs A-G"},{id:"day15-q20",number:20,type:"yes-no-not-given",text:"The financial costs of environmental damage are widely recognised.",correctAnswer:"NO",location:"Paragraph C"},{id:"day15-q21",number:21,type:"yes-no-not-given",text:"One of the costs calculated by Professor Pretty was illness caused by food.",correctAnswer:"YES",location:"Paragraph E"},{id:"day15-q22",number:22,type:"summary-completion",groupTitle:"Questions 22-26",instruction:"Complete the summary below. Choose NO MORE THAN THREE WORDS from the passage for each answer.",text:"Professor Pretty concludes that our ______ are higher than most people realise, because we make three different types of payment.",correctAnswer:"food bills",location:"Paragraph E"},{id:"day15-q23",number:23,type:"summary-completion",text:"He feels it is realistic to suggest that Britain should reduce its reliance on ______.",correctAnswer:"intensive farming",location:"Paragraph F"},{id:"day15-q24",number:24,type:"summary-completion",text:"Although most farmers would be unable to adapt to ______, Professor Pretty wants the government to initiate change.",correctAnswer:"organic farming",location:"Paragraph G"},{id:"day15-q25",number:25,type:"summary-completion",text:"He recommends establishing what he refers to as a ______.",correctAnswer:"Greener Food Standard",location:"Paragraph G"},{id:"day15-q26",number:26,type:"summary-completion",text:"He feels this would help to change the attitudes of both farmers and ______.",correctAnswer:"consumers",location:"Paragraph G"}],ot=[{id:"day16-q27",number:27,type:"matching-headings",groupTitle:"Questions 27-30",instruction:"Reading Passage 3 has six sections. Choose the correct heading for each section from the list of headings below.",text:"Section B",options:O,correctAnswer:"B",location:"Section B"},{id:"day16-q28",number:28,type:"matching-headings",text:"Section C",options:O,correctAnswer:"E",location:"Section C"},{id:"day16-q29",number:29,type:"matching-headings",text:"Section E",options:O,correctAnswer:"J",location:"Section E"},{id:"day16-q30",number:30,type:"matching-headings",text:"Section F",options:O,correctAnswer:"A",location:"Section F"},{id:"day16-q31",number:31,type:"yes-no-not-given",groupTitle:"Questions 31-35",instruction:"Choose YES if the statement agrees with the information in the text, choose NO if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"MIRTP was divided into five phases.",correctAnswer:"NO",location:"Sections A-D"},{id:"day16-q32",number:32,type:"yes-no-not-given",text:"Prior to the start of MIRTP the Makete district was almost inaccessible during the rainy season.",correctAnswer:"YES",location:"Section B"},{id:"day16-q33",number:33,type:"yes-no-not-given",text:"Phase I of MIRTP consisted of a survey of household expenditure on transport.",correctAnswer:"NO",location:"Section B"},{id:"day16-q34",number:34,type:"yes-no-not-given",text:"The survey concluded that one-fifth or 20% of the household transport requirement was outside the local area.",correctAnswer:"YES",location:"Section B"},{id:"day16-q35",number:35,type:"yes-no-not-given",text:"MIRTP hoped to improve the movement of goods from Makete district to the country's capital.",correctAnswer:"NOT GIVEN",location:"Sections A-F"},{id:"day16-q36",number:36,type:"matching-information",groupTitle:"Questions 36-39",instruction:"Complete each sentence with the correct ending, A-J, below.",text:"Construction of footbridges, steps and handrails",options:N,correctAnswer:"D",location:"Section C"},{id:"day16-q37",number:37,type:"matching-information",text:"Frequent breakdown of buses and trucks in Makete",options:N,correctAnswer:"I",location:"Section D"},{id:"day16-q38",number:38,type:"matching-information",text:"The improvement of secondary roads and paths",options:N,correctAnswer:"G",location:"Section D"},{id:"day16-q39",number:39,type:"matching-information",text:"The isolation of Makete for part of year",options:N,correctAnswer:"E",location:"Section D"},{id:"day16-q40",number:40,type:"multiple-choice",groupTitle:"Question 40",instruction:"Choose the correct answer.",text:"Which of the following phrases best describes the main aim of Reading Passage 3?",options:["to suggest that projects such as MIRTP are needed in other countries","to describe how MIRTP was implemented and how successful it was","to examine how MIRTP promoted the use of donkeys","to warn that projects such as MIRTP are likely to have serious problems"],correctAnswer:"B",location:"Whole passage"}],nt=[{id:"day17-q1",number:1,type:"note-completion",groupTitle:"Questions 1-9",instruction:"Complete the notes below. Choose ONE WORD ONLY from the passage for each answer.",text:"Silkworm cocoon fell into emperor's wife's ______.",correctAnswer:"tea",location:"Paragraph A"},{id:"day17-q2",number:2,type:"note-completion",text:"Emperor's wife invented a ______ to pull out silk fibres.",correctAnswer:"reel",location:"Paragraph A"},{id:"day17-q3",number:3,type:"note-completion",text:"Only ______ were allowed to produce silk.",correctAnswer:"women",location:"Paragraph B"},{id:"day17-q4",number:4,type:"note-completion",text:"Only ______ were allowed to wear silk.",correctAnswer:"royalty",location:"Paragraph B"},{id:"day17-q5",number:5,type:"note-completion",text:"Silk was used as a form of ______.",correctAnswer:"currency",location:"Paragraph B"},{id:"day17-q6",number:6,type:"note-completion",text:"Evidence found of ______ made from silk around 168 AD.",correctAnswer:"paper",location:"Paragraph B"},{id:"day17-q7",number:7,type:"note-completion",text:"Merchants used the Silk Road to take silk westward and bring back ______ and precious metals.",correctAnswer:"wool",location:"Paragraph C"},{id:"day17-q8",number:8,type:"note-completion",text:"550 AD: ______ hid silkworm eggs in canes and took them to Constantinople.",correctAnswer:"monks",location:"Paragraph D"},{id:"day17-q9",number:9,type:"note-completion",text:"20th century: ______ and other manmade fibres caused decline in silk production.",correctAnswer:"nylon",location:"Paragraph F"},{id:"day17-q10",number:10,type:"true-false-not-given",groupTitle:"Questions 10-13",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Gold was the most valuable material transported along the Silk Road.",correctAnswer:"FALSE",location:"Paragraph C"},{id:"day17-q11",number:11,type:"true-false-not-given",text:"Most tradesmen only went along certain sections of the Silk Road.",correctAnswer:"TRUE",location:"Paragraph C"},{id:"day17-q12",number:12,type:"true-false-not-given",text:"The Byzantines spread the practice of silk production across the West.",correctAnswer:"FALSE",location:"Paragraph D"},{id:"day17-q13",number:13,type:"true-false-not-given",text:"Silk yarn makes up the majority of silk currently exported from China.",correctAnswer:"NOT GIVEN",location:"Paragraph F"}],it=[{id:"day18-q14",number:14,type:"true-false-not-given",groupTitle:"Questions 14-18",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Local gulls and migrating arctic terns behave in the same way when offered food.",correctAnswer:"FALSE",location:"Paragraph B"},{id:"day18-q15",number:15,type:"true-false-not-given",text:"Experts' definitions of migration tend to vary according to their area of study.",correctAnswer:"TRUE",location:"Paragraph D"},{id:"day18-q16",number:16,type:"true-false-not-given",text:"Very few experts agree that the movement of aphids can be considered migration.",correctAnswer:"NOT GIVEN",location:"Paragraph E"},{id:"day18-q17",number:17,type:"true-false-not-given",text:"Aphids' journeys are affected by changes in the light that they perceive.",correctAnswer:"TRUE",location:"Paragraph F"},{id:"day18-q18",number:18,type:"true-false-not-given",text:"Dingle's aim is to distinguish between the migratory behaviours of different species.",correctAnswer:"FALSE",location:"Paragraph F"},{id:"day18-q19",number:19,type:"matching-information",groupTitle:"Questions 19-22",instruction:"Complete each sentence with the correct ending, A-G, below.",text:"According to Dingle, migratory routes are likely to",options:F,correctAnswer:"G",location:"Paragraph A"},{id:"day18-q20",number:20,type:"matching-information",text:"To prepare for migration, animals are likely to",options:F,correctAnswer:"C",location:"Paragraph F"},{id:"day18-q21",number:21,type:"matching-information",text:"During migration, animals are unlikely to",options:F,correctAnswer:"A",location:"Paragraph A"},{id:"day18-q22",number:22,type:"matching-information",text:"Arctic terns illustrate migrating animals' ability to",options:F,correctAnswer:"E",location:"Paragraph B"},{id:"day18-q23",number:23,type:"summary-completion",groupTitle:"Questions 23-26",instruction:"Complete the summary below. Choose ONE WORD ONLY from the passage for each answer.",text:"Pronghorns rely on their eyesight and ______ to avoid predators.",correctAnswer:"speed",location:"Paragraph G"},{id:"day18-q24",number:24,type:"summary-completion",text:"Their winter home is on the ______, where they avoid deep snow.",correctAnswer:"plains",location:"Paragraph G"},{id:"day18-q25",number:25,type:"summary-completion",text:"Their route between the two homes contains three ______.",correctAnswer:"bottlenecks",location:"Paragraph G"},{id:"day18-q26",number:26,type:"summary-completion",text:"One problem is construction of new homes in a narrow ______ of land on the route.",correctAnswer:"corridor",location:"Paragraph G"}],rt=[{id:"day19-q27",number:27,type:"matching-information",groupTitle:"Questions 27-34",instruction:"Reading Passage 3 has seven sections. Which section contains the following information? NB You may use any letter more than once.",text:"a reference to books that assume a lack of mathematical knowledge",options:r,correctAnswer:"D",location:"Section D"},{id:"day19-q28",number:28,type:"matching-information",text:"the way in which this is not a typical book about mathematics",options:r,correctAnswer:"B",location:"Section B"},{id:"day19-q29",number:29,type:"matching-information",text:"personal examples of being helped by mathematics",options:r,correctAnswer:"G",location:"Section G"},{id:"day19-q30",number:30,type:"matching-information",text:"examples of people who each had abilities that seemed incompatible",options:r,correctAnswer:"C",location:"Section C"},{id:"day19-q31",number:31,type:"matching-information",text:"mention of different focuses of books about mathematics",options:r,correctAnswer:"B",location:"Section B"},{id:"day19-q32",number:32,type:"matching-information",text:"a contrast between reading this book and reading other kinds of publication",options:r,correctAnswer:"E",location:"Section E"},{id:"day19-q33",number:33,type:"matching-information",text:"a claim that the whole of the book is accessible to everybody",options:r,correctAnswer:"A",location:"Section A"},{id:"day19-q34",number:34,type:"matching-information",text:"a reference to different categories of intended readers of this book",options:r,correctAnswer:"F",location:"Section F"},{id:"day19-q35",number:35,type:"summary-completion",groupTitle:"Questions 35-40",instruction:"Complete the sentences below. Choose ONE WORD ONLY from the passage for each answer.",text:"Some areas of both music and mathematics are suitable for someone who is a ______.",correctAnswer:"beginner",location:"Section A"},{id:"day19-q36",number:36,type:"summary-completion",text:"It is sometimes possible to understand advanced mathematics using no more than a limited knowledge of ______.",correctAnswer:"arithmetic",location:"Section A"},{id:"day19-q37",number:37,type:"summary-completion",text:"The writer intends to show that mathematics requires ______ thinking, as well as analytical skills.",correctAnswer:"intuitive",location:"Section C"},{id:"day19-q38",number:38,type:"summary-completion",text:"Some books written by ______ have had to leave out the mathematics that is central to their theories.",correctAnswer:"scientists",location:"Section D"},{id:"day19-q39",number:39,type:"summary-completion",text:"The writer advises non-mathematical readers to perform ______ while reading the book.",correctAnswer:"experiments",location:"Section E"},{id:"day19-q40",number:40,type:"summary-completion",text:"A lawyer found that studying ______ helped even more than other areas of mathematics in the study of law.",correctAnswer:"theorems",location:"Section G"}],st=[{id:"day21-q1",number:1,type:"true-false-not-given",groupTitle:"Questions 1-7",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Polar bears suffer from various health problems due to the build-up of fat under their skin.",correctAnswer:"FALSE",location:"Paragraph A"},{id:"day21-q2",number:2,type:"true-false-not-given",text:"The study done by Liu and his colleagues compared different groups of polar bears.",correctAnswer:"FALSE",location:"Paragraph B"},{id:"day21-q3",number:3,type:"true-false-not-given",text:"Liu and colleagues were the first researchers to compare polar bears and brown bears genetically.",correctAnswer:"NOT GIVEN",location:"Paragraph B"},{id:"day21-q4",number:4,type:"true-false-not-given",text:"Polar bears are able to control their levels of 'bad' cholesterol by genetic means.",correctAnswer:"TRUE",location:"Paragraph B"},{id:"day21-q5",number:5,type:"true-false-not-given",text:"Female polar bears are able to survive for about six months without food.",correctAnswer:"TRUE",location:"Paragraph C"},{id:"day21-q6",number:6,type:"true-false-not-given",text:"It was found that the bones of female polar bears were very weak when they came out of their dens in spring.",correctAnswer:"FALSE",location:"Paragraph D"},{id:"day21-q7",number:7,type:"true-false-not-given",text:"The polar bear's mechanism for increasing bone density could also be used by people one day.",correctAnswer:"FALSE",location:"Paragraph D"},{id:"day21-q8",number:8,type:"summary-completion",groupTitle:"Questions 8-13",instruction:"Complete the notes below. Choose ONE WORD ONLY from the passage for each answer.",text:"People think of bears as unintelligent and ______.",correctAnswer:"violent",location:"Paragraph E"},{id:"day21-q9",number:9,type:"summary-completion",text:"In Tennoji Zoo, a bear has been seen using a branch as a ______.",correctAnswer:"tool",location:"Paragraph E"},{id:"day21-q10",number:10,type:"summary-completion",text:"This allowed him to knock down some ______.",correctAnswer:"meat",location:"Paragraph E"},{id:"day21-q11",number:11,type:"summary-completion",text:"A wild polar bear worked out a method of reaching a platform where a ______ was located.",correctAnswer:"photographer",location:"Paragraph E"},{id:"day21-q12",number:12,type:"summary-completion",text:"Polar bears have displayed behaviour such as conscious manipulation of objects and activity similar to a ______.",correctAnswer:"game",location:"Paragraph F"},{id:"day21-q13",number:13,type:"summary-completion",text:"They may make movements suggesting ______ if disappointed when hunting.",correctAnswer:"frustration",location:"Paragraph G"}],ht=[{id:"day22-q14",number:14,type:"matching-headings",groupTitle:"Questions 14-20",instruction:"Reading Passage 2 has seven paragraphs. Choose the correct heading for each paragraph from the list of headings below.",text:"Paragraph 1",options:l,correctAnswer:"D",location:"Paragraph 1"},{id:"day22-q15",number:15,type:"matching-headings",text:"Paragraph 2",options:l,correctAnswer:"G",location:"Paragraph 2"},{id:"day22-q16",number:16,type:"matching-headings",text:"Paragraph 3",options:l,correctAnswer:"B",location:"Paragraph 3"},{id:"day22-q17",number:17,type:"matching-headings",text:"Paragraph 4",options:l,correctAnswer:"E",location:"Paragraph 4"},{id:"day22-q18",number:18,type:"matching-headings",text:"Paragraph 5",options:l,correctAnswer:"A",location:"Paragraph 5"},{id:"day22-q19",number:19,type:"matching-headings",text:"Paragraph 6",options:l,correctAnswer:"H",location:"Paragraph 6"},{id:"day22-q20",number:20,type:"matching-headings",text:"Paragraph 7",options:l,correctAnswer:"F",location:"Paragraph 7"},{id:"day22-q21",number:21,type:"summary-completion",groupTitle:"Questions 21-24",instruction:"Complete the notes below. Choose ONE WORD ONLY from the passage for each answer.",text:"The complex that included the Step Pyramid and its surroundings is considered to be as big as an Egyptian ______ of the past.",correctAnswer:"city",location:"Paragraph 4"},{id:"day22-q22",number:22,type:"summary-completion",text:"The area outside the pyramid included accommodation occupied by ______.",correctAnswer:"priests",location:"Paragraph 4"},{id:"day22-q23",number:23,type:"summary-completion",text:"A long ______ encircled the wall.",correctAnswer:"trench",location:"Paragraph 4"},{id:"day22-q24",number:24,type:"summary-completion",text:"Visitors could only enter the pyramid grounds if they knew the ______ of the real entrance.",correctAnswer:"location",location:"Paragraph 4"},{id:"day22-q25",number:25,type:"five-true-statements",groupTitle:"Questions 25-26",instruction:"Choose TWO correct answers.",text:"Which TWO of the following points does the writer make about King Djoser?",options:Xe,correctAnswer:["B","D"],location:"Paragraphs 2 and 6"}],lt=[{id:"day23-q27",number:27,type:"multiple-choice",groupTitle:"Question 27",instruction:"Choose the correct answer.",text:"The first paragraph tells us about",options:["the kinds of jobs that will be most affected by the growth of AI.","the extent to which AI will alter the nature of the work that people do.","the proportion of the world's labour force who will have jobs in AI in the future.","the difference between ways that embodied and disembodied AI will impact on workers."],correctAnswer:"B",location:"Paragraph A"},{id:"day23-q28",number:28,type:"multiple-choice",groupTitle:"Question 28",instruction:"Choose the correct answer.",text:"According to the second paragraph, what is Stella Pachidi's view of the 'knowledge economy'?",options:["It is having an influence on the number of jobs available.","It is changing people's attitudes towards their occupations.","It is the main reason why the production sector is declining.","It is a key factor driving current developments in the workplace."],correctAnswer:"D",location:"Paragraph B"},{id:"day23-q29",number:29,type:"multiple-choice",groupTitle:"Question 29",instruction:"Choose the correct answer.",text:"What did Pachidi observe at the telecommunications company?",options:["staff disagreeing with the recommendations of AI","staff feeling resentful about the intrusion of AI in their work","staff making sure that AI produces the results that they want","staff allowing AI to carry out tasks they ought to do themselves"],correctAnswer:"C",location:"Paragraph F"},{id:"day23-q30",number:30,type:"multiple-choice",groupTitle:"Question 30",instruction:"Choose the correct answer.",text:"In his recently published research, Ewan McGaughey",options:["challenges the idea that redundancy is a negative thing.","shows the profound effect of mass unemployment on society.","highlights some differences between past and future job losses.","illustrates how changes in the job market can be successfully handled."],correctAnswer:"D",location:"Paragraphs J-K"},{id:"day23-q31",number:31,type:"drag-drop-summary",groupTitle:"Questions 31-34",instruction:"Complete the summary by dragging the correct words into the gaps.",text:`Stella Pachidi has been focusing on the 'algorithmication' of jobs which rely not on production but on ______.
While monitoring a telecommunications company, she observed a growing ______ on recommendations made by AI.
Meanwhile, staff are deterred from experimenting and using their own ______.
Researchers are trying to make AI's decision-making easier to comprehend, and to increase users' ______ with regard to the technology.`,options:et,correctAnswer:["information","reliance","intuition","confidence"],location:"Paragraphs B-H"},{id:"day23-q35",number:35,type:"matching-information",groupTitle:"Questions 35-40",instruction:"Match each statement with the correct person. NB You may use any letter more than once.",text:"Greater levels of automation will not result in lower employment.",options:m,correctAnswer:"B",location:"Paragraph I"},{id:"day23-q36",number:36,type:"matching-information",text:"There are several reasons why AI is appealing to businesses.",options:m,correctAnswer:"A",location:"Paragraph C"},{id:"day23-q37",number:37,type:"matching-information",text:"AI's potential to transform people's lives has parallels with major cultural shifts which occurred in previous eras.",options:m,correctAnswer:"C",location:"Paragraph L"},{id:"day23-q38",number:38,type:"matching-information",text:"It is important to be aware of the range of problems that AI causes.",options:m,correctAnswer:"A",location:"Paragraph H"},{id:"day23-q39",number:39,type:"matching-information",text:"People are going to follow a less conventional career path than in the past.",options:m,correctAnswer:"B",location:"Paragraph I"},{id:"day23-q40",number:40,type:"matching-information",text:"Authorities should take measures to ensure that there will be adequately paid work for everyone.",options:m,correctAnswer:"C",location:"Paragraph K"}],ct={id:"day14-pagodas-p1",title:"Day 14 Passage 1: Why pagodas don't fall down",paragraphs:[{label:"A",content:"In a land swept by typhoons and shaken by earthquakes, how has Japan's tallest and seemingly flimsiest old buildings - 500 or so wooden pagodas - remained standing for centuries? Records show that only two have collapsed during the past 1400 years. Those that have disappeared were destroyed by fire as a result of lightning or civil war. The disastrous Hanshin earthquake in 1995 killed 6,400 people, toppled elevated highways, flattened office blocks and devastated the port area of Kobe. Yet it left the magnificent five-storey pagoda at the Toji temple in nearby Kyoto unscathed, though it levelled a number of buildings in the neighbourhood."},{label:"B",content:"Japanese scholars have been mystified for ages about why these tall, slender buildings are so stable. It was only thirty years ago that the building industry felt confident enough to erect office blocks of steel and reinforced concrete that had more than a dozen floors. With its special shock absorbers to dampen the effect of sudden sideways movements from an earthquake, the thirty-six-storey Kasumigaseki building in central Tokyo - Japan's first skyscraper - was considered a masterpiece of modern engineering when it was built in 1968. Yet in 826, with only pegs and wedges to keep his wooden structure upright, the master builder Kobodaishi had no hesitation in sending his majestic Toji pagoda soaring fifty-five meters into the sky - nearly half as high as the Kasumigaseki skyscraper built some eleven centuries later. Clearly, Japanese carpenters of the day knew a few tricks about allowing a building to sway and settle itself rather than fight nature's forces. But what sort of tricks?"},{label:"C",content:"The multi-storey pagoda came to Japan from China in the sixth century. As in China, they were first introduced with Buddhism and were attached to important temples. The Chinese built their pagodas in brick or stone, with inner staircases, and used them in later centuries mainly as watchtowers. When the pagoda reached Japan, however, its architecture was freely adapted to local conditions - they were built less high, typically five rather than nine storeys, made mainly of wood and the staircase was dispensed with because the Japanese pagoda did not have any practical use but became more of an art object. Because of the typhoons that batter Japan in the summer, Japanese builders learned to extend the eaves of buildings further beyond the walls. This prevents rainwater gushing down the walls."},{label:"D",content:"Pagodas in China and Korea have nothing like the overhang that is found on pagodas in Japan. The roof of a Japanese temple building can be made to overhang the sides of the structure by fifty percent or more of the building's overall width. For the same reason, the builders of Japanese pagodas seem to have further increased their weight by choosing to cover these extended eaves not with the porcelain tiles of many Chinese pagodas but with much heavier earthenware tiles."},{label:"E",content:"But this does not totally explain the great resilience of Japanese pagodas. Is the answer that, like a tall pine tree, the Japanese pagoda - with its massive trunk-like central pillar known as shinbashira - simply flexes and sways during a typhoon or earthquake? For centuries, many thought so. But the answer is not so simple because the startling thing is that the shinbashira actually carries no load at all. In fact, in some pagoda designs, it does not even rest on the ground, but is suspended from the top of the pagoda - hanging loosely down through the middle of the building. The weight of the building is supported entirely by twelve outer and four inner columns."},{label:"F",content:"And what is the role of the shinbashira, the central pillar? The best way to understand the shinbashira's role is to watch a video made by Shuzo Ishida, a structural engineer at Kyoto Institute of Technology. Mr Ishida, known to his students as 'Professor Pagoda' because of his passion to understand the pagoda, has built a series of models and tested them on a shake-table in his laboratory. In short, the shinbashira was acting like an enormous stationary pendulum. The ancient craftsmen, apparently without the assistance of very advanced mathematics, seemed to grasp the principles that were, more than a thousand years later, applied in the construction of Japan's first skyscraper. What those early craftsmen had found by trial and error was that under pressure a pagoda's loose stack of floors could be made to slither to and fro independent of one another. Viewed from the side, the pagoda seemed to be doing a snake dance - with each consecutive floor moving in the opposite direction to its neighbours above and below. The shinbashira, running up through a hole in the centre of the building, constrained individual storeys from moving too far because, after moving a certain distance, they banged into it, transmitting energy away along the column."},{label:"G",content:`Another strange feature of the Japanese pagoda is that, because the building tapers, with each successive floor plan being smaller than the one below, none of the vertical pillars that carry the weight of the building is connected to its corresponding pillar above. In other words, a five-storey pagoda contains not even one pillar that travels right up through the building to carry the structural loads from the top to the bottom. More surprising is the fact that the individual storeys of a Japanese pagoda, unlike their counterparts elsewhere, are not actually connected to each other. They are simply stacked one on top of another like a pile of hats. Interestingly, such a design would not be permitted under current Japanese building regulations. And the extra-wide eaves? Think of them as a tightrope walker's balancing pole. The bigger the mass at each end of the pole, the easier it is for the tightrope walker to maintain his or her balance. The same holds true for a pagoda. "With the eaves extending out on all sides like balancing poles," says Mr Ishida, "the building responds to even the most powerful jolt of an earthquake with a graceful swaying, never an abrupt shaking." Here again, Japanese master builders of a thousand years ago anticipated concepts of modern structural engineering.`}],questions:tt},dt={id:"day15-true-cost-food-p2",title:"Day 15 Passage 2: The True Cost of Food",paragraphs:[{label:"A",content:"For more than forty years, concern over the cost of food has intensified. Although food may appear cheaper to buy in many developed countries than in 1960, the real cost includes hidden damage linked to industrial agriculture."},{label:"B",content:"Over recent decades, farming progressed through mechanisation, heavy fertiliser and pesticide use, monocultures, intensive livestock systems, and genetic engineering. While yields rose, major ecological damage followed: declines in birds, flowers and insects, disappearance of hedgerows and ponds, and worsening water quality due to agricultural runoff."},{label:"C",content:"Consumers often fail to connect these effects to what they buy because many costs are 'externalities' - hidden costs outside normal market transactions, borne by society rather than directly by buyers or producers."},{label:"D",content:"Professor Jules Pretty and colleagues at the University of Essex quantified these externalities for British agriculture and found that total annual costs were extremely high, even on conservative estimates."},{label:"E",content:"The estimated costs included water purification, habitat damage, greenhouse gas emissions, soil erosion, food poisoning, and livestock disease. Pretty concluded that people pay three times: at the shop, through taxes supporting intensive farming, and through funding cleanup and repair of environmental damage."},{label:"F",content:"In Britain, moving away from industrial agriculture may be feasible because immediate food scarcity pressures are lower and long-term environmental harms are clearer."},{label:"G",content:"Pretty proposes a pragmatic middle path rather than an immediate universal shift to full organic farming: a 'Greener Food Standard' to improve agrochemical use, soil and water management, energy efficiency, food safety, and animal health while remaining accessible to consumers."}],questions:at},ut={id:"day16-makete-transport-p3",title:"Day 16 Passage 3: Makete Integrated Rural Transport Project",paragraphs:[{label:"A",content:"Poor outcomes from conventional African road projects led to a new strategy in the 1980s. In remote Makete District, Tanzania, planners adopted an integrated rural transport model aimed at reducing time and effort needed to access goods and services. MIRTP began in 1985 with support from the Swiss Development Corporation and the Tanzanian government."},{label:"B",content:"At the start, Makete was nearly cut off during rainy months. A Phase I survey of over 400 households showed very high daily transport burdens: most travel was on foot, most movement remained local, and much effort went into collecting water and firewood and reaching grinding mills."},{label:"C",content:"During Phase II, solutions were implemented: roads were improved through labour-intensive methods, training was provided for workshops and transport services, paths were upgraded with steps, handrails and footbridges, and lower-cost local transport options were explored, including donkeys and locally manufacturable wheelbarrows."},{label:"D",content:"Phase III focused on refinement and institutionalisation. Road access improved year-round and market supplies became more stable. Community-requested path upgrades were popular. However, motorised services remained unreliable due to frequent vehicle breakdowns and limited repair resources. Even low-cost transport options remained expensive for many households."},{label:"E",content:"The project's early top-down style could be criticised, but district-level governmental support was necessary to respond to rural needs and sustain implementation."},{label:"F",content:"After sustained community development work, awareness of improved paths and affordable transport increased. The integrated rural transport concept became established in Tanzania, and Makete was seen as a reference model for broader national initiatives."}],questions:ot},pt={id:"day17-story-of-silk-p1",title:"Day 17 Passage 1: The Story of Silk",paragraphs:[{label:"A",content:"Silk, one of the world's most luxurious fabrics, was first produced from silkworm cocoons in China. According to legend, around 3000 BC Lei Tzu discovered silk when a cocoon dropped into her hot tea and unravelled into a fine thread. She later developed a reel to draw out strong fibres for weaving."},{label:"B",content:"Originally, silk production was mainly a female activity and silk use was restricted to royalty. Over time restrictions loosened. During the Han Dynasty, silk functioned not only as a textile but also as currency, tax payment, and diplomatic gift. Early silk paper dates to around 168 AD."},{label:"C",content:"Demand for silk drove the Silk Road, a lucrative route stretching from eastern China to the Mediterranean. Silk moved westward while wool, gold and silver moved eastward. Few merchants travelled the full route; goods often changed hands through middlemen."},{label:"D",content:"China held a long monopoly, but eventually silk production knowledge spread. One account says Byzantine monks smuggled silkworm eggs to Constantinople in hollow canes around 550 AD. Production later spread through regions linked to Arab expansion and then further into Europe."},{label:"E",content:"By the medieval period, areas such as Italy developed significant silk industries and reputations for high-quality silk processing."},{label:"F",content:"In modern times, industrialisation, world wars and manmade fibres such as nylon disrupted traditional silk production patterns. China later re-established itself as the leading producer and exporter of raw silk and silk yarn."}],questions:nt},mt={id:"day18-great-migrations-p2",title:"Day 18 Passage 2: Great Migrations",paragraphs:[{label:"A",content:"Animal migration is more than simple movement. It often follows regular cycles, involves prolonged and purposeful travel, demands special energy allocation, and is maintained despite distractions or challenges."},{label:"B",content:"An arctic tern may fly around 20,000 km from South America to the Arctic while ignoring easy feeding opportunities that local gulls seize. The tern remains focused on arrival and breeding goals."},{label:"C",content:"Arrival at Arctic breeding grounds serves an evolutionary purpose: finding suitable conditions to hatch and rear offspring."},{label:"D",content:"Definitions of migration vary among biologists. Joel Berger, studying terrestrial mammals like pronghorn, defines migration as seasonal round trips between separate home areas for resources."},{label:"E",content:"Other movements can also qualify, such as daily vertical movement of zooplankton and multi-generational movement of aphids to new host plants."},{label:"F",content:"Hugh Dingle offers a broader evolutionary framework with defining characteristics shared across species, highlighting common migration principles rather than focusing on a single animal group."},{label:"G",content:"Human development increasingly threatens migration routes. Pronghorn in North America face bottlenecks where movement corridors narrow due to natural and human barriers, including fencing and housing expansion."},{label:"H",content:"Conservation agencies are working to protect migration corridors, but long-distance routes crossing jurisdictions remain difficult to secure without coordinated policy and sustained commitment."}],questions:it},gt={id:"day19-math-reasoning-preface-p3",title:"Day 19 Passage 3: Preface to 'How the other half thinks: Adventures in mathematical reasoning'",paragraphs:[{label:"A",content:"The author argues that some advanced mathematical discoveries can be understood with only elementary arithmetic. The book presents each chapter step by step so readers can participate in mathematical reasoning."},{label:"B",content:"A main goal is to reveal the reasoning behind discoveries. The author contrasts this book with many popular mathematics books that either focus on biographies, applications, or procedures requiring prior algebra expertise."},{label:"C",content:"The book aims to bridge the divide between humanities and sciences, emphasizing that intuition matters alongside analytical thinking. The author cites people whose mixed talents challenge stereotypes."},{label:"D",content:"Other science writers often omit mathematics when addressing non-specialists, even though mathematics is foundational to their fields."},{label:"E",content:"Non-mathematical readers can still progress, but the reading requires sustained attention. The author recommends working slowly with pencil and paper and checking claims through experiments."},{label:"F",content:"The book targets multiple reader groups, including former maths enthusiasts and those seeking stronger analytical skills for professional fields."},{label:"G",content:"Testimonials from a physician and a lawyer claim that mathematical training improved their problem-solving and professional performance."}],questions:rt},ft={id:"day21-polar-bears-p1",title:"Day 21 Passage 1: Why we need to protect polar bears",paragraphs:[{label:"A",content:"Polar bears are increasingly threatened by climate change, yet they survive extreme Arctic conditions with very high body fat levels that would usually cause severe health problems in humans."},{label:"B",content:"A 2014 study by Shi Ping Liu and colleagues compared polar bears with brown bears and identified genes linked to survival, including a gene affecting low-density lipoproteins (LDL). In humans, mutations in this gene are associated with heart disease risk."},{label:"C",content:"The polar bear genome may also provide insights into osteoporosis. Female polar bears endure lengthy fasting during maternity denning while still maintaining strong bones despite calcium depletion."},{label:"D",content:"Research by Alanda Lennox and Allen Goodship found that pregnant females increased bone density before denning and did not show major loss after emergence, suggesting unusual bone remodelling mechanisms with possible medical relevance."},{label:"E",content:"Conservation arguments are not only medical. Anecdotal evidence challenges stereotypes of bears as unintelligent and violent. Examples include tool-like branch use to dislodge food and calculated problem-solving behaviours in the wild."},{label:"F",content:"Other observations describe deliberate manipulation and behaviour resembling play, suggesting creativity and focused action beyond earlier assumptions."},{label:"G",content:"Reports also suggest emotional responses and unusual cross-species social relationships in some bears, reinforcing the argument that their extinction would be a major biological and moral loss."}],questions:st},yt={id:"day22-step-pyramid-p2",title:"Day 22 Passage 2: The Step Pyramid of Djoser",paragraphs:[{label:"A",content:"The Step Pyramid of Djoser at Saqqara is widely seen as the starting point of pyramid architecture in Egypt, despite ongoing debate over many details of early pyramid evolution."},{label:"B",content:"Before Djoser, tombs were rectangular mud-brick mastabas. Imhotep conceived a new design by stacking progressively smaller stone slabs, creating the stepped form. The exact reasons remain uncertain, and even Djoser's reign length is debated."},{label:"C",content:"Modern investigation indicates multiple design stages and extensive experimentation before the final six-level structure emerged. Managing the enormous weight required careful engineering choices."},{label:"D",content:"The surrounding complex was vast, including temples, courtyards, shrines, housing for priests, and defensive-style features such as false doors and a trench to deter intruders."},{label:"E",content:"Beneath the pyramid lay the burial chamber and a large network of passages and chambers. Thousands of inscribed stone vessels were discovered, but their exact purpose remains contested."},{label:"F",content:"Despite precautions, robbers still reached the tomb and removed major valuables. Nevertheless, sufficient finds remained to astonish archaeologists."},{label:"G",content:"Scholars regard the Step Pyramid as a major architectural milestone and an archetype for later pyramid builders in Egypt."}],questions:ht},wt={id:"day23-future-work-p3",title:"Day 23 Passage 3: The future of work",paragraphs:[{label:"A",content:"Forecasts suggest substantial workforce transition over coming years as occupations evolve alongside both embodied and disembodied AI systems."},{label:"B",content:"Stella Pachidi argues that major changes are occurring in data-dependent parts of the knowledge economy, where algorithms now handle tasks once requiring human judgement."},{label:"C",content:"Businesses are drawn to algorithms for speed, perceived informational quality, reduced costs, and productivity gains, including cases where AI outperforms humans in specific routine cognitive tasks."},{label:"D",content:"Pachidi warns that over-automation may weaken learning pathways for novices who traditionally acquire expertise through observation and guided participation."},{label:"E",content:"Her fieldwork in telecommunications showed increasing algorithmic control of customer-contact decisions, displacing professional judgement built through practical experience."},{label:"F",content:"She also observed workers becoming dependent on algorithmic instruction and, in some cases, gaming systems by feeding misleading data to achieve targets."},{label:"G",content:"Researchers are therefore working on more trustworthy and transparent AI systems to improve comprehension and user confidence in automated decisions."},{label:"H",content:"Hamish Low predicts more varied and multi-stage career paths with retraining across life, while rejecting simplistic fixed-job assumptions in automation forecasts."},{label:"I",content:"Ewan McGaughey argues that unemployment outcomes depend heavily on policy and law. He proposes proactive reforms to ensure secure employment, fair income, and broad-based economic participation."},{label:"J",content:"He frames current AI change in historical perspective, comparing it with earlier social and industrial transformations and arguing that the next revolution should be social as well as technological."}],questions:lt},bt={14:ct,15:dt,16:ut,17:pt,18:mt,19:gt,21:ft,22:yt,23:wt},R=["A","B","C","D","E","F","G"],g=["A","B","C","D","E","F","G","H","I"],W=["A 1836","B 1840","C 1965","D 1967","E 1971","F 1979","G 1982"],vt=["A. They are less imaginatively designed.","B. They are less spacious.","C. They are in less convenient locations.","D. They are less versatile.","E. They are made of less durable materials."],At=["A. offering improved amenities for the enjoyment of sports events","B. bringing community life back into the city environment","C. facilitating research into solar and wind energy solutions","D. enabling local residents to reduce their consumption of electricity","E. providing a suitable site for the installation of renewable power generators"],kt=["military innovation","large reward","widespread conspiracy","relative safety","new government","decisive victory","political debate","strategic alliance","popular solution","religious conviction"],_t=["A. Evidence of innovative environment management practices","B. An undisputed answer to a question about the moai","C. The future of the moai statues","D. A theory which supports a local belief","E. The future of Easter Island","F. Two opposing views about the Rapanui people","G. Destruction outside the inhabitants' control","H. How the statues made a situation worse","I. Diminishing food resources"],xt=["A. the period when the moai were created","B. how the moai were transported","C. the impact of the moai on Rapanui society","D. how the moai were carved","E. the origins of the people who made the moai"],Tt=["interpretation","complexity","emotions","movements","skill","layout","concern","images"],Pt=[{id:"day7-q1",number:1,type:"note-completion",groupTitle:"Questions 1-6",instruction:"Complete the notes below. Choose ONE WORD ONLY from the passage for each answer.",text:"The ______ of London increased rapidly between 1800 and 1850.",correctAnswer:"population",location:"Paragraph A"},{id:"day7-q2",number:2,type:"note-completion",text:"Building the railway would make it possible to move people to better housing in the ______.",correctAnswer:"suburbs",location:"Paragraph B"},{id:"day7-q3",number:3,type:"note-completion",text:"A number of ______ agreed with Pearson's idea.",correctAnswer:"businessmen",location:"Paragraph B"},{id:"day7-q4",number:4,type:"note-completion",text:"The company initially had problems getting the ______ needed for the project.",correctAnswer:"funding",location:"Paragraph C"},{id:"day7-q5",number:5,type:"note-completion",text:"Negative articles about the project appeared in the ______.",correctAnswer:"press",location:"Paragraph C"},{id:"day7-q6",number:6,type:"note-completion",text:"With the completion of the brick arch, the tunnel was covered with ______.",correctAnswer:"soil",location:"Paragraph D"},{id:"day7-q7",number:7,type:"true-false-not-given",groupTitle:"Questions 7-13",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Other countries had built underground railways before the Metropolitan line opened.",correctAnswer:"FALSE",location:"Paragraph E"},{id:"day7-q8",number:8,type:"true-false-not-given",text:"More people than predicted travelled on the Metropolitan line on the first day.",correctAnswer:"NOT GIVEN",location:"Paragraph E"},{id:"day7-q9",number:9,type:"true-false-not-given",text:"The use of ventilation shafts failed to prevent pollution in the tunnels.",correctAnswer:"TRUE",location:"Paragraph E"},{id:"day7-q10",number:10,type:"true-false-not-given",text:"A different approach from the 'cut and cover' technique was required in London's central area.",correctAnswer:"TRUE",location:"Paragraph F"},{id:"day7-q11",number:11,type:"true-false-not-given",text:"The windows on City & South London trains were at eye level.",correctAnswer:"FALSE",location:"Paragraph G"},{id:"day7-q12",number:12,type:"true-false-not-given",text:"The City & South London Railway was a financial success.",correctAnswer:"FALSE",location:"Paragraph G"},{id:"day7-q13",number:13,type:"true-false-not-given",text:"Trains on the 'Tuppenny Tube' nearly always ran on time.",correctAnswer:"NOT GIVEN",location:"Paragraph H"}],qt=[{id:"day8-q14",number:14,type:"matching-information",groupTitle:"Questions 14-17",instruction:"Match the information to the correct paragraph, A-G.",text:"mention of negative attitudes towards stadium building projects",options:R,correctAnswer:"A",location:"Paragraph A"},{id:"day8-q15",number:15,type:"matching-information",text:"figures demonstrating the environmental benefits of a certain stadium",options:R,correctAnswer:"F",location:"Paragraph F"},{id:"day8-q16",number:16,type:"matching-information",text:"examples of the wide range of facilities available at some new stadiums",options:R,correctAnswer:"E",location:"Paragraph E"},{id:"day8-q17",number:17,type:"matching-information",text:"reference to the disadvantages of the stadiums built during a certain era",options:R,correctAnswer:"D",location:"Paragraph D"},{id:"day8-q18",number:18,type:"summary-completion",groupTitle:"Questions 18-22",instruction:"Complete the summary below. Choose ONE WORD ONLY from the passage for each answer.",text:"The amphitheatre of Arles was converted first into a ______, then into a residential area and finally into an arena where spectators could watch bullfights.",correctAnswer:"fortress",location:"Paragraph B"},{id:"day8-q19",number:19,type:"summary-completion",text:"At Arles, the structure eventually returned to being a venue where ______ were staged.",correctAnswer:"bullfights",location:"Paragraph B"},{id:"day8-q20",number:20,type:"summary-completion",text:"The arena in Verona is now famous as a venue where ______ is performed.",correctAnswer:"opera",location:"Paragraph B"},{id:"day8-q21",number:21,type:"summary-completion",text:"The site in Lucca had various uses over time, including storage of ______.",correctAnswer:"salt",location:"Paragraph C"},{id:"day8-q22",number:22,type:"summary-completion",text:"Today, Lucca's market square includes ______ and homes incorporated into the old structure.",correctAnswer:"shops",location:"Paragraph C"},{id:"day8-q23",number:23,type:"five-true-statements",groupTitle:"Questions 23-24",instruction:"Choose TWO letters, A-E.",text:"When comparing twentieth-century stadiums to ancient amphitheatres in Section D, which TWO negative features does the writer mention?",options:vt,correctAnswer:["C","D"],location:"Paragraph D"},{id:"day8-q25",number:25,type:"five-true-statements",groupTitle:"Questions 25-26",instruction:"Choose TWO letters, A-E.",text:"Which TWO advantages of modern stadium design does the writer mention?",options:At,correctAnswer:["B","E"],location:"Paragraphs E-F"}],Ct=[{id:"day9-q27",number:27,type:"drag-drop-summary",groupTitle:"Questions 27-31",instruction:"Complete the summary by dragging the correct words into the gaps.",text:`Charles II then formed a ______ with the Scots.
In order to become King of Scots, he abandoned an important ______ held by his father.
The battle outside Worcester in 1651 led to a ______ for the Parliamentarians.
A ______ was offered for Charles's capture.
After six weeks in hiding, he eventually reached the ______ of continental Europe.`,options:kt,correctAnswer:["strategic alliance","religious conviction","decisive victory","large reward","relative safety"],location:"Paragraph A"},{id:"day9-q32",number:32,type:"yes-no-not-given",groupTitle:"Questions 32-35",instruction:"Choose YES if the statement agrees with the claims of the writer, NO if it contradicts the claims, or NOT GIVEN if there is no information on this.",text:"Charles chose Pepys for this task because he considered him trustworthy.",correctAnswer:"NOT GIVEN",location:"Paragraph B"},{id:"day9-q33",number:33,type:"yes-no-not-given",text:"Charles's personal recollection of the escape lacked sufficient detail.",correctAnswer:"NO",location:"Paragraph B"},{id:"day9-q34",number:34,type:"yes-no-not-given",text:"Charles indicated to Pepys that he had planned his escape before the battle.",correctAnswer:"NO",location:"Paragraph B"},{id:"day9-q35",number:35,type:"yes-no-not-given",text:"The inclusion of Charles's account is a positive aspect of the book.",correctAnswer:"YES",location:"Paragraph C"},{id:"day9-q36",number:36,type:"multiple-choice",groupTitle:"Questions 36-40",instruction:"Choose the correct answer.",text:"What is the reviewer's main purpose in the first paragraph?",options:["to describe what happened during the Battle of Worcester","to give an account of the circumstances leading to Charles II's escape","to compare Charles II's beliefs with those of his father","to provide details of the Parliamentarians' political views"],correctAnswer:"B",location:"Paragraph A"},{id:"day9-q37",number:37,type:"multiple-choice",text:"Why does the reviewer include examples of the fugitives' behaviour in the third paragraph?",options:["to explain how close Charles II came to losing his life","to suggest that Charles II's supporters were badly prepared","to illustrate how the events of the six weeks are brought to life","to argue that certain aspects are not as well known as they should be"],correctAnswer:"C",location:"Paragraph C"},{id:"day9-q38",number:38,type:"multiple-choice",text:"What point does the reviewer make about Charles II in the fourth paragraph?",options:["He chose to celebrate what was essentially a defeat.","He misunderstood the motives of his opponents.","He aimed to restore people's faith in the monarchy.","He was driven by a desire to be popular."],correctAnswer:"A",location:"Paragraph D"},{id:"day9-q39",number:39,type:"multiple-choice",text:"What does the reviewer say about Charles Spencer in the fifth paragraph?",options:["His decision to write the book comes as a surprise.","He takes an unbiased approach to the subject matter.","His descriptions of events would be better if they included more detail.","He chooses language that is suitable for a twenty-first-century audience."],correctAnswer:"B",location:"Paragraph E"},{id:"day9-q40",number:40,type:"multiple-choice",text:"When the reviewer says the book 'doesn't quite hit the mark', she is making the point that",options:["it overlooks the impact of events on ordinary people.","it lacks an analysis of prevalent views on monarchy.","it omits any references to the deceit practised by Charles II during his time in hiding.","it fails to address whether Charles II's experiences had a lasting influence on him."],correctAnswer:"D",location:"Paragraph F"}],It=[{id:"day11-q1",number:1,type:"true-false-not-given",groupTitle:"Questions 1-4",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"There is some doubt about what caused the Mary Rose to sink.",correctAnswer:"TRUE",location:"Paragraph A"},{id:"day11-q2",number:2,type:"true-false-not-given",text:"The Mary Rose was the only ship to sink in the battle of 19 July 1545.",correctAnswer:"NOT GIVEN",location:"Paragraph A"},{id:"day11-q3",number:3,type:"true-false-not-given",text:"Most of one side of the Mary Rose lay undamaged under the sea.",correctAnswer:"TRUE",location:"Paragraph B"},{id:"day11-q4",number:4,type:"true-false-not-given",text:"Alexander McKee knew that the wreck would contain many valuable historical objects.",correctAnswer:"FALSE",location:"Paragraph E"},{id:"day11-q5",number:5,type:"matching-information",groupTitle:"Questions 5-8",instruction:"Match each statement with the correct date, A-G.",text:"A search for the Mary Rose was launched.",options:W,correctAnswer:"C",location:"Paragraph D"},{id:"day11-q6",number:6,type:"matching-information",text:"One person's exploration of the Mary Rose site stopped.",options:W,correctAnswer:"B",location:"Paragraph C"},{id:"day11-q7",number:7,type:"matching-information",text:"It was agreed that the hull of the Mary Rose should be raised.",options:W,correctAnswer:"G",location:"Paragraph E"},{id:"day11-q8",number:8,type:"matching-information",text:"The site of the Mary Rose was found by chance.",options:W,correctAnswer:"A",location:"Paragraph C"},{id:"day11-q9",number:9,type:"short-answer",groupTitle:"Questions 9-13",instruction:"Choose NO MORE THAN TWO WORDS from the passage for each answer.",text:"______ attached to hull by wires",correctAnswer:"lifting frame",location:"Paragraph F"},{id:"day11-q10",number:10,type:"short-answer",text:"______ to prevent hull being sucked into mud",correctAnswer:"hydraulic jacks",location:"Paragraph F"},{id:"day11-q11",number:11,type:"short-answer",text:"legs are placed into ______",correctAnswer:"stabbing guides",location:"Paragraph G"},{id:"day11-q12",number:12,type:"short-answer",text:"hull is lowered into ______",correctAnswer:"lifting cradle",location:"Paragraph G"},{id:"day11-q13",number:13,type:"short-answer",text:"______ used as extra protection for the hull",correctAnswer:"air bags",location:"Paragraph G"}],Et=[{id:"day12-q14",number:14,type:"matching-headings",groupTitle:"Questions 14-20",instruction:"Choose the correct heading for each paragraph from the list of headings below.",text:"Paragraph A",options:_t,correctAnswer:"B",location:"Paragraph A"},{id:"day12-q15",number:15,type:"matching-headings",text:"Paragraph B",options:g,correctAnswer:"I",location:"Paragraph B"},{id:"day12-q16",number:16,type:"matching-headings",text:"Paragraph C",options:g,correctAnswer:"H",location:"Paragraph C"},{id:"day12-q17",number:17,type:"matching-headings",text:"Paragraph D",options:g,correctAnswer:"A",location:"Paragraph D"},{id:"day12-q18",number:18,type:"matching-headings",text:"Paragraph E",options:g,correctAnswer:"D",location:"Paragraph E"},{id:"day12-q19",number:19,type:"matching-headings",text:"Paragraph F",options:g,correctAnswer:"G",location:"Paragraph F"},{id:"day12-q20",number:20,type:"matching-headings",text:"Paragraph G",options:g,correctAnswer:"F",location:"Paragraph G"},{id:"day12-q21",number:21,type:"summary-completion",groupTitle:"Questions 21-24",instruction:"Complete the summary below. Choose ONE WORD ONLY from the passage for each answer.",text:"The Polynesian settlers cleared land for ______.",correctAnswer:"farming",location:"Paragraph B"},{id:"day12-q22",number:22,type:"summary-completion",text:"Without trees, islanders could no longer build ______ for fishing.",correctAnswer:"canoes",location:"Paragraph B"},{id:"day12-q23",number:23,type:"summary-completion",text:"They began using the island's ______ as a food source, according to Diamond.",correctAnswer:"birds",location:"Paragraph B"},{id:"day12-q24",number:24,type:"summary-completion",text:"Diamond says moving the statues required a great deal of ______.",correctAnswer:"wood",location:"Paragraph C"},{id:"day12-q25",number:25,type:"five-true-statements",groupTitle:"Questions 25-26",instruction:"Choose TWO letters, A-E.",text:"On what points do Hunt and Lipo disagree with Diamond?",options:xt,correctAnswer:["B","C"],location:"Paragraphs C-E"}],St=[{id:"day13-q27",number:27,type:"multiple-choice",groupTitle:"Questions 27-30",instruction:"Choose the correct answer, A, B, C or D.",text:"In the second paragraph, the writer refers to a shape-matching test in order to illustrate",options:["the subjective nature of art appreciation.","the reliance of modern art on abstract forms.","our tendency to be influenced by the opinions of others.","a common problem encountered when processing visual data."],correctAnswer:"C",location:"Paragraph B"},{id:"day13-q28",number:28,type:"multiple-choice",text:"Angelina Hawley-Dolan's findings indicate that people",options:["mostly favour works of art which they know well.","hold fixed ideas about what makes a good work of art.","are often misled by their initial expectations of a work of art.","have the ability to perceive the intention behind works of art."],correctAnswer:"D",location:"Paragraph C"},{id:"day13-q29",number:29,type:"multiple-choice",text:"Results of studies involving Robert Pepperell's pieces suggest that people",options:["can appreciate a painting without fully understanding it.","find it satisfying to work out what a painting represents.","vary widely in the time they spend looking at paintings.","generally prefer representational art to abstract art."],correctAnswer:"B",location:"Paragraph D"},{id:"day13-q30",number:30,type:"multiple-choice",text:"What do the experiments described in the fifth paragraph suggest about the paintings of Mondrian?",options:["They can be interpreted in a number of different ways.","They challenge our assumptions about shape and colour.","They are easier to appreciate than many other abstract works.","They are more carefully put together than they appear."],correctAnswer:"A",location:"Paragraph E"},{id:"day13-q31",number:31,type:"drag-drop-summary",groupTitle:"Questions 31-33",instruction:"Complete the summary by dragging the correct words into the gaps.",text:`Impressionist paintings seem to influence our ______.
Alex Forsythe suggests many artists use a key level of ______ to please the brain.
Appealing artworks often include repeated ______ that are common in nature.`,options:Tt,correctAnswer:["emotions","complexity","images"],location:"Paragraphs A and G"},{id:"day13-q34",number:34,type:"yes-no-not-given",groupTitle:"Questions 34-39",instruction:"Choose YES if the statement agrees with the claims of the writer, NO if it contradicts the claims, or NOT GIVEN if there is no information on this.",text:"Alex Forsythe was the first person to investigate the level of detail in paintings.",correctAnswer:"NOT GIVEN",location:"Paragraph G"},{id:"day13-q35",number:35,type:"yes-no-not-given",text:"Certain ideas regarding the link between 'mirror neurons' and art appreciation require further verification.",correctAnswer:"YES",location:"Paragraph H"},{id:"day13-q36",number:36,type:"yes-no-not-given",text:"People's taste in paintings depends entirely on the current artistic trends of the period.",correctAnswer:"NO",location:"Paragraph H"},{id:"day13-q37",number:37,type:"yes-no-not-given",text:"Scientists should seek to define the precise rules which govern people's reactions to works of art.",correctAnswer:"NO",location:"Paragraph I"},{id:"day13-q38",number:38,type:"yes-no-not-given",text:"Art appreciation should always involve taking into consideration the cultural context in which an artist worked.",correctAnswer:"YES",location:"Paragraph I"},{id:"day13-q39",number:39,type:"yes-no-not-given",text:"It is easier to find meaning in the field of science than in that of art.",correctAnswer:"NOT GIVEN",location:"Paragraph I"},{id:"day13-q40",number:40,type:"multiple-choice",groupTitle:"Question 40",instruction:"Choose the correct answer, A, B, C or D.",text:"What would be the most appropriate subtitle for the article?",options:["Some scientific insights into how the brain responds to abstract art","Recent studies focusing on the neural activity of abstract artists","A comparison of the neurological bases of abstract and representational art","How brain research has altered public opinion about abstract art"],correctAnswer:"A",location:"Paragraph I"}],Bt={id:"day7-london-underground-p1",title:"Day 7 Passage 1: The development of the London underground railway",paragraphs:[{label:"A",content:"In the first half of the 1800s, London's population grew at an astonishing rate, and the central area became increasingly congested. In addition, the expansion of the overground railway network resulted in more and more passengers arriving in the capital. However, in 1846, a Royal Commission decided that the railways should not be allowed to enter the City, the capital's historic and business centre. The result was that the overground railway stations formed a ring around the City. The area within consisted of poorly built, overcrowded slums and the streets were full of horse-drawn traffic. Crossing the City became a nightmare. It could take an hour and a half to travel 8 km by horse-drawn carriage or bus. Numerous schemes were proposed to resolve these problems, but few succeeded."},{label:"B",content:"Amongst the most vocal advocates for a solution to London's traffic problems was Charles Pearson, who worked as a solicitor for the City of London. He saw both social and economic advantages in building an underground railway that would link the overground railway stations together and clear London slums at the same time. His idea was to relocate the poor workers who lived in the inner-city slums to newly constructed suburbs, and to provide cheap rail travel for them to get to work. Pearson's ideas gained support amongst some businessmen and in 1851 he submitted a plan to Parliament. It was rejected, but coincided with a proposal from another group for an underground connecting line, which Parliament passed. The two groups merged and established the Metropolitan Railway Company in August 1854."},{label:"C",content:"The company's plan was to construct an underground railway line from the Great Western Railway's station at Paddington to the edge of the City at Farringdon Street - a distance of almost 5 km. The organisation had difficulty in raising the funding for such a radical and expensive scheme, not least because of the critical articles printed by the press. Objectors argued that the tunnels would collapse under the weight of traffic overhead, buildings would be shaken and passengers would be poisoned by the emissions from the train engines. However, Pearson and his partners persisted."},{label:"D",content:"The GWR, aware that the new line would finally enable them to run trains into the heart of the City, invested almost £250,000 in the scheme. Eventually, over a five-year period, £1m was raised. The chosen route ran beneath existing main roads to minimise the expense of demolishing buildings. Originally scheduled to be completed in 21 months, the construction of the underground line took three years. It was built just below street level using a technique known as 'cut and cover'. A trench about ten metres wide and six metres deep was dug, and the sides temporarily held up with timber beams. Brick walls were then constructed, and finally a brick arch was added to create a tunnel. A two-metre-deep layer of soil was laid on top of the tunnel and the road above rebuilt."},{label:"E",content:"The Metropolitan line, which opened on 10 January 1863, was the world's first underground railway. On its first day, almost 40,000 passengers were carried between Paddington and Farringdon, the journey taking about 18 minutes. By the end of the Metropolitan's first year of operation, 9.5 million journeys had been made. Even as the Metropolitan began operation, the first extensions to the line were being authorised; these were built over the next five years, reaching Moorgate in the east of London and Hammersmith in the west. The original plan was to pull the trains with steam locomotives, using firebricks in the boilers to provide steam, but these engines were never introduced. Instead, the line used specially designed locomotives that were fitted with water tanks in which steam could be condensed. However, smoke and fumes remained a problem, even though ventilation shafts were added to the tunnels."},{label:"F",content:"Despite the extension of the underground railway, by the 1880s, congestion on London's streets had become worse. The problem was partly that the existing underground lines formed a circuit around the centre of London and extended to the suburbs, but did not cross the capital's centre. The 'cut and cover' method of construction was not an option in this part of the capital. The only alternative was to tunnel deep underground."},{label:"G",content:"Although the technology to create these tunnels existed, steam locomotives could not be used in such a confined space. It wasn't until the development of a reliable electric motor, and a means of transferring power from the generator to a moving train, that the world's first deep-level electric railway, the City & South London, became possible. The line opened in 1890, and ran from the City to Stockwell, south of the River Thames. The trains were made up of three carriages and driven by electric engines. The carriages were narrow and had tiny windows just below the roof because it was thought that passengers would not want to look out at the tunnel walls. The line was not without its problems, mainly caused by an unreliable power supply. Although the City & South London Railway was a great technical achievement, it did not make a profit."},{label:"H",content:"Then, in 1900, the Central London Railway, known as the 'Tuppenny Tube', began operation using new electric locomotives. It was very popular and soon afterwards new railways and extensions were added to the growing tube network. By 1907, the heart of today's Underground system was in place."}],questions:Pt},Dt={id:"day8-stadiums-p2",title:"Day 8 Passage 2: Stadiums - past, present and future",paragraphs:[{label:"A",content:"Stadiums are among the oldest forms of urban architecture: vast stadiums where the public could watch sporting events were at the centre of western city life as far back as the ancient Greek and Roman Empires, well before the construction of the great medieval cathedrals and the grand nineteenth- and twentieth-century railway stations which dominated urban skylines in later eras. Today, however, stadiums are regarded with growing scepticism. Construction costs can soar above £1 billion, and stadiums finished for major events such as the Olympic Games or the FIFA World Cup have notably fallen into disuse and disrepair. But this need not be the case. History shows that stadiums can drive urban development and adapt to the culture of every age. Even today, architects and planners are finding new ways to adapt the mono-functional sports arenas which became emblematic of modernisation during the twentieth century."},{label:"B",content:"The amphitheatre of Arles in southwest France, with a capacity of 25,000 spectators, is perhaps the best example of just how versatile stadiums can be. Built by the Romans in 90 AD, it became a fortress with four towers after the fifth century, and was then transformed into a village containing more than 200 houses. With the growing interest in conservation during the nineteenth century, it was converted back into an arena for the staging of bullfights, thereby returning the structure to its original use as a venue for public spectacles. Another example is the imposing arena of Verona in northern Italy, with space for 30,000 spectators, which was built 60 years before the Arles amphitheatre and 40 years before Rome's famous Colosseum. It has endured the centuries and is currently considered one of the world's prime sites for opera, thanks to its outstanding acoustics."},{label:"C",content:"The area in the centre of the Italian town of Lucca, known as the Piazza dell'Anfiteatro, is yet another impressive example of an amphitheatre becoming absorbed into the fabric of the city. The site evolved in a similar way to Arles and was progressively filled with buildings from the Middle Ages until the nineteenth century, variously used as houses, a salt depot and a prison. But rather than reverting to an arena, it became a market square, designed by Romanticist architect Lorenzo Nottolini. Today, the ruins of the amphitheatre remain embedded in the various shops and residences surrounding the public square."},{label:"D",content:"There are many similarities between modern stadiums and the ancient amphitheatres intended for games. But some of the flexibility was lost at the beginning of the twentieth century, as stadiums were developed using new products such as steel and reinforced concrete, and made use of bright lights for night-time matches. Many such stadiums are situated in suburban areas, designed for sporting use only and surrounded by parking lots. These factors mean that they may not be as accessible to the general public, require more energy to run and contribute to urban heat."},{label:"E",content:"But many of today's most innovative architects see scope for the stadium to help improve the city. Among the current strategies, two seem to be having particular success: the stadium as an urban hub, and as a power plant. There's a growing trend for stadiums to be equipped with public spaces and services that serve a function beyond sport, such as hotels, retail outlets, conference centres, restaurants and bars, children's playgrounds and green space. Creating mixed-use developments such as this reinforces compactness and multi-functionality, making more efficient use of land and helping to regenerate urban spaces. This opens the space up to families and a wider cross-section of society, instead of catering only to sportspeople and supporters. There have been many examples of this in the UK: the mixed-use facilities at Wembley and Old Trafford have become a blueprint for many other stadiums in the world."},{label:"F",content:"The phenomenon of stadiums as power stations has arisen from the idea that energy problems can be overcome by integrating interconnected buildings by means of a smart grid, which is an electricity supply network that uses digital communications technology to detect and react to local changes in usage, without significant energy losses. Stadiums are ideal for these purposes, because their canopies have a large surface area for fitting photovoltaic panels and rise high enough (more than 40 metres) to make use of micro wind turbines. Freiburg Mage Solar Stadium in Germany is the first of a new wave of stadiums as power plants, which also includes the Amsterdam Arena and the Kaohsiung Stadium. The latter, inaugurated in 2009, has 8,844 photovoltaic panels producing up to 1.14 GWh of electricity annually. This reduces the annual output of carbon dioxide by 660 tons and supplies up to 80 percent of the surrounding area when the stadium is not in use. This is proof that a stadium can serve its city, and have a decidedly positive impact in terms of reduction of CO2 emissions."},{label:"G",content:"Sporting arenas have always been central to the life and culture of cities. In every era, the stadium has acquired new value and uses: from military fortress to residential village, public space to theatre and most recently a field for experimentation in advanced engineering. The stadium of today now brings together multiple functions, thus helping cities to create a sustainable future."}],questions:qt},Ot={id:"day9-to-catch-a-king-p3",title:"Day 9 Passage 3: To Catch a King",paragraphs:[{label:"A",content:"Charles Spencer's latest book, To Catch a King, tells the story of the hunt for King Charles II in the six weeks after his defeat at the Battle of Worcester in September 1651. After his father was executed by the Parliamentarians in 1649, the young Charles II made a deal with the Scots, accepting Presbyterianism as the national religion in return for being crowned King of Scots. His arrival in Edinburgh prompted the English Parliamentary army to invade Scotland in a pre-emptive strike. This was followed by a Scottish invasion of England. The two sides finally faced one another at Worcester in 1651. After being comprehensively defeated, the 21-year-old king became the subject of a national manhunt, with a huge sum offered for his capture. Over the following six weeks he managed, through a series of close escapes, to evade the Parliamentarians before seeking refuge in France."},{label:"B",content:'Years later, after his restoration, Charles II requested a meeting with the writer and diarist Samuel Pepys. He wanted Pepys to commit the episode to paper so it would never be forgotten. Over two three-hour sittings, the king related in detail his personal recollections of the six weeks he had spent as a fugitive. He began: "After the battle was so absolutely lost as to be beyond hope of recovery, I began to think of the best way of saving myself."'},{label:"C",content:"One of the joys of Spencer's book, not least because it uses Charles II's own narrative alongside those of his supporters, is how close the reader gets to the action. The day-by-day retelling gives striking details: the cutting of the king's long hair with agricultural shears, the use of walnut leaves to dye his pale skin, and the day Charles spent lying on a branch of the great oak tree in Boscobel Wood while Parliamentary soldiers searched below. Spencer captures both humour and tension, including moments when the secret of the king's presence was cautiously revealed to supporters."},{label:"D",content:"Charles's adventures also reveal the uncomfortable truth that while many in England had been appalled by the execution of his father, they had not welcomed the arrival of his son with the Scots army. People feared another civil war. This makes it all the more interesting that Charles II later loved the story so much. He repeatedly retold it and launched initiatives to memorialise it, including a proposed order of chivalry and huge oil paintings depicting the escape. In 1660, he commissioned John Michael Wright to paint cherubs carrying an oak tree to the heavens on the ceiling of his bedchamber."},{label:"E",content:"Charles Spencer is well suited to pass the story to a new generation. His pacey prose avoids modern idiom and vividly brings the tale to life. He shows even-handed sympathy for both the fugitive king and the republican regime that hunted him, and he explores much more background than previous books on the subject."},{label:"F",content:"The tantalising question left at the end is what it all meant. Would Charles II have been a different king had these six weeks never happened? The reviewer suggests this is where the book does not quite hit the mark. Its depiction of Charles II in his final years as an ineffective, pleasure-loving monarch is seen as not fully accurate and not fully just to his complexity. Even so, the book remains an excellent read."}],questions:Ct},Nt={id:"day11-mary-rose-p1",title:"Day 11 Passage 1: Raising the Mary Rose",paragraphs:[{label:"A",content:"On 19 July 1545, English and French fleets were engaged in a sea battle in the Solent, between Portsmouth and the Isle of Wight. Among the English vessels was the Mary Rose. Built in Portsmouth about 35 years earlier, she had enjoyed a long and successful fighting career and was a favourite of Henry VIII. Accounts of her sinking vary: some suggest she was outdated, overladen and sailing too low, while others say she was mishandled by an undisciplined crew. What is undisputed is that she sank that day, taking at least 500 men with her. Attempts to recover her after the battle failed."},{label:"B",content:"The Mary Rose came to rest on her starboard side at an angle of about 60 degrees. The hull trapped sand and mud carried by currents, so the starboard side filled rapidly while the exposed port side was eroded by marine organisms and mechanical degradation. Because of the way the ship sank, nearly all of the starboard half survived intact. In later centuries, the site became covered with hard grey clay, which reduced further erosion."},{label:"C",content:"On 16 June 1836, fishermen in the Solent found their equipment snagged on an underwater obstruction, which turned out to be the Mary Rose. Diver John Deane was nearby exploring another wreck and was asked to free their gear. He dived down and found it caught on a timber protruding from the seabed. He then uncovered more timbers and a bronze gun, and continued intermittent dives until 1840, recovering guns, bows, timbers, part of a pump and other small finds."},{label:"D",content:"The wreck then faded into obscurity for another century. In 1965, military historian and amateur diver Alexander McKee, with the British Sub-Aqua Club, began the 'Solent Ships' project. Although officially aimed at several known wrecks, McKee hoped to find the Mary Rose. Ordinary search techniques proved unsatisfactory, so he collaborated with Harold E. Edgerton of MIT. In 1967, Edgerton's side-scan sonar detected a large unusual object, which McKee believed was the Mary Rose."},{label:"E",content:"Further work uncovered stray timbers and an iron gun. The major breakthrough came on 5 May 1971, when part of the ship's frame was found. McKee and his team knew they had found the wreck, though they did not yet realise its rich store of artefacts. Interest grew, and in 1979 The Mary Rose Trust was formed, with Prince Charles as President and Dr Margaret Rule as Archaeological Director. The decision to salvage the wreck was difficult. Although an excavation in 1978 suggested raising the hull might be possible, final approval came only in January 1982 once all necessary information was available."},{label:"F",content:"A key issue was that the remaining hull was an open shell. This led to the decision to lift it in three distinct stages. The hull was attached to a lifting frame via bolts and lifting wires. The danger of it being sucked back into mud was overcome by using 12 hydraulic jacks. Over several days they raised it a few centimetres as the frame rose slowly on four legs."},{label:"G",content:"Once the hull was hanging freely, the second stage began. The lifting frame was connected to a crane and the hull was lifted clear of the seabed and transferred underwater into a lifting cradle. This required precise positioning so the legs entered the stabbing guides of the cradle. The cradle, designed from archaeological survey drawings, included air bags for cushioning. In the final stage, the whole structure was lifted into the air with support from below. On 11 October 1982, the timber skeleton of the Mary Rose emerged from the water and returned to Portsmouth."}],questions:It},Ft={id:"day12-easter-island-p2",title:"Day 12 Passage 2: What destroyed the civilisation of Easter Island?",paragraphs:[{label:"A",content:"Easter Island, or Rapa Nui, is home to hundreds of ancient human statues called moai. After this remote Pacific island was settled by Polynesians, it remained isolated for centuries. The moai were carved with stone tools and moved for many kilometres to stone platforms without animals or wheels. The identity of the builders remained disputed until modern linguistic, archaeological and genetic evidence proved they were Polynesians. Yet debate remained about how the statues were moved. Local folklore says they walked, while many researchers assumed they were dragged with ropes and logs."},{label:"B",content:"When Europeans arrived in 1722, Rapa Nui was mostly grassland. Later pollen evidence showed that for thousands of years it had been covered in palm forests, which disappeared after Polynesian settlement. Jared Diamond argues that the Rapanui destroyed their own fragile environment by clearing forests for fuel and farming. Without trees, they could not build canoes, so they turned to birds for food. Soil erosion reduced crop yields, and he argues the society descended into civil war and cannibalism before Europeans arrived."},{label:"C",content:"Diamond also argues that the moai accelerated this self-destruction. He sees them as power displays by rival chiefs who competed by building larger and larger statues. He suggests the statues were moved on wooden sledges and log rails, which required huge amounts of wood and labour. Feeding that labour force drove even more deforestation. Once wood ran out and conflict grew, the islanders toppled the moai, and by the nineteenth century none were standing."},{label:"D",content:"Archaeologists Terry Hunt and Carl Lipo agree that Easter Island suffered ecological catastrophe, but they do not blame the islanders themselves, and they reject the claim that the moai caused the collapse. Excavations suggest the Rapanui made extraordinary efforts to protect scarce resources. They built thousands of circular stone windbreaks and cultivated crops inside them, and used broken volcanic rock to retain soil moisture. Hunt and Lipo describe them as pioneers of sustainable farming."},{label:"E",content:"Hunt and Lipo also argue that moai-building may have helped keep peace between groups, and that moving the statues required few people and no wood because they were walked upright. They say archaeological evidence supports local folklore. Experiments suggest that as few as 18 people, using three ropes, could manoeuvre a one-tonne replica. The statues' shape and D-shaped base helped handlers rock them side to side."},{label:"F",content:"They further argue that settlers were not wholly responsible for forest loss. Nuts from the extinct Easter Island palm show grooves made by Polynesian rats, which arrived with settlers and multiplied quickly. The rats likely prevented reseeding of slow-growing palms and may have eaten birds' eggs. Hunt and Lipo also find no evidence that civilisation collapsed when the forest disappeared. They believe population remained relatively stable until Europeans brought deadly diseases, and nineteenth-century slave raids then devastated the island."},{label:"G",content:"Hunt and Lipo's view is therefore of a peaceful and ingenious society of moai builders and land stewards, not reckless destroyers. They call Rapa Nui an unlikely success story rather than an abject failure. Whichever interpretation is correct, the story offers important lessons for the wider world."}],questions:Et},Rt={id:"day13-neuroaesthetics-p3",title:"Day 13 Passage 3: Neuroaesthetics",paragraphs:[{label:"A",content:"Neuroaesthetics is an emerging field that seeks to bring scientific objectivity to the study of art. It has already improved understanding of many masterpieces. For example, blurred imagery in Impressionist paintings appears to stimulate the amygdala, a brain region linked to feelings, which may explain why these works can be so moving."},{label:"B",content:"Researchers also ask whether this approach can explain reactions to abstract twentieth-century art, from Mondrian to Pollock. Sceptics argue that people may claim to like such works simply because they are famous. Humans are often influenced by others: in simple shape-matching tasks, people may choose clearly wrong answers if they see others doing so. This tendency could be even stronger in art, where there is no single correct answer."},{label:"C",content:"Angelina Hawley-Dolan tested this by showing volunteers pairs of paintings: either famous abstract works or doodles by children, chimps and elephants. Some images had no captions and others were deliberately mislabelled. Volunteers generally preferred the works of renowned artists, even when they believed the works were by animals or children. This suggests people can detect an artist's intention even if they cannot explain it."},{label:"D",content:"Artist Robert Pepperell creates ambiguous pieces that are neither fully abstract nor clearly representational. In one study, volunteers judged how powerful an artwork felt and whether they recognized anything familiar in it. The longer they took, the higher they rated the piece, and the greater their neural activity. The brain seems to treat such images as puzzles, and finding meaning can be rewarding."},{label:"E",content:"Mondrian's paintings of horizontal and vertical lines and colour blocks look simple, but eye-tracking studies show they are meticulously composed. Rotating the works changes viewing behaviour: with originals, viewers' eyes rest longer on certain areas; with altered versions, their gaze moves around more quickly. Viewers then rate altered versions as less pleasurable."},{label:"F",content:"Oshin Vartanian similarly compared original paintings with versions where elements had been rearranged. Most people preferred the originals, whether representational or abstract. Rearranged versions also produced less activation in brain areas linked to meaning and interpretation."},{label:"G",content:"Alex Forsythe analysed visual intricacy in art and found that many artists seem to use an optimal level of detail. Too little is boring; too much can cause perceptual overload. Appealing works, abstract and representational alike, often contain fractals - repeated motifs at different scales. Since such patterns are common in nature, our visual systems may process them more easily."},{label:"H",content:"Other research suggests the brain may process movement when viewing handwritten marks, as if replaying the creator's actions. This has prompted the idea that Pollock's paintings feel dynamic because viewers mentally reconstruct his gestures, perhaps through mirror neurons. The hypothesis still needs thorough testing. Neuroaesthetics may even help explain why some artworks endure: while fashions shape short-term popularity, works better adapted to our visual system may persist longer."},{label:"I",content:"The field is still young. Yet reducing art appreciation to fixed scientific laws would be unwise. Style, historical context and the artistic environment remain crucial. Abstract art offers both challenge and freedom of interpretation. In this sense, art is not entirely unlike science, where we also seek patterns and decode meaning to see the world differently."}],questions:St},Wt={7:Bt,8:Dt,9:Ot,11:Nt,12:Ft,13:Rt,...bt},f=["A","B","C","D","E","F","G","H"],y=["A","B","C","D","E","F","G","H","I"],c=["A","B","C","D","E","F","G"],G=["A. James","B. Cooley","C. Lewis and Brooks-Gunn","D. Mead","E. Bronson"],M=["A. Edmond Halley","B. Johannes Kepler","C. Guillaume Le Gentil","D. Johann Franz Encke"],Gt=["A. current teaching methods","B. echoing corridors","C. cooling systems","D. large class sizes","E. loud-voiced teachers","F. playground games"],J=["A. requires both perceptual and social intelligence skills.","B. focuses on how groups decide on an action.","C. works in many fields, both artistic and scientific.","D. leaves one open to criticism and rejection.","E. involves understanding how organizations manage people."],Mt=[{id:"day1-q1",number:1,type:"true-false-not-given",groupTitle:"Questions 1-6",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Marie Curie's husband was a joint winner of both Marie's Nobel Prizes.",correctAnswer:"FALSE",location:"Paragraph A"},{id:"day1-q2",number:2,type:"true-false-not-given",text:"Marie became interested in science when she was a child.",correctAnswer:"NOT GIVEN",location:"Paragraph B"},{id:"day1-q3",number:3,type:"true-false-not-given",text:"Marie was able to attend the Sorbonne because of her sister's financial contribution.",correctAnswer:"TRUE",location:"Paragraph B"},{id:"day1-q4",number:4,type:"true-false-not-given",text:"Marie stopped doing research for several years when her children were born.",correctAnswer:"FALSE",location:"Paragraph F"},{id:"day1-q5",number:5,type:"true-false-not-given",text:"Marie took over the teaching position her husband had held.",correctAnswer:"TRUE",location:"Paragraph G"},{id:"day1-q6",number:6,type:"true-false-not-given",text:"Marie's sister Bronia studied the medical uses of radioactivity.",correctAnswer:"NOT GIVEN",location:"Paragraph B"},{id:"day1-q7",number:7,type:"summary-completion",groupTitle:"Questions 7-13",instruction:"Complete the notes below. Choose ONE WORD from the passage for each answer.",text:"When uranium was discovered to be radioactive, Marie Curie found that the element called ______ had the same property.",correctAnswer:"thorium",location:"Paragraph D"},{id:"day1-q8",number:8,type:"summary-completion",text:"Marie and Pierre Curie's research into the radioactivity of the mineral known as ______ led to the discovery of two new elements.",correctAnswer:"pitchblende",location:"Paragraph E"},{id:"day1-q9",number:9,type:"summary-completion",text:"In 1911, Marie Curie received recognition for her work on the element ______.",correctAnswer:"radium",location:"Paragraph G"},{id:"day1-q10",number:10,type:"summary-completion",text:"Marie and Irene Curie developed X-radiography which was used as a medical technique for ______.",correctAnswer:"treatment",location:"Paragraph H"},{id:"day1-q11",number:11,type:"summary-completion",text:"Marie Curie saw the importance of collecting radioactive material both for research and for cases of ______.",correctAnswer:"illness",location:"Paragraph J"},{id:"day1-q12",number:12,type:"summary-completion",text:"The radioactive material stocked in Paris contributed to the discoveries in the 1930s of the ______ and of what was known as artificial radioactivity.",correctAnswer:"neutron",location:"Paragraph K"},{id:"day1-q13",number:13,type:"summary-completion",text:"During her research, Marie Curie was exposed to radiation and as a result she suffered from ______.",correctAnswer:"leukaemia",location:"Paragraph K"}],Ht=[{id:"day2-q14",number:14,type:"matching-information",groupTitle:"Questions 14-19",instruction:"Which paragraph contains the following information? NB You may use any letter more than once.",text:"an account of the method used by researchers in a particular study",options:f,correctAnswer:"G",location:"Paragraph G"},{id:"day2-q15",number:15,type:"matching-information",text:"the role of imitation in developing a sense of identity",options:f,correctAnswer:"C",location:"Paragraph C"},{id:"day2-q16",number:16,type:"matching-information",text:"the age at which children can usually identify a static image of themselves",options:f,correctAnswer:"G",location:"Paragraph G"},{id:"day2-q17",number:17,type:"matching-information",text:"a reason for the limitations of scientific research into 'self-as-subject'",options:f,correctAnswer:"D",location:"Paragraph D"},{id:"day2-q18",number:18,type:"matching-information",text:"reference to a possible link between culture and a particular form of behaviour",options:f,correctAnswer:"H",location:"Paragraph H"},{id:"day2-q19",number:19,type:"matching-information",text:"examples of the wide range of features that contribute to the sense of 'self-as-object'",options:f,correctAnswer:"E",location:"Paragraph E"},{id:"day2-q20",number:20,type:"matching-information",groupTitle:"Questions 20-23",instruction:"Match each sentence with the correct person from the list of researchers.",text:"A sense of identity can never be formed without relationships with other people.",options:G,correctAnswer:"D",location:"Paragraph F"},{id:"day2-q21",number:21,type:"matching-information",text:"A child's awareness of self is related to a sense of mastery over things and people.",options:G,correctAnswer:"B",location:"Paragraph B"},{id:"day2-q22",number:22,type:"matching-information",text:"At a certain age, children's sense of identity leads to aggressive behaviour.",options:G,correctAnswer:"E",location:"Paragraph H"},{id:"day2-q23",number:23,type:"matching-information",text:"Observing their own reflection contributes to children's self-awareness.",options:G,correctAnswer:"C",location:"Paragraph C"},{id:"day2-q24",number:24,type:"summary-completion",groupTitle:"Questions 24-26",instruction:"Complete the summary below. Choose ONE WORD ONLY from the passage for each answer.",text:"First, children come to realise that they can have an effect on the world around them, for example by handling objects, or causing the image to move when they face a ______.",correctAnswer:"mirror",location:"Paragraph C"},{id:"day2-q25",number:25,type:"summary-completion",text:"This aspect of self-awareness is difficult to research directly, because of ______ problems.",correctAnswer:"communication",location:"Paragraph D"},{id:"day2-q26",number:26,type:"summary-completion",text:"In Western societies at least, the development of self awareness is often linked to a sense of ______ and can lead to disputes.",correctAnswer:"ownership",location:"Paragraph H"}],jt=[{id:"day3-q27",number:27,type:"matching-headings",groupTitle:"Questions 27-30",instruction:"Choose the correct heading for paragraphs B-E from the list of headings below.",text:"Paragraph B",options:["A. Commercial pressures on people in charge","B. Mixed views on current changes to museums","C. Interpreting the facts to meet visitor expectations","D. The international dimension","E. Collections of factual evidence","F. Fewer differences between public attractions","G. Current reviews and suggestions"],correctAnswer:"B",location:"Paragraph B"},{id:"day3-q28",number:28,type:"matching-headings",text:"Paragraph C",options:c,correctAnswer:"F",location:"Paragraph C"},{id:"day3-q29",number:29,type:"matching-headings",text:"Paragraph D",options:c,correctAnswer:"A",location:"Paragraph D"},{id:"day3-q30",number:30,type:"matching-headings",text:"Paragraph E",options:c,correctAnswer:"C",location:"Paragraph E"},{id:"day3-q31",number:31,type:"multiple-choice",groupTitle:"Questions 31-36",instruction:"Choose the correct answer.",text:"Compared with today's museums, those of the past",options:["did not present history in a detailed way.","were not primarily intended for the public.","were more clearly organised.","preserved items with greater care."],correctAnswer:"were not primarily intended for the public.",location:"Paragraph A"},{id:"day3-q32",number:32,type:"multiple-choice",text:"According to the writer, current trends in the heritage industry",options:["emphasise personal involvement.","have their origins in York and London.","rely on computer images.","reflect minority tastes."],correctAnswer:"emphasise personal involvement.",location:"Paragraph B"},{id:"day3-q33",number:33,type:"multiple-choice",text:"The writer says that museums, heritage sites and theme parks",options:["often work in close partnership.","try to preserve separate identities.","have similar exhibits.","are less easy to distinguish than before."],correctAnswer:"are less easy to distinguish than before.",location:"Paragraph C"},{id:"day3-q34",number:34,type:"multiple-choice",text:"Experts must balance historical evidence with the need to present exhibits attractively.",options:["should pursue a single objective.","have to do a certain amount of language translation.","should be free from commercial constraints.","have to balance conflicting priorities."],correctAnswer:"have to balance conflicting priorities.",location:"Paragraph D"},{id:"day3-q35",number:35,type:"multiple-choice",text:"In paragraph E, the writer suggests that some museum exhibits",options:["fail to match visitor expectations.","are based on the false assumptions of professionals.","reveal more about present beliefs than about the past.","allow visitors to make more use of their imagination."],correctAnswer:"reveal more about present beliefs than about the past.",location:"Paragraph E"},{id:"day3-q36",number:36,type:"multiple-choice",text:"The passage ends by noting that our view of history is biased because",options:["we fail to use our imagination.","only very durable objects remain from the past.","we tend to ignore things that displease us.","museum exhibits focus too much on the local area."],correctAnswer:"only very durable objects remain from the past.",location:"Paragraph F"},{id:"day3-q37",number:37,type:"yes-no-not-given",groupTitle:"Questions 37-40",instruction:"Choose YES if the statement agrees with the information, choose NO if it contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Consumers prefer theme parks which avoid serious issues.",correctAnswer:"NOT GIVEN",location:"Paragraph D"},{id:"day3-q38",number:38,type:"yes-no-not-given",text:"More people visit museums than theme parks.",correctAnswer:"NOT GIVEN",location:"Paragraph D"},{id:"day3-q39",number:39,type:"yes-no-not-given",text:"The boundaries of Leyden have changed little since the seventeenth century.",correctAnswer:"NO",location:"Paragraph F"},{id:"day3-q40",number:40,type:"yes-no-not-given",text:"Museums can give a false impression of how life used to be.",correctAnswer:"YES",location:"Paragraph F"}],Lt=[{id:"day4-q1",number:1,type:"matching-information",groupTitle:"Questions 1-6",instruction:"Which section contains the following information? Choose the correct letter, A-I.",text:"an account of a national policy initiative",options:y,correctAnswer:"H",location:"Paragraph H"},{id:"day4-q2",number:2,type:"matching-information",text:"a description of a global team effort",options:y,correctAnswer:"C",location:"Paragraph C"},{id:"day4-q3",number:3,type:"matching-information",text:"a hypothesis as to one reason behind the growth in classroom noise",options:y,correctAnswer:"B",location:"Paragraph B"},{id:"day4-q4",number:4,type:"matching-information",text:"a demand for suitable worldwide regulations",options:y,correctAnswer:"I",location:"Paragraph I"},{id:"day4-q5",number:5,type:"matching-information",text:"a list of medical conditions which place some children more at risk from noise than others",options:y,correctAnswer:"D",location:"Paragraph D"},{id:"day4-q6",number:6,type:"matching-information",text:"the estimated proportion of children in New Zealand with auditory problems",options:y,correctAnswer:"A",location:"Paragraph A"},{id:"day4-q7",number:7,type:"short-answer",groupTitle:"Questions 7-10",instruction:"Choose NO MORE THAN TWO WORDS AND/OR A NUMBER from the passage for each answer.",text:"For what period of time has hearing loss in schoolchildren been studied in New Zealand?",correctAnswer:"two decades",location:"Paragraph A"},{id:"day4-q8",number:8,type:"short-answer",text:"In addition to machinery noise, what other type of noise can upset children with autism?",correctAnswer:"crowd noise",location:"Paragraph E"},{id:"day4-q9",number:9,type:"short-answer",text:"What term is used to describe the hearing problems of schoolchildren which have not been diagnosed?",correctAnswer:"invisible disabilities",location:"Paragraph G"},{id:"day4-q10",number:10,type:"short-answer",text:"What part of the New Zealand Disability Strategy aims to give schoolchildren equal opportunity?",correctAnswer:"Objective 3",location:"Paragraph H"},{id:"day4-q11",number:11,type:"five-true-statements",groupTitle:"Questions 11-12",instruction:"Choose TWO letters, A-F. The list below includes factors contributing to classroom noise. Which TWO are mentioned by the writer?",text:"Select TWO options.",options:Gt,correctAnswer:["A","C"],location:"Paragraph B"},{id:"day4-q13",number:13,type:"multiple-choice",groupTitle:"Question 13",instruction:"Choose the correct answer.",text:"What is the writer's overall purpose in writing this article?",options:["to compare different methods of dealing with auditory problems","to provide solutions for overly noisy learning environments","to increase awareness of the situation of children with auditory problems","to promote New Zealand as a model for other countries to follow"],correctAnswer:"C",location:"Paragraph I"}],Qt=[{id:"day5-q14",number:14,type:"matching-information",groupTitle:"Questions 14-17",instruction:"Which paragraph contains the following information? Choose the correct letter, A-G.",text:"examples of different ways in which the parallax principle has been applied",options:c,correctAnswer:"F",location:"Paragraph F"},{id:"day5-q15",number:15,type:"matching-information",text:"a description of an event which prevented a transit observation",options:c,correctAnswer:"D",location:"Paragraph D"},{id:"day5-q16",number:16,type:"matching-information",text:"a statement about potential future discoveries leading on from transit observations",options:c,correctAnswer:"G",location:"Paragraph G"},{id:"day5-q17",number:17,type:"matching-information",text:"a description of physical states connected with Venus which early astronomical instruments failed to overcome",options:c,correctAnswer:"E",location:"Paragraph E"},{id:"day5-q18",number:18,type:"matching-information",groupTitle:"Questions 18-21",instruction:"Match each statement with the correct person from the list of people below.",text:"He calculated the distance of the Sun from the Earth based on observations of Venus with a fair degree of accuracy.",options:M,correctAnswer:"D",location:"Paragraph F"},{id:"day5-q19",number:19,type:"matching-information",text:"He understood that the distance of the Sun from the Earth could be worked out by comparing observations of a transit.",options:M,correctAnswer:"A",location:"Paragraph B"},{id:"day5-q20",number:20,type:"matching-information",text:"He realised that the time taken by a planet to go round the Sun depends on its distance from the Sun.",options:M,correctAnswer:"B",location:"Paragraph C"},{id:"day5-q21",number:21,type:"matching-information",text:"He witnessed a Venus transit but was unable to make any calculations.",options:M,correctAnswer:"C",location:"Paragraph D"},{id:"day5-q22",number:22,type:"true-false-not-given",groupTitle:"Questions 22-26",instruction:"Choose TRUE if the statement agrees with the information in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this.",text:"Halley observed one transit of the planet Venus.",correctAnswer:"FALSE",location:"Paragraph C"},{id:"day5-q23",number:23,type:"true-false-not-given",text:"Le Gentil managed to observe a second Venus transit.",correctAnswer:"FALSE",location:"Paragraph D"},{id:"day5-q24",number:24,type:"true-false-not-given",text:"The shape of Venus appears distorted when it starts to pass in front of the Sun.",correctAnswer:"TRUE",location:"Paragraph E"},{id:"day5-q25",number:25,type:"true-false-not-given",text:"Early astronomers suspected that the atmosphere on Venus was toxic.",correctAnswer:"NOT GIVEN",location:"Paragraph E"},{id:"day5-q26",number:26,type:"true-false-not-given",text:"The parallax principle allows astronomers to work out how far away distant stars are from the Earth.",correctAnswer:"TRUE",location:"Paragraph F"}],zt=[{id:"day6-q27",number:27,type:"multiple-choice",groupTitle:"Questions 27-31",instruction:"Choose the correct answer.",text:"Neuroeconomics is a field of study which seeks to",options:["cause a change in how scientists understand brain chemistry.","understand how good decisions are made in the brain.","understand how the brain is linked to achievement in competitive fields.","trace the specific firing patterns of neurons in different areas of the brain."],correctAnswer:"C",location:"Paragraph A"},{id:"day6-q28",number:28,type:"multiple-choice",text:"According to the writer, iconoclasts are distinctive because",options:["they create unusual brain circuits.","their brains function differently.","their personalities are distinctive.","they make decisions easily."],correctAnswer:"B",location:"Paragraph B"},{id:"day6-q29",number:29,type:"multiple-choice",text:"According to the writer, the brain works efficiently because",options:["it uses the eyes quickly.","it interprets data logically.","it generates its own energy.","it relies on previous events."],correctAnswer:"D",location:"Paragraph C"},{id:"day6-q30",number:30,type:"multiple-choice",text:"The writer says that perception is",options:["a combination of photons and sound waves.","a reliable product of what your senses transmit.","a result of brain processes.","a process we are usually conscious of."],correctAnswer:"C",location:"Paragraph C"},{id:"day6-q31",number:31,type:"multiple-choice",text:"According to the writer, an iconoclastic thinker",options:["centralises perceptual thinking in one part of the brain.","avoids cognitive traps.","has a brain that is hardwired for learning.","has more opportunities than the average person."],correctAnswer:"B",location:"Paragraph D"},{id:"day6-q32",number:32,type:"yes-no-not-given",groupTitle:"Questions 32-37",instruction:"Choose YES if the statement agrees with the claims of the writer, NO if it contradicts the claims, or NOT GIVEN if there is no information on this.",text:"Exposure to different events forces the brain to think differently.",correctAnswer:"YES",location:"Paragraph E"},{id:"day6-q33",number:33,type:"yes-no-not-given",text:"Iconoclasts are unusually receptive to new experiences.",correctAnswer:"NO",location:"Paragraph E"},{id:"day6-q34",number:34,type:"yes-no-not-given",text:"Most people are too shy to try different things.",correctAnswer:"NOT GIVEN",location:"Paragraph E"},{id:"day6-q35",number:35,type:"yes-no-not-given",text:"If you think in an iconoclastic way, you can easily overcome fear.",correctAnswer:"NO",location:"Paragraph F"},{id:"day6-q36",number:36,type:"yes-no-not-given",text:"When concern about embarrassment matters less, other fears become irrelevant.",correctAnswer:"NOT GIVEN",location:"Paragraph F"},{id:"day6-q37",number:37,type:"yes-no-not-given",text:"Fear of public speaking is a psychological illness.",correctAnswer:"NO",location:"Paragraph F"},{id:"day6-q38",number:38,type:"matching-information",groupTitle:"Questions 38-40",instruction:"Match each statement with the correct ending, A-E.",text:"Thinking like a successful iconoclast is demanding because it",options:J,correctAnswer:"A",location:"Paragraph H"},{id:"day6-q39",number:39,type:"matching-information",text:"The concept of the social brain is useful to iconoclasts because it",options:J,correctAnswer:"B",location:"Paragraph H"},{id:"day6-q40",number:40,type:"matching-information",text:"Iconoclasts are generally an asset because their way of thinking",options:J,correctAnswer:"C",location:"Paragraph I"}],Ut={id:"day1-curie-p1",title:"Day 1 Passage 1: The life and work of Marie Curie",paragraphs:[{label:"A",content:"Marie Curie is probably the most famous woman scientist who has ever lived. Born Maria Sklodowska in Poland in 1867, she is famous for her work on radioactivity, and was twice a winner of the Nobel Prize. With her husband, Pierre Curie, and Henri Becquerel, she was awarded the 1903 Nobel Prize for Physics, and was then sole winner of the 1911 Nobel Prize for Chemistry. She was the first woman to win a Nobel Prize."},{label:"B",content:"From childhood, Marie was remarkable for her prodigious memory, and at the age of 16 won a gold medal on completion of her secondary education. Because her father lost his savings through bad investment, she then had to take work as a teacher. From her earnings she was able to finance her sister Bronia's medical studies in Paris, on the understanding that Bronia would, in turn, later help her to get an education."},{label:"C",content:"In 1891 this promise was fulfilled and Marie went to Paris and began to study at the Sorbonne (the University of Paris). She often worked far into the night and lived on little more than bread and butter and tea. She came first in the examination in the physical sciences in 1893, and in 1894 was placed second in the examination in mathematical sciences. It was not until the spring of that year that she was introduced to Pierre Curie."},{label:"D",content:"Their marriage in 1895 marked the start of a partnership that was soon to achieve results of world significance. Following Henry Becquerel's discovery in 1896 of a new phenomenon, which Marie later called 'radioactivity', Marie Curie decided to find out if the radioactivity discovered in uranium was to be found in other elements. She discovered that this was true for thorium."},{label:"E",content:"Turning her attention to minerals, she found her interest drawn to pitchblende, a mineral whose radioactivity, superior to that of pure uranium, could be explained only by the presence in the ore of small quantities of an unknown substance of very high activity. Pierre Curie joined her in the work that she had undertaken to resolve this problem, and that led to the discovery of the new elements, polonium and radium. While Pierre Curie devoted himself chiefly to the physical study of the new radiations, Marie Curie struggled to obtain pure radium in the metallic state."},{label:"F",content:"This was achieved with the help of the chemist Andre-Louis Debierne, one of Pierre Curie's pupils. Based on the results of this research, Marie Curie received her Doctorate of Science, and in 1903 Marie and Pierre shared with Becquerel the Nobel Prize for Physics for the discovery of radioactivity. The births of Marie's two daughters, Irene and Eve, in 1897 and 1904 failed to interrupt her scientific work."},{label:"G",content:"The sudden death of her husband in 1906 was a bitter blow to Marie Curie, but was also a turning point in her career. Henceforth she was to devote all her energy to completing alone the scientific work that they had undertaken. On May 13, 1906, she was appointed to the professorship that had been left vacant on her husband's death, becoming the first woman to teach at the Sorbonne. In 1911 she was awarded the Nobel Prize for Chemistry for the isolation of a pure form of radium."},{label:"H",content:"During World War I, Marie Curie, with the help of her daughter Irene, devoted herself to the development of the use of X-radiography, including mobile units known as 'little curies', used for the treatment of wounded soldiers."},{label:"I",content:"In 1918 the Radium Institute began to operate in earnest and became a center for nuclear physics and chemistry. Marie Curie, now at the highest point of her fame and, from 1922, a member of the Academy of Medicine, researched the chemistry of radioactive substances and their medical applications."},{label:"J",content:"One of Marie Curie's outstanding achievements was to have understood the need to accumulate intense radioactive sources, not only to treat illness but also to maintain an abundant supply for research."},{label:"K",content:"The stock of radium in Paris made a decisive contribution to experiments around 1930. This work prepared the way for the discovery of the neutron by Sir James Chadwick and, above all, for the discovery in 1934 by Irene and Frederic Joliot-Curie of artificial radioactivity. A few months after this discovery, Marie Curie died as a result of leukaemia caused by exposure to radiation."},{label:"L",content:"Her contribution to physics had been immense, not only in her own work, the importance of which had been demonstrated by her two Nobel Prizes, but because of her influence on subsequent generations of nuclear physicists and chemists."}],questions:Mt},Vt={id:"day2-identity-p2",title:"Day 2 Passage 2: Young children's sense of identity",paragraphs:[{label:"A",content:"A sense of self develops in young children by degrees. The process can usefully be thought of in terms of the gradual emergence of two somewhat separate features: the self as a subject, and the self as an object. William James introduced the distinction in 1892, and contemporaries of his, such as Charles Cooley, added to the developing debate. Ever since then psychologists have continued building on the theory."},{label:"B",content:"According to James, a child's first step on the road to self-understanding can be seen as the recognition that he or she exists. This is an aspect of the self that he labelled 'self-as-subject', and he gave it various elements. These included an awareness of one's own agency and an awareness of one's distinctiveness from other people. Cooley suggested that a sense of the self-as-subject was primarily concerned with being able to exercise power. He proposed that the earliest examples of this are an infant's attempts to control physical objects, followed by attempts to affect the behaviour of other people."},{label:"C",content:"Another powerful source of information for infants about the effects they can have on the world around them is provided when others mimic them. Many parents spend a lot of time copying their infant's vocalizations and expressions. In addition, young children enjoy looking in mirrors, where the movements they can see are dependent on their own movements. Lewis and Brooks-Gunn suggest that this growing understanding leads to an awareness that infants are distinct from other people."},{label:"D",content:"This understanding that children gain of themselves as active agents continues to develop in their attempts to co-operate with others in play. Dunn points out that it is in day-to-day relationships and interactions that a child's understanding of self emerges. Empirical investigations of the self-as-subject in young children are, however, rather scarce because of difficulties of communication."},{label:"E",content:"Once children have acquired a certain level of self-awareness, they begin to place themselves in a whole series of categories. This second step in the development of a full sense of self is what James called the self-as-object. It has been seen by many to be the aspect of the self most influenced by social elements, made up of social roles and characteristics which derive meaning from comparison or interaction with other people."},{label:"F",content:"Cooley and other researchers suggested a close connection between a person's own understanding of identity and other people's understanding of it. Cooley believed that people build up identity from the reactions of others. Mead went even further and saw the self and the social world as inextricably bound together, arguing that it is impossible to conceive of a self arising outside social experience."},{label:"G",content:"Lewis and Brooks-Gunn argued that an important development milestone is reached when children become able to recognize themselves visually without the support of contingent movement. This recognition occurs around their second birthday. In one experiment they put red powder on the noses of children playing in front of a mirror and then observed how often they touched their noses. They also found that children of 15 to 18 months are generally not able to recognize themselves unless cues such as movement are present."},{label:"H",content:"Displays of rage are common from 18 months to 3 years of age. In a longitudinal study, Bronson found that the intensity of frustration and anger in children's disagreements increased sharply between the ages of 1 and 2 years. These disagreements often involved disputes over ownership rather than a wish to play with the toy itself. Although this may be less marked in other societies, the link between the sense of self and ownership is notable in Western childhood."}],questions:Ht},Jt={id:"day3-museums-p3",title:"Day 3 Passage 3: The Development of Museums",paragraphs:[{label:"A",content:"The conviction that historical relics provide infallible testimony about the past is rooted in the nineteenth and early twentieth centuries, when science was regarded as objective and value free. Although it is now evident that artefacts can be altered as easily as chronicles, public faith in their veracity endures. Museums used to look much like storage rooms of objects packed together in showcases, good for scholars but not for ordinary visitors. The information accompanying the objects often made little sense to the lay visitor."},{label:"B",content:"Recently, attitudes towards history and how it should be presented have altered. The key word in heritage display is now 'experience'. Good examples in the UK are the Jorvik Center in York, the National Museum of Photography, Film and Television in Bradford, and the Imperial War Museum in London. Re-enactment of historical events is increasingly popular, and computers will soon provide virtual reality experiences. Such developments have been criticized as vulgarization, but their success suggests most of the public does not share that opinion."},{label:"C",content:"In a related development, the distinction between museum and heritage sites on one hand, and theme parks on the other, is gradually evaporating. They borrow ideas and concepts from one another. Museums have adopted story lines, sites have accepted theming, and theme parks are moving towards more authenticity and research-based presentations."},{label:"D",content:"Theme parks are undergoing changes too, trying to present more serious social and cultural issues. This is a response to market forces and the competitive environment where visitors choose how and where to spend free time. Heritage and museum experts do not need to invent stories, since their assets already exist, but professionals who interpret history are in a difficult position. They must steer a narrow course between evidence and attractiveness, especially with the growing need for income-generating activities."},{label:"E",content:"It could be claimed that to make everything in heritage more real, historical accuracy must be altered. For example, Pithecanthropus erectus is depicted in Indonesian museum pictures because this corresponds to public perceptions. In Washington, Neanderthal man is shown making a dominant gesture to his wife. These presentations may tell us more about contemporary perceptions than about our ancestors. There is compensation, however, because visitors would otherwise provide their own interpretations based on misconceptions and prejudices."},{label:"F",content:"Human bias is inevitable, but another source of bias has to do with the transitory nature of materials. Not everything from history survives equally. Castles, palaces and cathedrals have longer lifespans than dwellings of ordinary people. As a result, many exhibitions are filled with nostalgia and can imply that life in the past was much better than it really was."}],questions:jt},Yt={id:"day4-auditory-problems-p1",title:"Day 4 Passage 1: Classroom Noise and Auditory Function Deficits in Children",paragraphs:[{label:"A",content:"Hearing impairment or other auditory function deficit in young children can have a major impact on their development of speech and communication, resulting in a detrimental effect on their ability to learn at school. This is likely to have major consequences for the individual and the population as a whole. The New Zealand Ministry of Health has found from research carried out over two decades that 6-10% of children in that country are affected by hearing loss."},{label:"B",content:"A preliminary study in New Zealand has shown that classroom noise presents a major concern for teachers and pupils. Modern teaching practices, the organisation of desks in the classroom, poor classroom acoustics, and mechanical means of ventilation such as air-conditioning units all contribute to the number of children unable to comprehend the teacher's voice. Education researchers Nelson and Soli have also suggested that recent trends in learning often involve collaborative interaction of multiple minds and tools as much as individual possession of information. This all amounts to heightened activity and noise levels, which have the potential to be particularly serious for children experiencing auditory function deficit. Noise in classrooms can only exacerbate their difficulty in comprehending and processing verbal communication with other children and instructions from the teacher."},{label:"C",content:"Children with auditory function deficit are potentially failing to learn to their maximum potential because of noise levels generated in classrooms. The effects of noise on the ability of children to learn effectively in typical classroom environments are now the subject of increasing concern. The International Institute of Noise Control Engineering (I-INCE), on the advice of the World Health Organization, has established an international working party, which includes New Zealand, to evaluate noise and reverberation control for school rooms."},{label:"D",content:"While the detrimental effects of noise in classroom situations are not limited to children experiencing disability, those with a disability that affects their processing of speech and verbal communication could be extremely vulnerable. The auditory function deficits in question include hearing impairment, autistic spectrum disorders (ASD) and attention deficit disorders (ADD/ADHD)."},{label:"E",content:"Autism is considered a neurological and genetic life-long disorder that causes discrepancies in the way information is processed. This disorder is characterised by interlinking problems with social imagination, social communication and social interaction. According to Janzen, this affects the ability to understand and relate in typical ways to people, understand events and objects in the environment, and understand or respond to sensory stimuli. Autism does not allow learning or thinking in the same ways as in children who are developing normally. Autistic spectrum disorders often result in major difficulties in comprehending verbal information and speech processing. Those experiencing these disorders often find sounds such as crowd noise and the noise generated by machinery painful and distressing. This is difficult to scientifically quantify as such extra-sensory stimuli vary greatly from one autistic individual to another. But a child who finds any type of noise in their classroom or learning space intrusive is likely to be adversely affected in their ability to process information."},{label:"F",content:"The attention deficit disorders are indicative of neurological and genetic disorders and are characterised by difficulties with sustaining attention, effort and persistence, organisation skills and disinhibition. Children experiencing these disorders find it difficult to screen out unimportant information, and focus on everything in the environment rather than attending to a single activity. Background noise in the classroom becomes a major distraction, which can affect their ability to concentrate."},{label:"G",content:"Children experiencing an auditory function deficit can often find speech and communication very difficult to isolate and process when set against high levels of background noise. These levels come from outside activities that penetrate the classroom structure, from teaching activities, and other noise generated inside, which can be exacerbated by room reverberation. Strategies are needed to obtain the optimum classroom construction and perhaps a change in classroom culture and methods of teaching. In particular, the effects of noisy classrooms and activities on those experiencing disabilities in the form of auditory function deficit need thorough investigation. It is probable that many undiagnosed children exist in the education system with 'invisible' disabilities. Their needs are less likely to be met than those of children with known disabilities."},{label:"H",content:"The New Zealand Government has developed a New Zealand Disability Strategy and has embarked on a wide-ranging consultation process. The strategy recognises that people experiencing disability face significant barriers in achieving a full quality of life in areas such as attitude, education, employment and access to services. Objective 3 of the New Zealand Disability Strategy is to 'Provide the Best Education for Disabled People' by improving education so that all children, youth learners and adult learners will have equal opportunities to learn and develop within their already existing local school. For a successful education, the learning environment is vitally significant, so any effort to improve this is likely to be of great benefit to all children, but especially to those with auditory function disabilities."},{label:"I",content:"A number of countries are already in the process of formulating their own standards for the control and reduction of classroom noise. New Zealand will probably follow their example. The literature to date on noise in school rooms appears to focus on the effects on schoolchildren in general, their teachers and the hearing impaired. Only limited attention appears to have been given to those students experiencing the other disabilities involving auditory function deficit. It is imperative that the needs of these children are taken into account in the setting of appropriate international standards to be promulgated in future."}],questions:Lt},Kt={id:"day5-venus-transit-p2",title:"Day 5 Passage 2: Venus in Transit",paragraphs:[{label:"A",content:"On 8 June 2004, more than half the population of the world were treated to a rare astronomical event. For over six hours, the planet Venus steadily inched its way over the surface of the Sun. This 'transit' of Venus was the first since 6 December 1882. On that occasion, the American astronomer Professor Simon Newcomb led a party to South Africa to observe the event. They were based at a girls' school, where - it is alleged - the combined forces of three schoolmistresses outperformed the professionals with the accuracy of their observations."},{label:"B",content:"For centuries, transits of Venus have drawn explorers and astronomers alike to the four corners of the globe. And you can put it all down to the extraordinary polymath Edmond Halley. In November 1677, Halley observed a transit of the innermost planet, Mercury, from the desolate island of St Helena in the south Pacific. He realized that, from different latitudes, the passage of the planet across the Sun's disc would appear to differ. By timing the transit from two widely-separated locations, teams of astronomers could calculate the parallax angle - the apparent difference in position of an astronomical body due to a difference in the observer's position. Calculating this angle would allow astronomers to measure what was then the ultimate goal: the distance of the Earth from the Sun. This distance is known as the astronomical unit (AU)."},{label:"C",content:"Halley was aware that the AU was one of the most fundamental of all astronomical measurements. Johannes Kepler, in the early 17th century, had shown that the distances of the planets from the Sun governed their orbital speeds, which were easily measurable. But no-one had found a way to calculate accurate distances to the planets from the Earth. The goal was to measure the AU; then, knowing the orbital speeds of all the other planets round the Sun, the scale of the Solar System would fall into place. However, Halley realised that Mercury was so far away that its parallax angle would be very difficult to determine. As Venus was closer to the Earth, its parallax angle would be larger, and Halley worked out that by using Venus it would be possible to measure the Sun's distance to 1 part in 500. But there was a problem: transits of Venus, unlike those of Mercury, are rare, occurring in pairs roughly eight years apart every hundred or so years. Nevertheless, he accurately predicted that Venus would cross the face of the Sun in both 1761 and 1769 - though he didn't survive to see either."},{label:"D",content:"Inspired by Halley's suggestion of a way to pin down the scale of the Solar System, teams of British and French astronomers set out on expeditions to places as diverse as India and Siberia. But things weren't helped by Britain and France being at war. The person who deserves most sympathy is the French astronomer Guillaume Le Gentil. He was thwarted by the fact that the British were besieging his observation site at Pondicherry in India. Fleeing on a French warship crossing the Indian Ocean, Le Gentil saw a wonderful transit - but the ship's pitching and rolling ruled out any attempt at making accurate observations. Undaunted, he remained south of the equator, keeping himself busy by studying the islands of Mauritius and Madagascar before setting off to observe the next transit in the Philippines. Ironically, after travelling nearly 50,000 kilometres, his view was clouded out at the last moment, a very dispiriting experience."},{label:"E",content:"While the early transit timings were as precise as instruments would allow, the measurements were dogged by the 'black drop' effect. When Venus begins to cross the Sun's disc, it looks smeared, not circular - which makes it difficult to establish timings. This is due to diffraction of light. The second problem is that Venus exhibits a halo of light when it is seen just outside the Sun's disc. While this showed astronomers that Venus was surrounded by a thick layer of gases refracting sunlight around it, both effects made it impossible to obtain accurate timings."},{label:"F",content:"But astronomers laboured hard to analyse the results of these expeditions to observe Venus transits. Johann Franz Encke, Director of the Berlin Observatory, finally determined a value for the AU based on all these parallax measurements: 153,340,000km. Reasonably accurate for the time, that is quite close to today's value of 149,597,870km. The AU is a cosmic measuring rod, and the basis of how we scale the Universe today. The parallax principle can be extended to measure the distances to the stars. If we look at a star in January - when Earth is at one point in its orbit - it will seem to be in a different position from where it appears six months later. Knowing the width of Earth's orbit, the parallax shift lets astronomers calculate the distance."},{label:"G",content:"June 2004's transit of Venus was thus more of an astronomical spectacle than a scientifically important event. But such transits have paved the way for what might prove to be one of the most vital breakthroughs in the cosmos - detecting Earth-sized planets orbiting other stars."}],questions:Qt},$t={id:"day6-neuroscientist-p3",title:"Day 6 Passage 3: A Neuroscientist Reveals How to Think Differently",paragraphs:[{label:"A",content:"In the last decade a revolution has occurred in the way that scientists think about the brain. We now know that the decisions humans make can be traced to the firing patterns of neurons in specific parts of the brain. These discoveries have led to the field known as neuroeconomics, which studies the brain's secrets to success in an economic environment that demands innovation and being able to do things differently from competitors. A brain that can do this is an iconoclastic one. Briefly, an iconoclast is a person who does something that others say can't be done."},{label:"B",content:"This definition implies that iconoclasts are different from other people, but more precisely, it is their brains that are different in three distinct ways: perception, fear response, and social intelligence. Each of these three functions utilizes a different circuit in the brain. Naysayers might suggest that the brain is irrelevant, that thinking in an original, even revolutionary, way is more a matter of personality than brain function. But the field of neuroeconomics was born out of the realization that the physical workings of the brain place limitations on the way we make decisions. By understanding these constraints, we begin to understand why some people march to a different drumbeat."},{label:"C",content:"The first thing to realize is that the brain suffers from limited resources. It has a fixed energy budget, about the same as a 40 watt light bulb, so it has evolved to work as efficiently as possible. This is where most people are impeded from being an iconoclast. For example, when confronted with information streaming from the eyes, the brain will interpret this information in the quickest way possible. Thus it will draw on both past experience and any other source of information, such as what other people say, to make sense of what it is seeing. This happens all the time. The brain takes shortcuts that work so well we are hardly ever aware of them. We think our perceptions of the world are real, but they are only biological and electrical rumblings. Perception is not simply a product of what your eyes or ears transmit to your brain. More than the physical reality of photons or sound waves, perception is a product of the brain."},{label:"D",content:"Perception is central to iconoclasm. Iconoclasts see things differently to other people. Their brains do not fall into efficiency pitfalls as much as the average person's brain. Iconoclasts, either because they were born that way or through learning, have found ways to work around the perceptual shortcuts that plague most people. Perception is not something that is hardwired into the brain. It is a learned process, which is both a curse and an opportunity for change. The brain faces the fundamental problem of interpreting physical stimuli from the senses. Everything the brain sees, hears, or touches has multiple interpretations. The one that is ultimately chosen is simply the brain's best theory. In technical terms, these conjectures have their basis in the statistical likelihood of one interpretation over another and are heavily influenced by past experience and, importantly for potential iconoclasts, what other people say."},{label:"E",content:"The best way to see things differently to other people is to bombard the brain with things it has never encountered before. Novelty releases the perceptual process from the chains of past experience and forces the brain to make new judgments. Successful iconoclasts have an extraordinary willingness to be exposed to what is fresh and different. Observation of iconoclasts shows that they embrace novelty while most people avoid things that are different."},{label:"F",content:"The problem with novelty, however, is that it tends to trigger the brain's fear system. Fear is a major impediment to thinking like an iconoclast and stops the average person in his tracks. There are many types of fear, but the two that inhibit iconoclastic thinking and people generally find difficult to deal with are fear of uncertainty and fear of public ridicule. These may seem like trivial phobias. But fear of public speaking, which everyone must do from time to time, afflicts one-third of the population. This makes it too common to be considered a mental disorder. It is simply a common variant of human nature, one which iconoclasts do not let inhibit their reactions."},{label:"G",content:"Finally, to be successful iconoclasts, individuals must sell their ideas to other people."},{label:"H",content:"This is where social intelligence comes in. Social intelligence is the ability to understand and manage people in a business setting. In the last decade there has been an explosion of knowledge about the social brain and how the brain works when groups coordinate decision making. Neuroscience has revealed which brain circuits are responsible for functions like understanding what other people think, empathy, fairness, and social identity. These brain regions play key roles in whether people convince others of their ideas. Perception is important in social cognition too. The perception of someone's enthusiasm, or reputation, can make or break a deal. Understanding how perception becomes intertwined with social decision making shows why successful iconoclasts are so rare."},{label:"I",content:"Iconoclasts create new opportunities in every area from artistic expression to technology to business. They supply creativity and innovation not easily accomplished by committees. Rules aren't important to them. Iconoclasts face alienation and failure, but can also be a major asset to any organization. It is crucial for success in any field to understand how the iconoclastic mind works."}],questions:zt},Zt={1:Ut,2:Vt,3:Jt,4:Yt,5:Kt,6:$t,...Wt},Xt=new Set([10,20,30]);function I(e){return{...e,paragraphs:e.paragraphs?e.paragraphs.map(t=>({...t})):void 0,questions:e.questions.map(t=>({...t,options:t.options?[...t.options]:void 0,correctAnswer:Array.isArray(t.correctAnswer)?[...t.correctAnswer]:t.correctAnswer}))}}function ea(e){const t=Math.max(1,e),o=Xt.has(t),i=Zt[t],n=I(i||w.sections[(t-1)%w.sections.length]),Q=n.questions.length;return{...w,id:`reading-day-${t}`,title:o?`IELTS Reading Day ${t} (Mock)`:`IELTS Reading Day ${t}`,duration:20,sections:[n],totalQuestions:Q}}function ta(e){const t=[w,we,ke,Be,Fe,Y,Me,Qe,Je,Ze],o=t[(Math.max(1,e)-1)%t.length];return{...o,id:`reading-full-${e}`,title:`IELTS Reading Full Test ${e}`,sections:o.sections.map(i=>I(i))}}function aa(e){const t=H[(Math.max(1,e)-1)%H.length],o=(Math.max(1,e)-1)%Math.min(3,t.sections.length),i=I(t.sections[o]);return{...t,id:`listening-day-${e}`,title:`IELTS Listening Day ${e}`,duration:20,sections:[i],totalQuestions:i.questions.length}}function oa(e){const t=H[(Math.max(1,e)-1)%H.length];return{...t,id:`listening-full-${e}`,title:`IELTS Listening Full Test ${e}`,sections:t.sections.map(o=>I(o))}}function Z(e,t){const o=t.match(/^(reading|listening)-day-(\d{1,2})$/);if(o){const n=Number(o[2]);if(n>=1&&n<=30)return e==="reading"?ea(n):aa(n)}const i=t.match(/^(reading|listening)-full-(\d{1,2})$/);if(i){const n=Number(i[2]);if(n>=1&&n<=20)return e==="reading"?ta(n):oa(n)}return null}function ra(e){return e?e.startsWith("reading-")?Z("reading",e):e.startsWith("listening-")?Z("listening",e):null:null}export{H as a,we as b,ke as c,Be as d,Fe as e,w as f,Y as g,Me as h,Qe as i,Je as j,Ze as k,ia as l,na as m,ra as n,Z as r};
